# ── Workflow Registry ─────────────────────────────────────────────────────
_wf_lock = threading.Lock()
_wf_registry: dict = {}  # workflow_id -> workflow dict

def _wf_register(wf_id, name, description, wf_type="system", interval="", interval_s=0, config_keys=None, exposed=True):
    """Register a system workflow in the registry."""
    with _wf_lock:
        _wf_registry[wf_id] = {
            "id": wf_id, "name": name, "description": description,
            "type": wf_type, "status": "active", "interval": interval,
            "interval_s": interval_s, "config_keys": config_keys or [],
            "last_run": None, "next_run": None, "run_count": 0,
            "error_count": 0, "last_error": None, "last_result": None,
            "last_duration_s": 0, "history": [], "started_at": None,
            "exposed": bool(exposed),
        }

def _wf_start_run(wf_id):
    """Mark a workflow as currently running."""
    import time as _t
    with _wf_lock:
        wf = _wf_registry.get(wf_id)
        if wf:
            wf["started_at"] = _t.time()

def _wf_record_run(wf_id, success=True, result=None, error=None, duration_s=0):
    """Record a workflow run in the registry."""
    import time as _t
    with _wf_lock:
        wf = _wf_registry.get(wf_id)
        if not wf:
            return
        wf["started_at"] = None  # clear running state
        now = _t.time()
        wf["last_run"] = now
        wf["run_count"] += 1
        wf["last_duration_s"] = round(duration_s, 3)
        wf["last_result"] = result
        if not success:
            wf["error_count"] += 1
            wf["last_error"] = str(error) if error else "Unknown error"
            wf["status"] = "error"
        else:
            wf["last_error"] = None  # v0.28.49 — clear stale error on success
            if wf["status"] == "error":
                wf["status"] = "active"
        if wf["interval_s"] > 0:
            wf["next_run"] = now + wf["interval_s"]
        entry = {"ts": now, "ok": success, "duration_s": round(duration_s, 3)}
        if error:
            entry["error"] = str(error)[:200]
        if result:
            entry["result"] = str(result)[:200]
        wf["history"].append(entry)
        if len(wf["history"]) > 20:
            wf["history"] = wf["history"][-20:]
        # Persist to DB
        import json as _j
        try:
            conn = _db_conn()
            conn.execute(
                "INSERT OR REPLACE INTO workflow_stats (wf_id, run_count, error_count, last_run, last_error, last_result, last_duration_s, history) VALUES (?,?,?,?,?,?,?,?)",
                (wf_id, wf["run_count"], wf["error_count"], wf["last_run"],
                 wf.get("last_error"), str(wf.get("last_result",""))[:500],
                 wf["last_duration_s"], _j.dumps(wf["history"]))
            )
            conn.commit(); conn.close()
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
def _wf_is_enabled(wf_id):
    """Check if a workflow is active (not paused)."""
    with _wf_lock:
        wf = _wf_registry.get(wf_id)
        return wf["status"] != "paused" if wf else True

def _wf_load_stats():
    """Load persisted workflow stats from DB into registry."""
    import json as _j
    try:
        conn = _db_conn()
        for row in conn.execute("SELECT wf_id, run_count, error_count, last_run, last_error, last_result, last_duration_s, history FROM workflow_stats").fetchall():
            wf = _wf_registry.get(row[0])
            if wf:
                wf["run_count"] = row[1] or 0
                wf["error_count"] = row[2] or 0
                wf["last_run"] = row[3]
                wf["last_error"] = row[4]
                wf["last_result"] = row[5]
                wf["last_duration_s"] = row[6] or 0
                try: wf["history"] = _j.loads(row[7]) if row[7] else []
                except: wf["history"] = []
        conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
def _run_if_due(wf_id, fn):
    """Run a workflow callback when its interval is due."""
    with _wf_lock:
        wf = dict(_wf_registry.get(wf_id) or {})
    interval_s = int(wf.get("interval_s") or 0)
    if interval_s <= 0:
        return False
    last = float(wf.get("last_run") or 0)
    if last and (time.time() - last) < interval_s:
        return False
    fn()
    return True

