def _check_brave_search() -> dict:
    """Check if Brave Search API key is configured (env or config)."""
    key = os.environ.get("BRAVE_API_KEY", "")
    if not key:
        try:
            cfg = json.loads(CONFIG_PATH.read_text()) if CONFIG_PATH.exists() else {}
            key = cfg.get("api_keys", {}).get("brave_search", "")
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    if key:
        return {"ok": True, "version": "API key configured"}
    return {"ok": False, "version": None}


def _check_gws_cli() -> dict:
    """Check gws CLI: binary + auth status."""
    r = _cap_check_bin("gws")
    if r["ok"]:
        token_path = Path.home() / ".config" / "gws" / "token.json"
        if token_path.exists():
            r["version"] = (r["version"] or "") + " (authenticated)"
        else:
            r["version"] = (r["version"] or "") + " (not authenticated)"
    return r

