# ── Google Workspace CLI helpers ──────────────────────────────────────────────

_GWS_ALLOWED_SERVICES = frozenset([
    "admin", "calendar", "chat", "classroom", "docs", "drive", "forms",
    "gmail", "groups", "keep", "meet", "people", "sheets", "sites",
    "slides", "tasks", "vault",
])

_gws_services_cache: dict = {"data": None, "ts": 0}


def _gws_resolve_bin() -> str | None:
    """Find the gws binary."""
    import shutil as _sh
    p = _sh.which("gws")
    if p:
        return p
    for d in (str(Path.home() / ".npm-global" / "bin"), str(Path.home() / ".local" / "bin"), "/usr/local/bin"):
        c = Path(d) / "gws"
        if c.exists():
            return str(c)
    return None


def _gws_status() -> dict:
    """Get gws installation status, auth state, and accounts."""
    gws_bin = _gws_resolve_bin()
    result = {"ok": True, "installed": gws_bin is not None, "version": "", "authenticated": False, "accounts": [], "granted_services": []}
    if not gws_bin:
        result["ok"] = False
        return result
    # Version
    try:
        r = subprocess.run([gws_bin, "--version"], capture_output=True, text=True, timeout=5)
        result["version"] = (r.stdout or r.stderr or "").strip().split("\n")[0][:80]
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Auth: check token file
    config_dir = Path.home() / ".config" / "gws"
    token_path = config_dir / "token.json"
    result["authenticated"] = token_path.exists()
    # Accounts
    accounts_path = config_dir / "accounts.json"
    if accounts_path.exists():
        try:
            accts = json.loads(accounts_path.read_text(encoding="utf-8"))
            if isinstance(accts, list):
                result["accounts"] = accts
            elif isinstance(accts, dict):
                result["accounts"] = [accts]
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Granted services
    grants_path = config_dir / "granted_services.json"
    if grants_path.exists():
        try:
            grants = json.loads(grants_path.read_text(encoding="utf-8"))
            if isinstance(grants, list):
                result["granted_services"] = grants
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return result


def _gws_exec(service: str, resource: str, method: str, params: dict | None = None, json_body: dict | None = None, timeout: int = 30) -> dict:
    """Execute a gws CLI command and return parsed JSON."""
    gws_bin = _gws_resolve_bin()
    if not gws_bin:
        return {"ok": False, "error": "gws CLI not installed. Run: npm install -g @googleworkspace/cli"}
    if service not in _GWS_ALLOWED_SERVICES:
        return {"ok": False, "error": f"Service '{service}' not allowed. Allowed: {', '.join(sorted(_GWS_ALLOWED_SERVICES))}"}
    # Sanitize resource and method — alphanumeric, dots, hyphens only
    import re as _re
    if not _re.match(r'^[a-zA-Z0-9._-]+$', resource):
        return {"ok": False, "error": "Invalid resource name"}
    if not _re.match(r'^[a-zA-Z0-9_-]+$', method):
        return {"ok": False, "error": "Invalid method name"}
    timeout = min(max(timeout, 5), 120)
    cmd = [gws_bin, service, resource, method]
    if params:
        cmd.extend(["--params", json.dumps(params)])
    if json_body:
        cmd.extend(["--body", json.dumps(json_body)])
    cmd.append("--json")
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout + 5,
                           env={**os.environ, "NO_COLOR": "1"}, cwd=str(Path.home()))
        if r.returncode != 0:
            err = (r.stderr or r.stdout or "").strip()[:500]
            return {"ok": False, "error": f"gws exited {r.returncode}: {err}"}
        # Parse JSON output
        out = (r.stdout or "").strip()
        if out:
            try:
                parsed = json.loads(out)
                return {"ok": True, "result": parsed}
            except json.JSONDecodeError:
                return {"ok": True, "result": out[:5000]}
        return {"ok": True, "result": None}
    except subprocess.TimeoutExpired:
        return {"ok": False, "error": f"gws command timed out after {timeout}s"}
    except Exception as e:
        return {"ok": False, "error": str(e)[:500]}


def _gws_exec_helper(helper: str, args: dict, timeout: int = 30) -> dict:
    """Execute a gws helper/shortcut command."""
    gws_bin = _gws_resolve_bin()
    if not gws_bin:
        return {"ok": False, "error": "gws CLI not installed. Run: npm install -g @googleworkspace/cli"}
    timeout = min(max(timeout, 5), 120)
    # Map helpers to gws commands
    _helpers = {
        "gmail-send": lambda a: [gws_bin, "gmail", "+send", "--to", a.get("to", ""), "--subject", a.get("subject", ""), "--body", a.get("body", "")],
        "calendar-agenda": lambda a: [gws_bin, "calendar", "+agenda"],
        "drive-list": lambda a: [gws_bin, "drive", "files", "list", "--params", json.dumps({"pageSize": a.get("pageSize", 10)})],
        "gmail-unread": lambda a: [gws_bin, "gmail", "users.messages", "list", "--params", json.dumps({"userId": "me", "q": "is:unread", "maxResults": a.get("maxResults", 10)})],
        "sheets-read": lambda a: [gws_bin, "sheets", "+read", "--spreadsheet-id", a.get("spreadsheetId", ""), "--range", a.get("range", "A1:Z100")],
    }
    builder = _helpers.get(helper)
    if not builder:
        return {"ok": False, "error": f"Unknown helper: {helper}. Available: {', '.join(sorted(_helpers.keys()))}"}
    cmd = builder(args)
    cmd.append("--json")
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout + 5,
                           env={**os.environ, "NO_COLOR": "1"}, cwd=str(Path.home()))
        if r.returncode != 0:
            err = (r.stderr or r.stdout or "").strip()[:500]
            return {"ok": False, "error": f"gws exited {r.returncode}: {err}"}
        out = (r.stdout or "").strip()
        if out:
            try:
                return {"ok": True, "result": json.loads(out)}
            except json.JSONDecodeError:
                return {"ok": True, "result": out[:5000]}
        return {"ok": True, "result": None}
    except subprocess.TimeoutExpired:
        return {"ok": False, "error": f"gws command timed out after {timeout}s"}
    except Exception as e:
        return {"ok": False, "error": str(e)[:500]}


def _gws_list_services() -> dict:
    """List available gws services (cached 5 minutes)."""
    now = time.time()
    if _gws_services_cache["data"] and (now - _gws_services_cache["ts"]) < 300:
        return _gws_services_cache["data"]
    result = {"ok": True, "services": sorted(_GWS_ALLOWED_SERVICES)}
    _gws_services_cache["data"] = result
    _gws_services_cache["ts"] = now
    return result



# v0.28.4 — Loop guard: prevent runaway agent-to-agent dispatch loops
_loop_guard = {}  # chat_id -> {"hop_count": int, "paused": bool, "last_human_at": float}
_loop_guard_lock = threading.Lock()
_LOOP_GUARD_MAX_HOPS = 4  # Auto-pause after this many agent-to-agent hops

def _loop_guard_check(chat_id, sender_is_human=False):
    """Check/update loop guard. Returns (allowed, message)."""
    import time as _t
    with _loop_guard_lock:
        if chat_id not in _loop_guard:
            _loop_guard[chat_id] = {"hop_count": 0, "paused": False, "last_human_at": _t.time()}
        state = _loop_guard[chat_id]
        if sender_is_human:
            state["hop_count"] = 0
            state["paused"] = False
            state["last_human_at"] = _t.time()
            return True, ""
        if state["paused"]:
            return False, f"Loop guard: chain paused after {_LOOP_GUARD_MAX_HOPS} agent hops. Send a message to resume."
        state["hop_count"] += 1
        if state["hop_count"] > _LOOP_GUARD_MAX_HOPS:
            state["paused"] = True
            mlog.emit("warn", "chat", "loop_guard.pause", f"Loop guard paused chat {chat_id} after {state['hop_count']} hops")
            return False, f"Loop guard: {state['hop_count']} consecutive agent hops — paused to prevent runaway. Send a message to resume."
        return True, ""


# v0.28.4 — Cursor-based reads: per-agent read position tracking
_agent_cursors = {}  # agent_id -> {chat_id -> last_message_id}
_agent_cursor_lock = threading.Lock()
_agent_empty_reads = {}  # agent_id -> consecutive empty read count

def _cursor_get_new_messages(agent_id, chat_id, limit=20):
    """Get only NEW messages since this agent's last read. Returns (messages, warning_text)."""
    with _agent_cursor_lock:
        cursor = _agent_cursors.get(agent_id, {}).get(chat_id, 0)
    try:
        conn = _db_conn()
        if cursor:
            rows = conn.execute(
                "SELECT id, role, content, timestamp FROM chat_messages "
                "WHERE chat_id=? AND id > ? ORDER BY id ASC LIMIT ?",
                (chat_id, cursor, limit)
            ).fetchall()
        else:
            # First read: return last N messages for initial context
            rows = conn.execute(
                "SELECT id, role, content, timestamp FROM chat_messages "
                "WHERE chat_id=? ORDER BY id DESC LIMIT ?",
                (chat_id, limit)
            ).fetchall()
            rows = list(reversed(rows))
        conn.close()
    except Exception:
        rows = []

    messages = [{"id": r[0], "role": r[1], "content": r[2], "timestamp": r[3]} for r in rows]

    # Update cursor
    if messages:
        with _agent_cursor_lock:
            if agent_id not in _agent_cursors:
                _agent_cursors[agent_id] = {}
            _agent_cursors[agent_id][chat_id] = messages[-1]["id"]
            _agent_empty_reads[agent_id] = 0
        return messages, ""

    # Empty read — escalating warnings
    with _agent_cursor_lock:
        _agent_empty_reads[agent_id] = _agent_empty_reads.get(agent_id, 0) + 1
        n = _agent_empty_reads[agent_id]
    if n == 1:
        warning = "No new messages. Do not poll — wait for a mention or event."
    elif n == 2:
        warning = "You have read with no results twice. Stop polling and wait."
    else:
        warning = "STOP. Repeated empty reads waste tokens. Only read when triggered."
    return [], warning

def _mem_consolidation_loop():
    """Memory V2: background consolidation loop (every 4 hours).
    - Decay unused memories (confidence -= 0.03)
    - Auto-archive memories with confidence < 0.15
    - Auto-promote signals with evidence_count >= 3 and confidence > 0.7
    """
    import time as _t
    with _wf_lock:
        _wf_registry.setdefault("mem_consolidation", {"enabled": True, "started_at": 0, "runs": []})
        _wf_registry["mem_consolidation"]["started_at"] = _t.time()
    while True:
        prefs = _config.get("preferences", {})
        hours = max(1, prefs.get("mem_consolidate_hours", 4))
        _t.sleep(hours * 3600)
        _t0 = _t.time()
        try:
            result = _mem_consolidate_once()
            _wf_record_run("mem_consolidation", success=True, result=result, duration_s=_t.time()-_t0)
        except Exception as e:
            _wf_record_run("mem_consolidation", success=False, error=e, duration_s=_t.time()-_t0)


def _mem_consolidate_once():
    """Run one Memory V2 consolidation pass."""
    import time as _t
    conn = _db_conn()
    decayed = 0
    archived = 0
    promoted = 0
    try:
        now = _t.time()
        seven_days_ago = now - 7 * 86400
        # Decay: confidence -= 0.03 for unused memories older than 7 days
        conn.execute(
            "UPDATE memories SET confidence = MAX(0, confidence - 0.03), updated_at=strftime('%s','now') "
            "WHERE use_count = 0 AND created_at < ? AND status = 'active' AND confidence > 0.15",
            (seven_days_ago,))
        decayed = conn.total_changes
        conn.commit()
        # Auto-archive: confidence < 0.15
        conn.execute(
            "UPDATE memories SET status = 'archived', updated_at=strftime('%s','now') "
            "WHERE confidence < 0.15 AND status = 'active'")
        archived = conn.total_changes
        conn.commit()
        # Auto-promote: signals with evidence_count >= 3 and confidence > 0.7
        conn.execute(
            "UPDATE memories SET memory_kind = 'concept', trust_tier = 'medium', review_state = 'accepted', updated_at=strftime('%s','now') "
            "WHERE memory_kind = 'signal' AND evidence_count >= 3 AND confidence > 0.7 AND status = 'active'")
        promoted = conn.total_changes
        conn.commit()
    except Exception as e:
        log.warning("Memory V2 consolidation error: %s", e)
    finally:
        conn.close()
    result = f"decayed={decayed}, archived={archived}, promoted={promoted}"
    if decayed or archived or promoted:
        log.info("Memory V2 consolidation: %s", result)
    return result






# ── Context Hygiene Engine ─────────────────────────────────────────────────

def _hygiene_prune_logs():
    """Rule 1: Delete daily dispatch logs older than retention days."""
    prefs = _config.get("preferences", {})
    retention = max(1, prefs.get("hygiene_log_retention_days", 7))
    from datetime import datetime, timedelta, timezone as _tz
    cutoff = datetime.now(_tz.utc) - timedelta(days=retention)
    pruned = 0
    try:
        if not PERSONAS_DIR.exists():
            return pruned
        for pdir in PERSONAS_DIR.iterdir():
            mem_dir = pdir / "memory"
            if not mem_dir.is_dir():
                continue
            for f in mem_dir.iterdir():
                if not f.name.endswith(".md"):
                    continue
                # Match YYYY-MM-DD.md pattern
                try:
                    fdate = datetime.strptime(f.stem, "%Y-%m-%d").replace(tzinfo=_tz.utc)
                    if fdate < cutoff:
                        f.unlink()
                        pruned += 1
                except ValueError:
                    continue
    except Exception as e:
        _hygiene_stats["errors"].append(f"prune_logs: {e}")
        log.warning("Hygiene prune_logs error: %s", e)
    return pruned


def _hygiene_cap_soul():
    """Rule 2: Cap Learned Traits in SOUL.md, archive overflow."""
    prefs = _config.get("preferences", {})
    max_traits = max(5, prefs.get("hygiene_soul_max_traits", 20))
    capped = 0
    try:
        if not PERSONAS_DIR.exists():
            return capped
        for pdir in PERSONAS_DIR.iterdir():
            soul_path = pdir / "SOUL.md"
            if not soul_path.is_file():
                continue
            content = soul_path.read_text()
            if "## Learned Traits" not in content:
                continue
            # Split at Learned Traits section
            parts = content.split("## Learned Traits", 1)
            header = parts[0]
            traits_section = parts[1] if len(parts) > 1 else ""
            # Extract trait lines (start with "- ")
            trait_lines = [l for l in traits_section.split("\n") if l.strip().startswith("- ")]
            if len(trait_lines) <= max_traits:
                continue
            # Archive overflow
            overflow = trait_lines[:-max_traits]
            keep = trait_lines[-max_traits:]
            archive_path = pdir / "SOUL_ARCHIVE.md"
            existing_archive = archive_path.read_text() if archive_path.exists() else ""
            from datetime import datetime, timezone as _tz
            ts = datetime.now(_tz.utc).strftime("%Y-%m-%d %H:%M")
            archive_entry = f"\n## Archived Traits ({ts})\n" + "\n".join(overflow) + "\n"
            archive_path.write_text(existing_archive + archive_entry)
            # Rebuild SOUL.md with non-trait lines preserved
            non_trait_lines = [l for l in traits_section.split("\n") if not l.strip().startswith("- ")]
            rebuilt = header + "## Learned Traits" + "\n".join(non_trait_lines) + "\n" + "\n".join(keep) + "\n"
            soul_path.write_text(rebuilt)
            capped += 1
            log.info("Hygiene: capped SOUL.md for %s (%d traits archived)", pdir.name, len(overflow))
    except Exception as e:
        _hygiene_stats["errors"].append(f"cap_soul: {e}")
        log.warning("Hygiene cap_soul error: %s", e)
    return capped


def _hygiene_archive_memory():
    """Rule 3: Archive MEMORY.md overflow beyond max lines."""
    prefs = _config.get("preferences", {})
    max_lines = max(20, prefs.get("hygiene_memory_max_lines", 100))
    archived = 0
    try:
        if not PERSONAS_DIR.exists():
            return archived
        for pdir in PERSONAS_DIR.iterdir():
            mem_path = pdir / "MEMORY.md"
            if not mem_path.is_file():
                continue
            content = mem_path.read_text()
            mem_lines = content.split("\n")
            if len(mem_lines) <= max_lines:
                continue
            # Keep last max_lines, archive the rest
            overflow = mem_lines[:-max_lines]
            keep = mem_lines[-max_lines:]
            archive_path = pdir / "MEMORY_ARCHIVE.md"
            existing = archive_path.read_text() if archive_path.exists() else ""
            from datetime import datetime, timezone as _tz
            ts = datetime.now(_tz.utc).strftime("%Y-%m-%d %H:%M")
            archive_entry = f"\n## Archived ({ts})\n" + "\n".join(overflow) + "\n"
            archive_path.write_text(existing + archive_entry)
            mem_path.write_text("\n".join(keep))
            archived += 1
            log.info("Hygiene: archived %d lines from MEMORY.md for %s", len(overflow), pdir.name)
    except Exception as e:
        _hygiene_stats["errors"].append(f"archive_memory: {e}")
        log.warning("Hygiene archive_memory error: %s", e)
    return archived


def _hygiene_merge_identity():
    """Rule 4: DISABLED — persona files must stay separate (IDENTITY.md, ROLE_CARD.md, SOUL.md)."""
    # v0.28.34 — Merging was architecturally wrong. Each file serves a distinct purpose:
    # SOUL.md = personality/directives, IDENTITY.md = metadata, ROLE_CARD.md = governance/scope.
    return 0


def _hygiene_run():
    """Execute all hygiene rules. Called by daemon or API trigger."""
    import time as _ptime
    prefs = _config.get("preferences", {})
    if not prefs.get("hygiene_enabled", True):
        return {"skipped": True, "reason": "disabled"}
    from datetime import datetime, timezone as _tz
    t0 = _ptime.time()
    results = {}
    results["logs_pruned"] = _hygiene_prune_logs()
    results["souls_capped"] = _hygiene_cap_soul()
    results["memories_archived"] = _hygiene_archive_memory()
    results["identities_merged"] = _hygiene_merge_identity()
    elapsed = round(_ptime.time() - t0, 2)
    results["elapsed_s"] = elapsed
    # Update stats
    _hygiene_stats["last_run"] = datetime.now(_tz.utc).isoformat()
    _hygiene_stats["total_runs"] += 1
    _hygiene_stats["logs_pruned"] += results["logs_pruned"]
    _hygiene_stats["souls_capped"] += results["souls_capped"]
    _hygiene_stats["memories_archived"] += results["memories_archived"]
    _hygiene_stats["identities_merged"] += results["identities_merged"]
    # Keep only last 20 errors
    _hygiene_stats["errors"] = _hygiene_stats["errors"][-20:]
    log.info("Hygiene run complete: %s (%.2fs)", results, elapsed)
    # Mission log
    try:
        mlog.emit("info", "system", "hygiene.run", f"Hygiene complete: {results['logs_pruned']} logs pruned, {results['souls_capped']} souls capped, {results['memories_archived']} memories archived", elapsed_s=elapsed)
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return results


def _context_hygiene_loop():
    """Background daemon: run hygiene at configured interval."""
    import time as _t
    with _wf_lock:
        _wf_registry["context_hygiene"]["started_at"] = _t.time()
    # Initial delay — let Porter boot
    _t.sleep(60)
    # Run once on startup
    try:
        _t0 = _t.time()
        _hr = _hygiene_run()
        _wf_record_run("context_hygiene", success=True, result=f"logs={_hr.get('logs_pruned',0)}, souls={_hr.get('souls_capped',0)}, archived={_hr.get('memories_archived',0)}", duration_s=_t.time()-_t0)
    except Exception as e:
        log.warning("Hygiene startup run failed: %s", e)
        _wf_record_run("context_hygiene", success=False, error=e)
    while True:
        prefs = _config.get("preferences", {})
        hours = max(1, prefs.get("hygiene_interval_hours", 12))
        _t.sleep(hours * 3600)
        if not prefs.get("hygiene_enabled", True):
            continue
        if not _wf_is_enabled("context_hygiene"):
            continue
        _t0 = _t.time()
        try:
            _hr2 = _hygiene_run()
            _wf_record_run("context_hygiene", success=True, result=f"logs={_hr2.get('logs_pruned',0)}, souls={_hr2.get('souls_capped',0)}, archived={_hr2.get('memories_archived',0)}", duration_s=_t.time()-_t0)
        except Exception as e:
            log.warning("Hygiene loop error: %s", e)
            _wf_record_run("context_hygiene", success=False, error=e, duration_s=_t.time()-_t0)



# v0.29.27 — Session Lifecycle: state machine (active → paused → archived)
_SESSION_PAUSE_SECS = 1800   # 30 minutes
_SESSION_ARCHIVE_SECS = 86400  # 24 hours

def _session_update_activity(chat_id):
    """Mark a chat session as active."""
    import time as _sa
    try:
        conn = _db_conn()
        conn.execute(
            "UPDATE chats SET session_state='active', last_activity=?, paused_at=NULL WHERE id=?",
            (_sa.time(), chat_id))
        conn.commit(); conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
def _session_lifecycle_sweep():
    """Background sweep: pause inactive, archive old sessions."""
    import time as _sl
    now = _sl.time()
    try:
        conn = _db_conn()
        conn.execute(
            "UPDATE chats SET session_state='paused', paused_at=? "
            "WHERE session_state='active' AND last_activity IS NOT NULL AND last_activity < ?",
            (now, now - _SESSION_PAUSE_SECS))
        conn.execute(
            "UPDATE chats SET session_state='archived', archived_at=? "
            "WHERE session_state='paused' AND paused_at IS NOT NULL AND paused_at < ?",
            (now, now - _SESSION_ARCHIVE_SECS))
        conn.commit(); conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
def _project_knowledge_brief(project_id: str) -> dict:
    """Summarize all knowledge Porter has about a project: memories, agents, tasks, decisions."""
    pid = str(project_id or "").strip()
    if not pid:
        return {"ok": False, "error": "project_id required"}
    # Get project metadata
    proj = _project_by_id(pid)
    if not proj:
        return {"ok": False, "error": "project not found"}
    brief = {
        "ok": True,
        "project": {"id": pid, "name": proj.get("name", ""), "description": proj.get("description", "")},
        "knowledge": {"facts": [], "total": 0, "by_agent": {}, "top_keywords": {}},
        "agents": [],
        "tasks": {"pending": 0, "in_progress": 0, "complete": 0, "items": []},
        "recent_activity": [],
    }
    try:
        conn = _db_conn()
        # Project-scoped memories (V2)
        rows = conn.execute(
            "SELECT text, source_id, importance, confidence, evidence_count, keywords, use_count, created_at "
            "FROM memories WHERE scope='project' AND scope_id=? AND status='active' "
            "ORDER BY confidence DESC, importance DESC LIMIT 50", (pid,)
        ).fetchall()
        total = conn.execute(
            "SELECT COUNT(*) FROM memories WHERE scope='project' AND scope_id=? AND status='active'", (pid,)
        ).fetchone()[0]
        brief["knowledge"]["total"] = total
        kw_counts = {}
        for r in rows:
            fact = {"fact": r["text"], "confidence": r["confidence"], "importance": r["importance"],
                    "evidence_count": r["evidence_count"], "use_count": r["use_count"]}
            # Agent attribution
            if r["source_id"]:
                agent_name = r["source_id"]
                persona = conn.execute("SELECT name FROM personas WHERE id=?", (r["source_id"],)).fetchone()
                if persona:
                    agent_name = persona["name"]
                fact["agent"] = agent_name
                brief["knowledge"]["by_agent"][agent_name] = brief["knowledge"]["by_agent"].get(agent_name, 0) + 1
            brief["knowledge"]["facts"].append(fact)
            # Keyword frequency
            for kw in (r["keywords"] or "").split(","):
                kw = kw.strip()
                if kw and len(kw) > 2:
                    kw_counts[kw] = kw_counts.get(kw, 0) + 1
        # Top 10 keywords
        brief["knowledge"]["top_keywords"] = dict(sorted(kw_counts.items(), key=lambda x: -x[1])[:10])
        # Assigned agents
        for aid in (proj.get("assigned_personas") or []):
            persona = conn.execute("SELECT id, name, avatar, role, preferred_backend, status FROM personas WHERE id=?", (aid,)).fetchone()
            if persona:
                brief["agents"].append(dict(persona))
        # Tasks
        task_rows = conn.execute(
            "SELECT id, title, status, priority, assigned_persona_id FROM tasks WHERE project_id=? ORDER BY updated_at DESC LIMIT 20", (pid,)
        ).fetchall()
        if not task_rows:
            # Try task registry files
            pass
        for t in task_rows:
            status = t["status"] or "pending"
            if status == "pending": brief["tasks"]["pending"] += 1
            elif status == "in_progress": brief["tasks"]["in_progress"] += 1
            elif status in ("complete", "completed"): brief["tasks"]["complete"] += 1
            brief["tasks"]["items"].append({"title": t["title"], "status": status, "priority": t["priority"]})
        # Recent activity (last 10 trace steps for this project)
        traces = conn.execute(
            "SELECT agent_name, action, status, output_summary, ts FROM trace_steps "
            "WHERE project_id=? ORDER BY ts DESC LIMIT 10", (pid,)
        ).fetchall()
        for tr in traces:
            brief["recent_activity"].append({
                "agent": tr["agent_name"], "action": tr["action"],
                "status": tr["status"], "summary": (tr["output_summary"] or "")[:100],
                "ts": tr["ts"]
            })
        conn.close()
    except Exception as e:
        brief["_error"] = str(e)
    return brief


def _build_project_dispatch_context(project_id, persona_id="", task_id="", message=""):
    """Build compact project-specific context for persona dispatch."""
    pid = str(project_id or "").strip()
    if not pid:
        return ""
    proj = _project_by_id(pid)
    if not proj:
        return ""

    parts = []
    pname = str(proj.get("name") or pid).strip()
    pdesc = str(proj.get("description") or "").strip()
    if pname:
        parts.append(f"--- Active Project ---\n{pname} [{pid}]")
        if pdesc:
            parts.append(f"Project summary: {pdesc[:300]}")

    anatomy_ctx = _project_anatomy_context(pid, max_chars=1800)
    if anatomy_ctx:
        parts.append(anatomy_ctx)

    project_dir = _project_shared_dir(pid)
    decision_path = project_dir / "DECISION_LOG.md"
    if decision_path.exists():
        try:
            decisions = [ln.strip() for ln in decision_path.read_text(encoding="utf-8", errors="replace").splitlines() if ln.strip()]
            decision_rows = [ln for ln in decisions if ln.startswith("|") and "------" not in ln]
            if len(decision_rows) > 1:
                parts.append("Recent decisions:\n" + "\n".join(decision_rows[-4:]))
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    task = _task_by_id(task_id)
    if task:
        ttitle = str(task.get("title") or "Untitled").strip()
        tdesc = str(task.get("description") or "").strip()
        tstatus = str(task.get("status") or "pending").strip()
        parts.append(f"Current task:\n- [{tstatus}] {ttitle}")
        if tdesc:
            parts.append("Task details:\n" + tdesc[:700])

    try:
        with _treg_lock:
            project_tasks = [dict(t) for t in _treg.values() if str(t.get("project_id") or "").strip() == pid]
        assigned = []
        backlog = []
        for t in project_tasks:
            status = str(t.get("status") or "").strip()
            if status in {"complete", "completed", "done", "cancelled"}:
                continue
            bucket = assigned if str(t.get("assigned_persona_id") or "").strip() == str(persona_id or "").strip() else backlog
            bucket.append(t)
        assigned.sort(key=lambda t: (str(t.get("priority") or ""), -(float(t.get("updated_at") or 0))))
        backlog.sort(key=lambda t: (str(t.get("priority") or ""), -(float(t.get("updated_at") or 0))))
        if assigned:
            lines = [f"- [{str(t.get('status') or 'pending')}] {str(t.get('title') or 'Untitled')[:120]}" for t in assigned[:4]]
            parts.append("Your pending tasks:\n" + "\n".join(lines))
        if backlog:
            lines = [f"- [{str(t.get('status') or 'pending')}] {str(t.get('title') or 'Untitled')[:120]}" for t in backlog[:4]]
            parts.append("Other project tasks in flight:\n" + "\n".join(lines))
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    try:
        conn = _db_conn()
        rows = conn.execute(
            "SELECT agent_name, action, status, output_summary, ts FROM trace_steps "
            "WHERE project_id=? ORDER BY ts DESC LIMIT 5",
            (pid,)
        ).fetchall()
        conn.close()
        if rows:
            lines = []
            for r in rows:
                who = str(r[0] or "Agent").strip()
                action = str(r[1] or "work").strip()
                status = str(r[2] or "").strip()
                summary = str(r[3] or "").strip()
                line = f"- {who}: {action}"
                if status:
                    line += f" [{status}]"
                if summary:
                    line += f" — {summary[:140]}"
                lines.append(line)
            parts.append("Recent project activity:\n" + "\n".join(lines))
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    try:
        state_ctx = _project_state_context(pid, persona_id=persona_id, limit=5)
        if state_ctx:
            parts.append(state_ctx[:1200])
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    if not parts:
        return ""
    return "\n\n".join(parts)[:3200]


# ─── Memory V2: Dispatch Integration (v0.31.88) ──────────────────────────────


def _estimate_tokens(text: str) -> int:
    """Fast approximation: 1 token ~= 4 chars (stdlib-safe, no tiktoken needed)."""
    return max(1, len(text) // 4)


def _get_directives(persona_id='', project_id=''):
    """Get directives for injection — always included first."""
    conn = _db_conn()
    try:
        rows = conn.execute(
            "SELECT id, text, scope, scope_id FROM memories "
            "WHERE memory_kind='directive' AND status='active' "
            "AND (scope='global' OR (scope='agent' AND scope_id=?) OR (scope='project' AND scope_id=?)) "
            "ORDER BY importance DESC, created_at DESC",
            (persona_id, project_id)
        ).fetchall()
        return [dict(r) for r in rows]
    except Exception as _e:
        mlog.emit("warn", "memory", "exception.swallowed", str(_e),
                  extra={"exc_type": type(_e).__name__, "fn": "_get_directives"})
        return []
    finally:
        conn.close()


def _get_concepts(persona_id='', project_id='', query=''):
    """Get concepts for injection — included after directives, ranked by relevance."""
    conn = _db_conn()
    try:
        if query and len(query) > 3:
            # FTS5 relevance search
            import re as _re
            fts_q = _re.sub(r'[^\w\s]', ' ', query[:100]).strip()
            terms = fts_q.split()
            fts_q = ' OR '.join('"' + t + '"*' for t in terms if t) if terms else ''
            if fts_q:
                rows = conn.execute(
                    "SELECT m.id, m.text, m.scope, m.scope_id FROM memories m "
                    "JOIN memories_fts f ON m.id = f.rowid "
                    "WHERE memories_fts MATCH ? AND m.memory_kind='concept' AND m.status='active' "
                    "AND (m.scope='global' OR (m.scope='agent' AND m.scope_id=?) "
                    "     OR (m.scope='project' AND m.scope_id=?)) "
                    "ORDER BY rank LIMIT 20",
                    (fts_q, persona_id, project_id)
                ).fetchall()
                return [dict(r) for r in rows]
        rows = conn.execute(
            "SELECT id, text, scope, scope_id FROM memories "
            "WHERE memory_kind='concept' AND status='active' "
            "AND (scope='global' OR (scope='agent' AND scope_id=?) OR (scope='project' AND scope_id=?)) "
            "ORDER BY importance DESC, last_used_at DESC, created_at DESC LIMIT 20",
            (persona_id, project_id)
        ).fetchall()
        return [dict(r) for r in rows]
    except Exception as _e:
        mlog.emit("warn", "memory", "exception.swallowed", str(_e),
                  extra={"exc_type": type(_e).__name__, "fn": "_get_concepts"})
        return []
    finally:
        conn.close()


def _get_recent_episodes(persona_id='', project_id='', limit=5):
    """Get recent episodes — included last if token budget allows."""
    conn = _db_conn()
    try:
        rows = conn.execute(
            "SELECT id, text, scope, scope_id FROM memories "
            "WHERE memory_kind='episode' AND status='active' "
            "AND (scope='global' OR (scope='agent' AND scope_id=?) OR (scope='project' AND scope_id=?)) "
            "ORDER BY created_at DESC LIMIT ?",
            (persona_id, project_id, limit)
        ).fetchall()
        return [dict(r) for r in rows]
    except Exception as _e:
        mlog.emit("warn", "memory", "exception.swallowed", str(_e),
                  extra={"exc_type": type(_e).__name__, "fn": "_get_recent_episodes"})
        return []
    finally:
        conn.close()




def _mem_inject_for_dispatch(message, persona_id='', project_id='', run_id='', token_cap=500):
    """Frozen snapshot injection with tiered priority and token cap.

    Tier 1: Directives (always, highest priority)
    Tier 2: Concepts (relevant to scope + message)
    Tier 3: Episodes (recent, only if budget remains)

    Returns a string block ready for context injection, or '' if no memories.
    token_cap can be overridden by _build_context_suffix memory_budget.
    """
    used_tokens = 0
    parts = []

    # Check project privacy — private projects block global injection
    is_private = _project_is_private(project_id) if project_id else False

    # Tier 1: Directives (always first)
    for mem in _get_directives(persona_id, project_id):
        if is_private and mem.get('scope') == 'global':
            continue  # Private project: skip global directives
        est = _estimate_tokens(mem['text'])
        if used_tokens + est > token_cap:
            break
        parts.append(f"[DIRECTIVE] {mem['text']}")
        used_tokens += est
        _mem_record_injection(mem['id'])

    # Tier 2: Concepts (relevant to scope + message content)
    query_text = message if isinstance(message, str) else str(message)
    for mem in _get_concepts(persona_id, project_id, query_text):
        if is_private and mem.get('scope') == 'global':
            continue
        est = _estimate_tokens(mem['text'])
        if used_tokens + est > token_cap:
            break
        parts.append(f"[CONCEPT] {mem['text']}")
        used_tokens += est
        _mem_record_injection(mem['id'])

    # Tier 3: Episodes (only if under 80% budget)
    if used_tokens < token_cap * 0.8:
        for mem in _get_recent_episodes(persona_id, project_id):
            if is_private and mem.get('scope') == 'global':
                continue
            est = _estimate_tokens(mem['text'])
            if used_tokens + est > token_cap:
                break
            parts.append(f"[EPISODE] {mem['text']}")
            used_tokens += est
            _mem_record_injection(mem['id'])

    if parts:
        mlog.emit("debug", "memory", "recall.injected",
                  f"Injected {len(parts)} memories ({used_tokens} est tokens)",
                  extra={"count": len(parts), "tokens": used_tokens,
                         "persona_id": persona_id, "project_id": project_id})

    return '\n'.join(parts) if parts else ''



def _mem_extract_signals(message, response, persona_id='', project_id='', run_id='', source_category=''):
    """Memory V2: extract signals from dispatch response.
    Lightweight keyword-based extraction — no LLM call needed."""
    # Noise filter — block signal extraction for non-learning actions
    if not _recall_should_extract(source_category if source_category else 'chat'):
        return 0
    if not response or len(response) < 50:
        return 0
    import re as _re
    sentences = _re.split(r'[.!?\n]+', response)
    signal_keywords = ('should', 'must', 'need to', 'recommend', 'decided', 'confirmed',
                       'discovered', 'found that', 'learned', 'note:', 'important:',
                       'bug:', 'fix:', 'issue:', 'prefer', 'always', 'never')
    signals = []
    for s in sentences:
        s = s.strip()
        if len(s) < 20 or len(s) > 300:
            continue
        lower = s.lower()
        if any(kw in lower for kw in signal_keywords):
            signals.append(s)
    if not signals:
        return 0
    inserted = 0
    for sig_text in signals[:5]:
        # Dedup via FTS5
        try:
            existing = _mem_search(sig_text, limit=3)
            if any(e.get('preview', '')[:60].lower() in sig_text.lower() for e in existing if e.get('preview')):
                continue
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        # Categorize
        lower = sig_text.lower()
        if any(k in lower for k in ('bug', 'fix', 'error', 'issue')):
            cat = 'bugfix'
        elif any(k in lower for k in ('decided', 'decision', 'chose')):
            cat = 'decision'
        elif any(k in lower for k in ('prefer', 'always', 'never')):
            cat = 'preference'
        elif any(k in lower for k in ('found', 'discover', 'learned')):
            cat = 'discovery'
        else:
            cat = 'rule'
        _mem_insert(
            memory_kind='signal', text=sig_text, scope='global',
            scope_id='', trust_tier='low', source_type='dispatch',
            source_id=run_id or '', source_category=cat,
            confidence=0.3, importance=4, review_state='pending')
        inserted += 1
    return inserted



def _build_lean_identity(persona_id: str) -> str:
    """Phase 3 — PERF-01: Build a lean identity block for persona dispatch.

    Replaces _build_context_suffix() for the system prompt.
    Output: ~200-300 tokens of agent identity + awareness + guardrails.
    Memory injection is handled separately by _mem_inject_for_dispatch().

    Circuit breaker: if prompt exceeds 2K tokens, logs a warning and
    returns a minimal fallback to prevent bloated prompts.
    """
    conn = _db_conn()
    try:
        row = conn.execute(
            "SELECT name, role, config FROM personas WHERE id=?",
            (persona_id,)
        ).fetchone()
        if not row:
            return "You are an AI assistant. Never fabricate data. Never claim tasks done without verification. Say when you don't know."
        name = row[0] or 'Agent'
        role = row[1] or ''
        try:
            import json as _json
            cfg = _json.loads(row[2] or '{}')
        except Exception:
            cfg = {}
        description = cfg.get('description', '') or role
        awareness_mode = cfg.get('awareness_mode', 'aware')

        # Identity line
        identity_line = f"You are {name}, {description}." if description else f"You are {name}."

        # Awareness block
        if awareness_mode == 'sandboxed':
            awareness_block = "You are a focused assistant. Handle tasks within your assigned domain."
        else:  # default: aware
            awareness_block = (
                "You work within Porter, an AI orchestration platform. "
                "Use Porter's resources (memory, project context, tools) for tasks outside your direct scope. "
                "Other agents exist and Porter coordinates delegation."
            )

        # Guardrails — always present
        guardrails = "Rules: (1) Never fabricate data or sources. (2) Never claim a task is done without verification. (3) Say when you don't know."

        prompt = f"{identity_line}\n{awareness_block}\n{guardrails}"

        # Circuit breaker: if somehow > 2000 tokens, log and return minimal fallback
        est_tokens = _estimate_tokens(prompt)
        if est_tokens > 2000:
            mlog.emit("warn", "system", "prompt.circuit_breaker",
                      f"Lean identity for {persona_id} exceeded 2K tokens ({est_tokens}), using minimal fallback",
                      extra={"persona_id": persona_id, "tokens": est_tokens})
            return f"You are {name}. Never fabricate data. Never claim tasks done without verification. Say when you don't know."

        return prompt
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__, "fn": "_build_lean_identity"})
        return "You are an AI assistant. Never fabricate data. Never claim tasks done without verification. Say when you don't know."
    finally:
        conn.close()


# DEPRECATED Phase 3: replaced by _build_lean_identity()
def _build_context_suffix(persona_id, message="", project_id="", task_id=""):
    """Build a lean context suffix for persona dispatch.
    v0.29.18: Trimmed from ~4.5KB to ~2KB by dropping redundant files."""
    prefs = _config.get("preferences", {})
    total_budget = max(800, prefs.get("hygiene_ctx_budget", 2500))
    pdir = PERSONAS_DIR / persona_id
    # Budget: SOUL 55%, RULES 25%, MEMORY V2 20% (v0.31.88: FTS5 injection)
    soul_budget = int(total_budget * 0.55)
    rules_budget = int(total_budget * 0.25)
    memory_budget = int(total_budget * 0.20)
    parts = []
    # SOUL.md — primary identity source (replaces IDENTITY.md + ROLE_CARD.md)
    soul_path = pdir / "SOUL.md"
    if soul_path.exists():
        soul = soul_path.read_text().strip()
        if soul:
            parts.append(f"--- SOUL ---\n{soul[:soul_budget]}\n---")
    # RULES.md — communication + task rules only (skip ship process)
    rules_path = PERSONAS_DIR / "RULES.md"
    if rules_path.exists():
        rules = rules_path.read_text().strip()
        if rules:
            # Strip ship process section — not relevant to chat dispatch
            _ship_idx = rules.find("## 6. Ship Process")
            if _ship_idx > 0:
                rules = rules[:_ship_idx].rstrip()
            parts.append(f"--- Rules ---\n{rules[:rules_budget]}\n---")
    # v0.31.88 — Memory V2: inject operational memories via FTS5
    try:
        _mem_ctx = _mem_inject_for_dispatch(message, persona_id=persona_id, project_id=project_id, token_cap=memory_budget)
        if _mem_ctx:
            parts.append(_mem_ctx[:memory_budget])
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # MEM-04 — Recall prior work: search agent's past sessions before dispatch
    try:
        _prior_work = _recall_prior_work(persona_id, message, limit=3)
        if _prior_work:
            parts.append(_prior_work)
            mlog.emit("debug", "memory", "recall.prior_work",
                      f"Injected prior work context for agent {persona_id}",
                      extra={"persona_id": persona_id})
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Squad roster — compact one-liner per teammate
    try:
        teammates = _persona_list()
        if len(teammates) > 1:
            roster = ", ".join(
                f"{tm.get('name','?')} ({tm.get('role','')})"
                for tm in teammates if tm.get("id") != persona_id
            )
            if roster:
                parts.append(f"Squad: {roster}\nIf outside scope: [HANDOFF: AgentName] reason")
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    try:
        proj_ctx = _build_project_dispatch_context(project_id, persona_id=persona_id, task_id=task_id, message=message)
        if proj_ctx:
            parts.append(proj_ctx)
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # v0.30.39 — Inject failure lessons from recent failed dispatches
    try:
        _fail_ctx = _build_failure_context(persona_id, backend="", message=message)
        if _fail_ctx:
            parts.append(_fail_ctx)
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return "\n\n".join(parts)




def _build_failure_context(persona_id: str, backend: str, message: str = "") -> str:
    """v0.30.39 — Cortex-driven optimization: extract recent failure patterns for this agent+backend.

    Looks at the last 24h of failed dispatches for this persona and backend.
    If failures exist, returns a brief context block summarizing what went wrong
    so the agent can avoid repeating the same mistakes.
    """
    try:
        conn = _db_conn()
        rows = conn.execute("""
            SELECT error, created_at FROM agent_messages
            WHERE persona_id = ? AND status = 'failed'
              AND created_at > strftime('%s','now') - 86400
            ORDER BY created_at DESC LIMIT 5
        """, (persona_id,)).fetchall()
        conn.close()
        if not rows:
            return ""
        # Deduplicate error messages
        seen = set()
        unique_errors = []
        for r in rows:
            err = (r[0] or "")[:100].strip()
            if err and err not in seen:
                seen.add(err)
                unique_errors.append(err)
        if not unique_errors:
            return ""
        error_list = "\n".join(f"- {e}" for e in unique_errors[:3])
        return (f"--- Recent Failures (last 24h) ---\n"
                f"Previous dispatches to you failed with:\n{error_list}\n"
                f"Avoid approaches that led to these errors.\n---")
    except Exception:
        return ""



def _boot_sequence():
    """Detect -> notify -> install -> configure -> verify -> badge.

    Runs once at startup before accepting HTTP requests.
    Checks required and optional capabilities, logs results via mlog,
    and populates _capabilities_cache for UI badging.
    """
    import sys as _sys
    import subprocess as _subprocess
    import urllib.request as _urllib_req

    results = {}

    # 1. Required: Python stdlib (always available)
    results["python"] = {"ok": True, "version": _sys.version.split()[0]}

    # 2. Required: SQLite DB writable
    try:
        _bconn = _db_conn()
        _bconn.execute("SELECT 1")
        results["sqlite"] = {"ok": True, "path": str(DB_PATH)}
    except Exception as _e:
        results["sqlite"] = {"ok": False, "error": str(_e)}

    # 3. Required: Data directory exists and is writable
    try:
        _DATA_DIR.mkdir(parents=True, exist_ok=True)
        _dir_ok = _DATA_DIR.exists() and os.access(str(_DATA_DIR), os.W_OK)
    except Exception:
        _dir_ok = False
    results["data_dir"] = {"ok": _dir_ok, "path": str(_DATA_DIR)}

    # 4. Optional: Node.js (for Fastify backend)
    try:
        _node_r = _subprocess.run(
            ["node", "--version"], capture_output=True, text=True, timeout=5
        )
        results["node"] = {
            "ok": _node_r.returncode == 0,
            "version": _node_r.stdout.strip(),
        }
    except Exception as _e:
        results["node"] = {"ok": False, "error": "node not found"}

    # 5. Optional: Ollama (local models)
    try:
        _ollama_resp = _urllib_req.urlopen(
            "http://127.0.0.1:11434/api/tags", timeout=3
        )
        results["ollama"] = {"ok": True}
    except Exception:
        results["ollama"] = {"ok": False, "error": "Ollama not reachable"}

    # 6. Optional: OpenClaw gateway (only if OPENCLAW_URL is set)
    _openclaw_url = os.environ.get("OPENCLAW_URL", "").strip()
    if _openclaw_url:
        try:
            _oc_resp = _urllib_req.urlopen(f"{_openclaw_url}/health", timeout=3)
            results["openclaw"] = {"ok": True, "url": _openclaw_url}
        except Exception as _e:
            results["openclaw"] = {
                "ok": False,
                "error": f"OpenClaw not reachable at {_openclaw_url}",
            }
    else:
        results["openclaw"] = {
            "ok": False,
            "error": "OPENCLAW_URL not configured (skipped)",
        }

    # Store for UI badging (merge into existing capabilities cache)
    _capabilities_cache.update({
        f"boot.{k}": {
            "id": f"boot.{k}",
            "label": k,
            "ok": v.get("ok", False),
            "version": v.get("version"),
            "checked_at": __import__("time").time(),
        }
        for k, v in results.items()
    })

    # Log summary with structured mlog
    _required_ok = all(
        results.get(k, {}).get("ok", False) for k in ["python", "sqlite", "data_dir"]
    )
    _optional_missing = [
        k for k in ["node", "ollama", "openclaw"]
        if not results.get(k, {}).get("ok", False)
    ]

    if _required_ok and not _optional_missing:
        mlog.emit(
            "info", "system", "boot.ok",
            "All capabilities verified",
            extra={"capabilities": results},
        )
    elif _required_ok:
        mlog.emit(
            "warn", "system", "boot.degraded",
            f"Optional capabilities missing: {_optional_missing}",
            extra={"capabilities": results},
        )
    else:
        _failed = [
            k for k in ["python", "sqlite", "data_dir"]
            if not results.get(k, {}).get("ok", False)
        ]
        mlog.emit(
            "error", "system", "boot.critical",
            f"Required capabilities failed: {_failed}",
            extra={"capabilities": results},
        )

    return results


def _run_cap_checks(force: bool = False):
    """Run all capability checks; cache with 30s TTL. Pass force=True to bypass TTL."""
    global _capabilities_cache_ts
    if not force and _capabilities_cache and (time.time() - _capabilities_cache_ts) < 30:
        return  # Cache is fresh enough
    _cap_start_t = time.time()
    checked = {}
    for cap in AI_PROVIDERS + CAPABILITIES:
        try:
            result = cap["check"]()
            checked[cap["id"]] = {
                "id": cap["id"], "label": cap["label"],
                "ok": result.get("ok", False),
                "version": result.get("version"),
                "install": cap["install"],
                "features": cap["features"],
                "checked_at": time.time(),
            }
        except Exception as exc:
            checked[cap["id"]] = {
                "id": cap["id"], "label": cap["label"],
                "ok": False, "version": None,
                "install": cap["install"],
                "features": cap["features"],
                "checked_at": time.time(),
                "error": str(exc),
            }
    _capabilities_cache.update(checked)
    _cap_check_duration = time.time() - _cap_start_t
    _capabilities_cache_ts = time.time()
    _wf_record_run("capability_checks", success=True,
                    result=f"{sum(1 for v in checked.values() if v.get('ok'))}/{len(checked)} ok",
                    duration_s=_cap_check_duration)
    try:
        (RUNTIME_DIR / "capabilities.json").write_text(
            json.dumps(list(checked.values()), indent=2)
        )
    except Exception as e:
        log.debug("Ignored: %s", e)

