def _migrate_checkpoint_to_registry():
    """One-time migration: read checkpoint.md and ensure all items exist in task registry.

    After migration, checkpoint.md is marked deprecated. The task registry
    is the sole source of truth for task state going forward.
    """
    checkpoint_path = _DATA_DIR / "tasks" / "checkpoint.md"
    if not checkpoint_path.exists():
        return

    raw = checkpoint_path.read_text(encoding="utf-8")

    # Check if already migrated
    if "DEPRECATED" in raw[:200]:
        return

    # Parse checkpoint items
    import re as _re
    completed_items = _re.findall(r"- \[x\] (.+)", raw)
    pending_items = _re.findall(r"- \[ \] (.+)", raw)

    # Check each item against task registry
    treg_dir = RUNTIME_DIR / "task-registry"
    if not treg_dir.exists():
        return

    existing_titles = set()
    for fp in treg_dir.glob("*.json"):
        try:
            t = json.loads(fp.read_text())
            existing_titles.add(t.get("title", "").lower())
        except Exception as e:
            log.debug("Ignored: %s", e)

    migrated = 0
    for item in pending_items:
        # Check if a matching task already exists
        item_lower = item.lower().strip()
        found = False
        for title in existing_titles:
            if item_lower[:30] in title or title[:30] in item_lower:
                found = True
                break
        if not found:
            # Create a new task registry entry
            import uuid
            active_project_id = str(_config.get("active_project_id") or "").strip()
            active_project_name = ""
            if active_project_id:
                try:
                    active_project_name = (_project_by_id(active_project_id) or {}).get("name", "")
                except Exception:
                    active_project_name = ""
            task = {
                "id": str(uuid.uuid4()),
                "title": f"Migrated: {item[:80]}",
                "description": f"Auto-migrated from checkpoint.md: {item}",
                "status": "pending",
                "priority": "normal",
                "project_id": active_project_id,
                "project_name": active_project_name or "Active Project",
                "tags": ["migrated", "checkpoint"],
                "sort_order": 50,
                "assigned_agent_id": None,
                "assigned_persona_id": None,
                "created_by": "checkpoint-migration",
                "created_at": time.time(),
                "updated_at": time.time(),
                "tokens_used": None,
                "time_spent_mins": None,
                "result": None,
            }
            fp = treg_dir / f"{task['id']}.json"
            fp.write_text(json.dumps(task, indent=2))
            migrated += 1

    # Mark checkpoint.md as deprecated
    deprecated_header = """# Checkpoint — DEPRECATED
# This file is no longer the source of truth for task state.
# All tasks are now tracked in runtime/task-registry/*.json
# This file is kept for historical reference only.
# Last migrated: """ + time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime()) + """
#
"""
    checkpoint_path.write_text(deprecated_header + raw, encoding="utf-8")
    if migrated:
        log.info("Checkpoint migration: %d items migrated to task registry", migrated)


def _time_ago(ts: float) -> str:
    """Human-readable relative time from a unix timestamp."""
    delta = int(time.time() - ts)
    if delta < 60:    return "just now"
    if delta < 3600:  return f"{delta // 60}m ago"
    if delta < 86400: return f"{delta // 3600}h ago"
    return f"{delta // 86400}d ago"


def _find_projects_file():
    """Locate projects.md: explicit config key then root of each SERVE_DIR."""
    configured = _config.get("projects_file", "").strip()
    if configured and Path(configured).exists():
        return Path(configured)
    for _label, root in SERVE_DIRS.items():
        candidate = root / 'projects.md'
        if candidate.exists():
            return candidate
    return None


def _project_is_private(project_id: str) -> bool:
    """Check project privacy toggle — private projects block global memory injection."""
    if not project_id:
        return False
    try:
        conn = _db_conn()
        row = conn.execute(
            "SELECT metadata FROM projects WHERE id=?", (str(project_id),)
        ).fetchone()
        conn.close()
        if row:
            meta_raw = row['metadata'] if row['metadata'] else '{}'
            if isinstance(meta_raw, str):
                meta = json.loads(meta_raw)
            else:
                meta = meta_raw or {}
            return bool(meta.get('private', False))
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed", str(_e),
                  extra={"exc_type": type(_e).__name__, "fn": "_project_is_private"})
    return False


def _project_by_id(project_id: str | None) -> dict | None:
    """Load a project by ID from SQLite."""
    pid = str(project_id or "").strip()
    if not pid:
        return None
    conn = _db_conn()
    try:
        row = conn.execute("SELECT * FROM projects WHERE id = ?", (pid,)).fetchone()
        if row:
            proj = _project_row_to_dict(row)
            _normalize_project_assigned_personas(proj, persist=False)
            return proj
        return None
    except Exception as e:
        mlog.emit("warn", "db", "project.read_failed", str(e),
                  extra={"exc_type": type(e).__name__})
        return None


def _project_list(owner_id=None, status=None, include_all=False) -> list:
    """List projects from SQLite, optionally filtered by owner or status."""
    conn = _db_conn()
    try:
        query = "SELECT * FROM projects"
        params = []
        conditions = []
        if owner_id and not include_all:
            conditions.append("owner_id = ?")
            params.append(owner_id)
        if status:
            conditions.append("status = ?")
            params.append(status)
        if conditions:
            query += " WHERE " + " AND ".join(conditions)
        query += " ORDER BY updated_at DESC"
        rows = conn.execute(query, params).fetchall()
        return [_project_row_to_dict(r) for r in rows]
    except Exception as e:
        mlog.emit("warn", "db", "project.list_failed", str(e),
                  extra={"exc_type": type(e).__name__})
        return []


def _db_project_save(proj: dict) -> None:
    """Persist a full project dict back to SQLite (upsert)."""
    import time as _time
    proj["updated_at"] = _time.time()
    row_vals = _project_dict_to_row(proj)
    conn = _db_conn()
    try:
        conn.execute("""
            INSERT OR REPLACE INTO projects
                (id, name, slug, type, status, description, owner_id,
                 milestones, artifacts, links, metadata, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, row_vals)
        conn.commit()
    except Exception as e:
        mlog.emit("error", "db", "project.save_failed", str(e),
                  extra={"exc_type": type(e).__name__})
        raise


def _normalize_project_assigned_personas(proj: dict | None, persist: bool = False) -> list[str]:
    if not isinstance(proj, dict):
        return []
    raw_ids = [str(x).strip() for x in (proj.get("assigned_personas") or []) if str(x).strip()]
    if not raw_ids:
        proj["assigned_personas"] = []
        return []
    unique_ids = []
    seen_ids = set()
    for aid in raw_ids:
        if aid not in seen_ids:
            seen_ids.add(aid)
            unique_ids.append(aid)
    changed = unique_ids != raw_ids
    try:
        conn = _db_conn()
        cols = {str(r[1]) for r in conn.execute("PRAGMA table_info(personas)").fetchall()}
        has_owner = "owner" in cols
        has_managed = "managed_by_porter" in cols
        has_created = "created_at" in cols
        select_cols = ["id", "name"]
        if has_owner:
            select_cols.append("owner")
        if has_managed:
            select_cols.append("managed_by_porter")
        if has_created:
            select_cols.append("created_at")
        rows = {}
        for aid in unique_ids:
            row = conn.execute(f"SELECT {', '.join(select_cols)} FROM personas WHERE id=?", (aid,)).fetchone()
            if row:
                if isinstance(row, sqlite3.Row):
                    rows[aid] = {k: row[k] for k in row.keys()}
                else:
                    rows[aid] = {select_cols[i]: row[i] for i in range(len(select_cols))}
        conn.close()
        owner = str(proj.get("owner") or "").strip().lower()
        chosen = {}
        order = []
        for idx, aid in enumerate(unique_ids):
            row = rows.get(aid)
            if not row:
                changed = True
                continue
            name_key = str((row.get("name") or aid)).strip().lower()
            candidate = {
                "id": aid,
                "name_key": name_key,
                "owner_match": 1 if owner and str(row.get("owner") or "").strip().lower() == owner else 0,
                "managed": 1 if row.get("managed_by_porter") else 0,
                "created_at": str(row.get("created_at") or ""),
                "index": idx,
            }
            current = chosen.get(name_key)
            if not current:
                chosen[name_key] = candidate
                order.append(name_key)
                continue
            better = False
            if candidate["owner_match"] != current["owner_match"]:
                better = candidate["owner_match"] > current["owner_match"]
            elif candidate["managed"] != current["managed"]:
                better = candidate["managed"] > current["managed"]
            elif candidate["created_at"] and current["created_at"] and candidate["created_at"] < current["created_at"]:
                better = True
            if better:
                chosen[name_key] = candidate
            changed = True
        normalized = [chosen[k]["id"] for k in order if k in chosen]
    except Exception:
        normalized = unique_ids
    proj["assigned_personas"] = normalized
    if changed and persist:
        try:
            _db_project_save(proj)
        except Exception:
            pass  # Non-critical normalize persist failure
    return normalized


def _task_by_id(task_id: str | None) -> dict | None:
    tid = str(task_id or "").strip()
    if not tid:
        return None
    with _treg_lock:
        task = _treg.get(tid)
        return dict(task) if task else None


def _persona_project_ids(persona_id: str) -> list[str]:
    pid = str(persona_id or "").strip()
    if not pid:
        return []
    matches = []
    for proj in _project_list(include_all=True):
        assigned = [str(x).strip() for x in (proj.get("assigned_personas") or []) if str(x).strip()]
        if pid in assigned:
            matches.append(str(proj.get("id") or "").strip())
    return [m for m in matches if m]


def _resolve_persona_project(persona_id: str, explicit_project_id: str | None = None, task_id: str | None = None) -> str:
    task = _task_by_id(task_id)
    if task and str(task.get("project_id") or "").strip():
        return str(task.get("project_id") or "").strip()
    explicit = str(explicit_project_id or "").strip()
    if explicit and _project_by_id(explicit):
        return explicit
    active = str(_config.get("active_project_id") or "").strip()
    if active:
        active_proj = _project_by_id(active)
        assigned = [str(x).strip() for x in (active_proj or {}).get("assigned_personas", []) if str(x).strip()]
        if not assigned or str(persona_id or "").strip() in assigned:
            return active
    matches = _persona_project_ids(persona_id)
    if len(matches) == 1:
        return matches[0]
    # v0.30.43 — Squad-project binding: check if agent's squad has a project
    try:
        conn = _db_conn()
        squad_proj = conn.execute(
            "SELECT s.project_id FROM squads s "
            "JOIN squad_members sm ON s.id = sm.squad_id "
            "WHERE sm.persona_id = ? AND s.project_id != '' AND s.active = 1 "
            "LIMIT 1", (persona_id,)
        ).fetchone()
        conn.close()
        if squad_proj and squad_proj[0]:
            return squad_proj[0]
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return ""


