def _project_state_payload(project_id: str) -> dict:
    proj = _project_by_id(project_id) or {}
    artifact_info = _project_artifact_listing(project_id)
    directives = _state_list_directives("project", str(project_id or "").strip())
    notes = _state_get_project_notes(project_id, limit=50)
    mem_stats = _mem_stats(scope='project', scope_id=str(project_id or "").strip())
    # Count pending signals for review badge
    pending_signals = 0
    try:
        conn = _db_conn()
        pending_signals = conn.execute(
            "SELECT COUNT(*) FROM memories WHERE review_state='pending' AND status='active' AND scope='project' AND scope_id=?",
            (str(project_id or "").strip(),)).fetchone()[0]
        conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return {
        "project": dict(proj),
        "directives": directives,
        "notes": notes,
        "artifacts": {
            "count": artifact_info.get("artifact_count", 0),
            "dir": artifact_info.get("artifacts_dir", ""),
            "docs_count": artifact_info.get("project_docs_count", 0),
        },
        "memory_stats": mem_stats,
        "pending_signals": pending_signals,
    }


def _agent_state_payload(agent_id: str) -> dict:
    persona = _persona_by_id(agent_id) or {}
    # v0.31.49 — Orchestrators see all projects, workers see only assigned
    if persona.get("orchestrator_only"):
        project_ids = [str(p.get("id", "")) for p in _project_list(include_all=True) if p.get("id")]
    else:
        project_ids = _persona_project_ids(agent_id)
    project_states = [_project_state_payload(pid) for pid in project_ids[:10]]
    directives = _state_list_directives("agent", str(agent_id or "").strip())
    notes = _state_get_agent_notes(agent_id, limit=40)
    if persona and persona.get("orchestrator_only"):
        directives = _state_list_directives("global") + directives
    return {
        "agent": dict(persona),
        "directives": directives,
        "notes": notes,
        "projects": project_states,
    }


def _project_state_context(project_id: str, persona_id: str = "", limit: int = 6) -> str:
    payload = _project_state_payload(project_id)
    proj = payload.get("project") or {}
    if not proj:
        return ""
    parts = []
    anatomy_ctx = _project_anatomy_context(project_id, max_chars=1400)
    if anatomy_ctx:
        parts.append(anatomy_ctx)
    directives = payload.get("directives") or []
    notes = payload.get("notes") or []
    if directives:
        parts.append("Project directives:\n" + "\n".join(f"- [#{d.get('id','?')}] {d.get('text','')[:180]}" for d in directives[:6] if d.get("text")))
    if notes:
        note_lines = []
        for n in notes[:limit]:
            line = f"- {str(n.get('note_kind') or 'note').replace('_',' ')}: {str(n.get('body') or '')[:180]}"
            note_lines.append(line)
        if note_lines:
            parts.append("Project state notes:\n" + "\n".join(note_lines))
    artifact_meta = payload.get("artifacts") or {}
    if artifact_meta.get("count"):
        parts.append(f"Project artifacts: {artifact_meta.get('count')} in {artifact_meta.get('dir')}")
    return "\n\n".join(parts).strip()


def _memory_auto_extract_enabled() -> bool:
    """Whether generic chat/dispatch extraction should write durable memory."""
    return bool(_config.get("preferences", {}).get("memory_auto_extract", False))


def _detect_environment_tools():
    """v0.31.65 — Scan for installed tools and populate environment_tools table."""
    import shutil
    _tool_checks = [
        ("python3", "python3 --version"),
        ("node", "node --version"),
        ("npm", "npm --version"),
        ("git", "git --version"),
        ("docker", "docker --version"),
        ("ollama", "ollama --version"),
        ("gemini", "gemini --version"),
        ("codex", "codex --version"),
        ("sqlite3", "sqlite3 --version"),
        ("curl", "curl --version"),
        ("ffmpeg", "ffmpeg -version"),
        ("playwright", "npx playwright --version"),
    ]
    conn = _db_conn()
    _detected = 0
    for tool_key, version_cmd in _tool_checks:
        found = shutil.which(tool_key) is not None
        version = ""
        if found:
            try:
                result = subprocess.run(version_cmd.split(), capture_output=True, text=True, timeout=5)
                version = result.stdout.strip().split("\n")[0][:80] if result.returncode == 0 else ""
            except Exception as _e:
                mlog.emit("warn", "system", "exception.swallowed",
                          f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        try:
            conn.execute(
                "INSERT OR REPLACE INTO environment_tools (tool_key, detected, version, source, health, last_checked_at) VALUES (?,?,?,?,?,strftime('%s','now'))",
                (tool_key, found, version, "local", "ok" if found else "missing")
            )
            if found:
                _detected += 1
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    conn.commit()
    conn.close()
    log.info("Environment tool scan: %d/%d tools detected", _detected, len(_tool_checks))


def _parse_kv_table(block: str) -> dict:
    """Parse a | Key | Value | markdown table into a dict."""
    result = {}
    for row in re.finditer(r'\|\s*([^|\-][^|]*?)\s*\|\s*([^|]+?)\s*\|', block):
        k, v = row.group(1).strip(), row.group(2).strip()
        if k and k.lower() != "field":
            result[k] = v
    return result


def _parse_projects_md(raw: str) -> list:
    """Extract project entries from Active Projects section of projects.md."""
    projects = []
    m = re.search(r'## Active Projects(.*?)(?=\n## |\Z)', raw, re.DOTALL)
    if not m:
        return projects
    section = m.group(1)
    for pm in re.finditer(r'### (.+?)\n(.*?)(?=\n### |\Z)', section, re.DOTALL):
        name  = pm.group(1).strip()
        block = pm.group(2)
        fields = _parse_kv_table(block)
        kf = re.search(r'\*\*Key files:\*\*(.*?)(?=\n\*\*|\Z)', block, re.DOTALL)
        key_files = []
        if kf:
            for line in kf.group(1).splitlines():
                line = line.strip().lstrip('- ')
                if line:
                    key_files.append(line)
        projects.append({"name": name, "fields": fields, "key_files": key_files})
    return projects


def _parse_model_registry(raw: str) -> list:
    """Extract rows from the Model Registry table in projects.md."""
    models = []
    m = re.search(r'## Model Registry(.*?)(?=\n## |\Z)', raw, re.DOTALL)
    if not m:
        return models
    section = m.group(1)
    rows = re.findall(r'\|([^|\n]+)\|([^|\n]+)\|([^|\n]+)\|([^|\n]+)\|([^|\n]+)\|', section)
    header_found = False
    for cells in rows:
        c = [x.strip() for x in cells]
        if not header_found:
            if c[0].lower() in ('model', 'name'):
                header_found = True
            continue
        if not c[0] or c[0].replace('-','').replace(' ','') == '':
            continue
        models.append({"model": c[0], "identity": c[1], "interface": c[2], "role": c[3], "memory_files": c[4]})
    return models


def _parse_checkpoint_file(path) -> dict:
    """Parse a checkpoint.md YAML-ish header into a dict."""
    raw = Path(path).read_text(encoding='utf-8', errors='replace')
    fields = {"checkpoint_path": str(path)}
    for line in raw.splitlines():
        line = line.strip()
        for key in ("project", "task", "status", "step", "next_action"):
            if line.startswith(key + ':'):
                fields[key] = line[len(key)+1:].strip()
                break
    st = Path(path).stat()
    fields['modified_at']  = st.st_mtime
    fields['modified_ago'] = _time_ago(st.st_mtime)
    return fields


def _scan_checkpoints() -> list:
    """Scan SERVE_DIRs two levels deep for tasks/checkpoint.md."""
    tasks, seen = [], set()
    for _label, root in SERVE_DIRS.items():
        for cp in root.glob('*/tasks/checkpoint.md'):
            if str(cp) in seen:
                continue
            seen.add(str(cp))
            try:
                parsed = _parse_checkpoint_file(cp)
                if parsed.get('status'):
                    tasks.append(parsed)
            except Exception as e:
                log.debug("Ignored: %s", e)
    tasks.sort(key=lambda t: t.get('modified_at', 0), reverse=True)
    return tasks


def _find_sprint_plan():
    """Locate SPRINT_PLAN.md near projects.md or in any serve dir root."""
    pf = _find_projects_file()
    if pf:
        candidate = pf.parent / 'SPRINT_PLAN.md'
        if candidate.exists():
            return candidate
    for _label, root in SERVE_DIRS.items():
        for sp in root.rglob('SPRINT_PLAN.md'):
            return sp
    return None


def _parse_sprint_plan(raw: str) -> list:
    """Extract sprint entries from SPRINT_PLAN.md."""
    sprints = []
    for m in re.finditer(r'^## (Sprint .+?)\n(.*?)(?=^## |\Z)', raw, re.MULTILINE | re.DOTALL):
        title = m.group(1).strip()
        body  = m.group(2)
        complete = (
            'COMPLETE' in title or
            '✓ shipped' in body or
            'COMPLETE' in body[:80]
        )
        is_next = '(NEXT)' in title
        ver_m = re.search(r'\*\*Version:\*\*\s*(.+?)(?:\n|$)', body)
        version = ver_m.group(1).strip() if ver_m else ''
        sprints.append({'title': title, 'version': version, 'complete': complete, 'is_next': is_next})
    return sprints


def scaffold_project_dir(project_id: str, project_name: str) -> "Path":
    """Create project workspace directory with template files. Idempotent."""
    from datetime import datetime, timezone
    proj_dir = AGENT_WORKSPACE_DIR / "projects" / project_id
    proj_dir.mkdir(parents=True, exist_ok=True)
    (proj_dir / "artifacts").mkdir(exist_ok=True)
    now_iso = datetime.now(timezone.utc).isoformat()
    pm = proj_dir / "PROJECT.md"
    if not pm.exists():
        pm.write_text(
            f"# Project: {project_name}\n\n"
            f"ID: {project_id}\n"
            f"Created: {now_iso}\n\n"
            "## Overview\n\n## Goals\n\n## Notes\n"
        )
    sm = proj_dir / "STATE.md"
    if not sm.exists():
        sm.write_text(
            f"# Project State: {project_name}\n\n"
            "*Durable project state for directives, decisions, notes, and artifact context.*\n\n"
            "## Directives\n\n## Decisions\n\n## Notes\n\n## Artifact Context\n"
        )
    sj = proj_dir / "settings.json"
    if not sj.exists():
        sj.write_text(json.dumps({
            "project_id":       project_id,
            "name":             project_name,
            "memory_isolation": "project",
            "agents":           [],
        }, indent=2))
    shared = proj_dir / "00_SHARED"
    shared.mkdir(exist_ok=True)
    _bootstrap_shared_docs(shared, project_name, now_iso)

    return proj_dir


