def _project_shared_dir(project_id: str) -> "Path":
    return AGENT_WORKSPACE_DIR / "projects" / str(project_id) / "00_SHARED"


def _read_project_context_file(path: "Path", limit: int = 1200) -> str:
    try:
        text = path.read_text(encoding="utf-8", errors="replace").strip()
    except Exception:
        return ""
    if not text:
        return ""
    return text[:limit]


def _project_context_snapshot(project_id: str) -> dict:
    pid = str(project_id or "").strip()
    if not pid:
        return {}
    shared_dir = _project_shared_dir(pid)
    sections = {
        "why": _read_project_context_file(shared_dir / "WHY.md", limit=1200),
        "map": _read_project_context_file(shared_dir / "REPO_MAP.md", limit=1200),
        "rules": _read_project_context_file(shared_dir / "RULES.md", limit=1200),
        "workflows": _read_project_context_file(shared_dir / "WORKFLOWS.md", limit=1200),
    }
    if not sections["why"]:
        sections["why"] = _read_project_context_file(shared_dir / "PROJECT_BRIEF.md", limit=1200)
    if not sections["rules"]:
        sections["rules"] = _read_project_context_file(shared_dir / "OPERATING_PROTOCOL.md", limit=1200)
    if not sections["workflows"]:
        sections["workflows"] = _read_project_context_file(shared_dir / "SUCCESS_CRITERIA.md", limit=1200)
    if not sections["map"]:
        sections["map"] = _read_project_context_file(shared_dir / "ARCHITECTURE_JOURNAL.md", limit=1000)
    return sections


def _project_anatomy_context(project_id: str, max_chars: int = 2200) -> str:
    snap = _project_context_snapshot(project_id)
    if not snap:
        return ""
    parts = []
    labels = [
        ("why", "Project Why"),
        ("map", "Project Map"),
        ("rules", "Project Rules"),
        ("workflows", "Project Workflows"),
    ]
    for key, label in labels:
        body = str(snap.get(key) or "").strip()
        if body:
            parts.append(f"{label}:\n{body}")
    if not parts:
        return ""
    return "\n\n".join(parts)[:max_chars]


