def _normalize_project_name(name: str) -> str:
    raw = str(name or "").strip()
    if not raw:
        return ""
    candidate = raw
    for pat in (
        r"^(?:let'?s|lets)\s+call\s+this\s+project\s+(.+)$",
        r"^(?:call\s+this\s+project|name\s+the\s+project)\s+(.+)$",
        r"^(?:project\s+name\s*[:\-]\s*)(.+)$",
    ):
        m = re.match(pat, raw, re.I)
        if m:
            candidate = str(m.group(1) or "").strip()
            break
    candidate = re.split(r"(?<=[.!?])\s+", candidate, 1)[0].strip()
    candidate = re.split(r"\s+(?:first|next|we need|we should|what do you need|the draft|it'?s already)\b", candidate, 1, flags=re.I)[0].strip()
    candidate = candidate.strip(" \t\r\n\"'`.,:;!?")
    if not candidate:
        candidate = raw.strip(" \t\r\n\"'`.,:;!?")
    if len(candidate) > 80:
        candidate = candidate[:80].rstrip(" \t\r\n\"'`.,:;!?")
    return candidate


def _migrate_project_workspace_root() -> bool:
    legacy_root = Path.home() / ".openclaw" / "workspace" / "projects"
    target_root = AGENT_WORKSPACE_DIR / "projects"
    if AGENT_WORKSPACE_DIR == legacy_root.parent or not legacy_root.exists():
        return False
    changed = False
    try:
        target_root.mkdir(parents=True, exist_ok=True)
        for item in legacy_root.iterdir():
            if not item.is_dir():
                continue
            target = target_root / item.name
            if target.exists():
                continue
            shutil.move(str(item), str(target))
            changed = True
    except Exception as e:
        log.debug("Project workspace migration failed: %s", e)
    return changed


def _normalize_project_registry_names(cfg: dict) -> bool:
    changed = False
    for proj in cfg.get("projects", []) or []:
        raw_name = str(proj.get("name") or "").strip()
        norm_name = _normalize_project_name(raw_name)
        if norm_name and norm_name != raw_name:
            proj["name"] = norm_name
            changed = True
        if norm_name == "First Mission" and float(proj.get("created_at") or 0) < 1735689600:
            proj["created_at"] = time.time()
            changed = True
        pid = str(proj.get("id") or "").strip()
        if pid and norm_name:
            try:
                sj = AGENT_WORKSPACE_DIR / "projects" / pid / "settings.json"
                if sj.exists():
                    sdata = json.loads(sj.read_text())
                    if sdata.get("name") != norm_name:
                        sdata["name"] = norm_name
                        sj.write_text(json.dumps(sdata, indent=2))
            except Exception as e:
                log.debug("Project settings normalization failed: %s", e)
    return changed


def _migrate_legacy_porter_app_project(cfg: dict) -> bool:
    """Rename the legacy starter project to First Mission and refresh its docs."""
    changed = False
    for proj in cfg.get("projects", []) or []:
        if str(proj.get("name") or "").strip() != "Porter App":
            continue
        proj["name"] = "First Mission"
        proj["description"] = (
            "Guided starter project for learning how Porter manages workers, "
            "projects, state, and artifacts."
        )
        proj["success_bar"] = (
            "Create one worker, review one artifact, and launch one real project."
        )
        proj["type"] = "manual"
        proj["assigned_personas"] = []
        proj["updated_at"] = time.time()
        try:
            _seed_launchpad_workspace(str(proj.get("id") or "").strip())
            _seed_launchpad_state(str(proj.get("id") or "").strip())
        except Exception as e:
            log.debug("First Mission workspace migration failed: %s", e)
        changed = True
    return changed


def _ensure_launchpad_project(cfg: dict) -> bool:
    """Seed the first-run First Mission project when no projects exist yet.
    Checks SQLite DB first — only creates a new project if truly empty."""
    # If config still has projects (pre-migration), skip
    if cfg.get("projects", []):
        return False
    # Check DB for existing projects (post-migration, projects live in SQLite)
    try:
        _econn = _db_conn()
        _existing_count = _econn.execute("SELECT count(*) FROM projects").fetchone()[0]
        if _existing_count > 0:
            return False  # Projects exist in DB, no need to seed
    except Exception:
        pass  # DB not ready yet (e.g., first call before _db_init); will retry
    pid = str(uuid.uuid4())
    project = {
        "id": pid,
        "name": "First Mission",
        "type": "manual",
        "owner": cfg.get("username", "admin"),
        "description": (
            "Guided starter project for learning how Porter manages workers, "
            "projects, state, and artifacts."
        ),
        "success_bar": (
            "Create one worker, review one artifact, and launch one real project."
        ),
        "created_at": time.time(),
        "assigned_personas": [],
    }
    # Write to DB if available, otherwise fall back to config for first-run bootstrap
    try:
        _seed_conn = _db_conn()
        project["owner_id"] = project["owner"]
        _project_dict_to_row_vals = _project_dict_to_row(project)
        _seed_conn.execute("""
            INSERT OR IGNORE INTO projects
                (id, name, slug, type, status, description, owner_id,
                 milestones, artifacts, links, metadata, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, _project_dict_to_row_vals)
        _seed_conn.commit()
        log.info("Seeded First Mission project in DB: %s", pid)
    except Exception as _e:
        # DB not ready (first boot before _db_init) — use config fallback
        log.debug("First Mission DB seed failed, using config: %s", _e)
        cfg["projects"] = [project]
        cfg["active_project_id"] = pid
    try:
        _seed_launchpad_workspace(pid)
        _seed_launchpad_state(pid)
    except Exception as e:
        log.debug("First Mission seed failed: %s", e)
    return True


def _create_user_first_mission(username: str) -> dict:
    """Create a personal First Mission project for a new user."""
    pid = str(uuid.uuid4())
    project = {
        "id": pid,
        "name": "First Mission",
        "type": "manual",
        "owner": username,
        "description": (
            "Guided starter project for learning how Porter manages workers, "
            "projects, state, and artifacts."
        ),
        "success_bar": (
            "Create one worker, review one artifact, and launch one real project."
        ),
        "created_at": time.time(),
        "assigned_personas": [],
    }
    _db_project_save(project)
    try:
        scaffold_project_dir(pid, "First Mission")
        _seed_launchpad_workspace(pid)
        _seed_launchpad_state(pid)
    except Exception as e:
        log.debug("First Mission seed for user %s failed: %s", username, e)
    log.info("Created personal First Mission for user: %s (project_id=%s)", username, pid)
    return project


def resolve_project_memory(project_id: "str | None", agent_id: "str | None",
                           filename: str) -> dict:
    """
    Resolve a memory/config file through the 3-layer project scope stack.
    Priority: agent override > project > global (workspace root).
    Returns {path, content, source_layer} where source_layer is
    'agent', 'project', 'global', or None if not found anywhere.
    """
    layers: list = []
    if agent_id:
        layers.append(("agent",   AGENT_WORKSPACE_DIR / "agents"   / str(agent_id)   / filename))
    if project_id:
        layers.append(("project", AGENT_WORKSPACE_DIR / "projects" / str(project_id) / filename))
    layers.append(    ("global",  AGENT_WORKSPACE_DIR / filename))
    for layer, path in layers:
        if path.exists():
            try:
                content = path.read_text(encoding="utf-8", errors="replace")
            except Exception as e:
                log.debug("Ignored: %s", e)
                content = ""
            return {"path": str(path), "content": content, "source_layer": layer}
    return {"path": None, "content": None, "source_layer": None}


def _project_file_chain(project_id: str) -> list:
    """Stat canonical project files and return chain metadata."""
    wp = AGENT_WORKSPACE_DIR / "projects" / str(project_id)
    canonical = [
        ("PROJECT.md",                         "Project config"),
        ("STATE.md",                           "Project state"),
        ("00_SHARED/WHY.md",                   "Project why"),
        ("00_SHARED/REPO_MAP.md",              "Project map"),
        ("00_SHARED/RULES.md",                 "Project rules"),
        ("00_SHARED/WORKFLOWS.md",             "Project workflows"),
        ("settings.json",                      "Settings"),
    ]
    chain = []
    for rel, label in canonical:
        fp = wp / rel
        exists = fp.exists()
        st = fp.stat() if exists else None
        chain.append({
            "key":          rel,
            "label":        label,
            "exists":       exists,
            "size":         st.st_size if st else 0,
            "size_human":   human_size(st.st_size) if st else "",
            "mtime":        st.st_mtime if st else 0,
            "modified_ago": _time_ago(st.st_mtime) if st else "",
        })
    return chain



def _analyze_file(filepath: "Path", mime_type: str = "") -> dict:
    """Analyze a file and extract metadata useful for Porter context.
    Returns: {summary, tags, word_count, lang}"""
    import mimetypes
    result = {"summary": "", "tags": [], "word_count": 0, "lang": ""}
    try:
        fp = Path(filepath) if not isinstance(filepath, Path) else filepath
        if not fp.exists():
            return result
        if not mime_type:
            mime_type = mimetypes.guess_type(str(fp))[0] or "application/octet-stream"
        name = fp.name.lower()
        ext = fp.suffix.lower()
        size = fp.stat().st_size

        # Detect language/type from extension
        lang_map = {
            ".py": "python", ".js": "javascript", ".ts": "typescript", ".jsx": "javascript",
            ".tsx": "typescript", ".go": "go", ".rs": "rust", ".java": "java", ".c": "c",
            ".cpp": "cpp", ".h": "c-header", ".rb": "ruby", ".php": "php", ".swift": "swift",
            ".kt": "kotlin", ".sh": "bash", ".sql": "sql", ".html": "html", ".css": "css",
            ".md": "markdown", ".txt": "text", ".json": "json", ".yaml": "yaml", ".yml": "yaml",
            ".xml": "xml", ".csv": "csv", ".toml": "toml", ".ini": "ini", ".conf": "config",
        }
        result["lang"] = lang_map.get(ext, "")

        # Auto-tag from extension and content
        tags = []
        if mime_type.startswith("image/"):
            tags.append("image")
        elif mime_type.startswith("video/"):
            tags.append("video")
        elif mime_type.startswith("audio/"):
            tags.append("audio")
        elif ext == ".pdf":
            tags.append("document")
            tags.append("pdf")
        elif ext in (".doc", ".docx", ".odt", ".rtf"):
            tags.append("document")
        elif ext in (".xls", ".xlsx", ".csv", ".tsv"):
            tags.append("data")
            tags.append("spreadsheet")
        elif ext in (".zip", ".tar", ".gz", ".bz2", ".7z"):
            tags.append("archive")
        elif result["lang"]:
            tags.append("code")
            tags.append(result["lang"])

        # For text-readable files, extract word count + summary
        text_exts = set(lang_map.keys()) | {".log", ".env", ".cfg", ".rst"}
        if ext in text_exts or mime_type.startswith("text/"):
            if size < 2 * 1024 * 1024:  # Only analyze files under 2MB
                try:
                    text = fp.read_text(encoding="utf-8", errors="replace")
                    words = text.split()
                    result["word_count"] = len(words)

                    # Generate summary (first meaningful lines, up to 200 chars)
                    lines = [l.strip() for l in text.split("\n") if l.strip() and not l.strip().startswith("#!")]
                    summary_lines = []
                    char_count = 0
                    for line in lines[:10]:
                        if char_count + len(line) > 200:
                            break
                        # Skip comment-only lines for code files
                        if result["lang"] and line.startswith(("//", "#", "/*", "*", "<!--")):
                            continue
                        summary_lines.append(line)
                        char_count += len(line)
                    result["summary"] = " ".join(summary_lines)[:200]

                    # Extract topic tags from content for markdown/text
                    if ext in (".md", ".txt", ".rst"):
                        # Find headings as topic tags
                        import re as _re_fa
                        headings = _re_fa.findall(r"^#{1,3}\s+(.+)", text, _re_fa.MULTILINE)
                        for h in headings[:5]:
                            tag = h.strip().lower().replace(" ", "-")[:30]
                            if tag and tag not in tags:
                                tags.append(tag)
                except Exception as _e:
                    mlog.emit("warn", "system", "exception.swallowed",
                              f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        result["tags"] = tags
    except Exception as e:
        log.debug("File analysis failed for %s: %s", filepath, e)
    return result

def _project_artifact_listing(project_id: str) -> dict:
    """Return project-scoped artifacts plus canonical project docs."""
    import mimetypes

    proj_dir = scaffold_project_dir(project_id, project_id)
    artifacts_dir = proj_dir / "artifacts"
    docs = _project_file_chain(project_id)

    def _artifact_kind(mime_type: str, filename: str) -> str:
        mime_type = str(mime_type or "").lower()
        suffix = Path(filename).suffix.lower()
        if mime_type.startswith("image/"):
            return "image"
        if mime_type in ("application/pdf",):
            return "pdf"
        if mime_type.startswith("video/"):
            return "video"
        if mime_type.startswith("audio/"):
            return "audio"
        if suffix in {".md", ".txt", ".rtf"}:
            return "doc"
        if suffix in {".doc", ".docx", ".odt"}:
            return "doc"
        if suffix in {".csv", ".tsv", ".xlsx", ".xls", ".json"}:
            return "data"
        if suffix in {".zip", ".tar", ".gz"}:
            return "archive"
        return "file"



    def _sync_project_artifact_record(relative_path: str, filename: str, kind: str, mime_type: str, size: int):
        try:
            conn = _db_conn()
            row = conn.execute(
                "SELECT id, source, created_by, created_at FROM project_artifacts WHERE project_id=? AND relative_path=?",
                (project_id, relative_path),
            ).fetchone()
            if row:
                conn.execute(
                    "UPDATE project_artifacts SET filename=?, kind=?, mime_type=?, size=?, updated_at=strftime('%s','now') WHERE id=?",
                    (filename, kind, mime_type, size, row["id"]),
                )
                meta = dict(row)
            else:
                # v0.31.84 — Analyze file for metadata
                _artifact_path = AGENT_WORKSPACE_DIR / "projects" / project_id / relative_path
                _fa = _analyze_file(_artifact_path, mime_type)
                conn.execute(
                    "INSERT INTO project_artifacts (project_id, relative_path, filename, kind, mime_type, size, summary, tags, word_count, lang) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    (project_id, relative_path, filename, kind, mime_type, size,
                     _fa.get("summary", ""), json.dumps(_fa.get("tags", [])),
                     _fa.get("word_count", 0), _fa.get("lang", "")),
                )
                new_id = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
                meta = {"id": new_id, "source": "workspace", "created_by": "", "created_at": time.time()}
            conn.commit()
            conn.close()
            return meta
        except Exception as e:
            log.debug("Artifact sync failed for %s/%s: %s", project_id, relative_path, e)
            return {"id": None, "source": "workspace", "created_by": "", "created_at": 0}

    artifacts = []
    for fp in sorted(artifacts_dir.rglob("*")):
        if not fp.is_file():
            continue
        rel = str(fp.relative_to(artifacts_dir))
        mime_type, _ = mimetypes.guess_type(str(fp))
        st = fp.stat()
        kind = _artifact_kind(mime_type or "", fp.name)
        meta = _sync_project_artifact_record(rel, fp.name, kind, mime_type or "application/octet-stream", st.st_size)
        artifacts.append({
            "id": meta.get("id"),
            "name": fp.name,
            "path": str(fp),
            "relative_path": rel,
            "mime_type": mime_type or "application/octet-stream",
            "kind": kind,
            "source": meta.get("source") or "workspace",
            "created_by": meta.get("created_by") or "",
            "created_at": meta.get("created_at") or 0,
            "size": st.st_size,
            "size_human": human_size(st.st_size),
            "mtime": st.st_mtime,
            "modified_ago": _time_ago(st.st_mtime),
        })
    return {
        "artifacts_dir": str(artifacts_dir),
        "artifacts": artifacts,
        "artifact_count": len(artifacts),
        "project_docs": docs,
        "project_docs_count": sum(1 for d in docs if d.get("exists")),
    }


def _load_integrations() -> dict:
    """Read OpenClaw skills, sessions, and auth profiles for integration visibility."""
    result = {"ok": True, "openclaw_available": False, "skills": [], "sessions": [],
              "auth_profiles": [], "cron_jobs": [], "hooks": []}

    oc_dir = OPENCLAW_STATE_DIR
    if not oc_dir.exists():
        return result

    result["openclaw_available"] = True

    # Read skills from session snapshot
    sessions_file = oc_dir / "agents" / "main" / "sessions" / "sessions.json"
    if sessions_file.exists():
        try:
            sessions_data = json.loads(sessions_file.read_text(encoding="utf-8"))
            skills_seen = set()
            for key, sess in sessions_data.items():
                snap = sess.get("skillsSnapshot", {})
                for sk in snap.get("skills", []):
                    name = sk.get("name", "")
                    if name and name not in skills_seen:
                        skills_seen.add(name)
                        result["skills"].append({
                            "name": name,
                            "required_env": sk.get("requiredEnv", []),
                        })
                result["sessions"].append({
                    "key": key,
                    "session_id": sess.get("sessionId", ""),
                    "model": sess.get("model", "unknown"),
                    "updated_at": sess.get("updatedAt", 0),
                    "chat_type": sess.get("chatType", ""),
                    "channel": sess.get("lastChannel", ""),
                })
        except Exception as e:
            log.debug("Ignored: %s", e)

    # v0.31.84 — Use CLI for resolved model/auth status (authoritative)
    import subprocess as _sp_int
    oc_bin = _resolve_cli("openclaw")
    if oc_bin:
        try:
            r = _sp_int.run([oc_bin, "models", "status", "--json"],
                capture_output=True, text=True, timeout=10, env=_agent_env())
            if r.returncode == 0 and r.stdout.strip():
                models_status = json.loads(r.stdout)
                result["resolved_models"] = models_status
                # Extract auth readiness from resolved state
                result["model_auth_ready"] = models_status.get("authReady", False)
                result["effective_model"] = models_status.get("effectiveModel", "")
                result["fallbacks"] = models_status.get("fallbacks", [])
                result["image_fallbacks"] = models_status.get("imageFallbacks", [])
                result["allowed_models"] = models_status.get("allowedModels", [])
                log.debug("Loaded resolved model status from CLI")
        except Exception as e:
            log.debug("openclaw models status CLI failed, using filesystem: %s", e)

    # Read auth profiles (filesystem fallback)
    auth_file = oc_dir / "agents" / "main" / "agent" / "auth-profiles.json"
    if auth_file.exists():
        try:
            auth_data = json.loads(auth_file.read_text(encoding="utf-8"))
            for prof_id, prof in auth_data.get("profiles", {}).items():
                expires = prof.get("expires", 0)
                is_expired = expires > 0 and expires < time.time() * 1000
                result["auth_profiles"].append({
                    "id": prof_id,
                    "provider": prof.get("provider", ""),
                    "type": prof.get("type", ""),
                    "expired": is_expired,
                    "expires_at": expires,
                })
        except Exception as e:
            log.debug("Ignored: %s", e)

    # Read models config
    models_file = oc_dir / "agents" / "main" / "agent" / "models.json"
    if models_file.exists():
        try:
            models_data = json.loads(models_file.read_text(encoding="utf-8"))
            result["model_providers"] = []
            for prov_id, prov in models_data.get("providers", {}).items():
                models = [m.get("id", "") for m in prov.get("models", [])]
                result["model_providers"].append({
                    "id": prov_id,
                    "base_url": prov.get("baseUrl", ""),
                    "api": prov.get("api", ""),
                    "models": models,
                })
        except Exception as e:
            log.debug("Ignored: %s", e)

    # Read cron jobs
    cron_file = oc_dir / "cron" / "jobs.json"
    if cron_file.exists():
        try:
            cron_data = json.loads(cron_file.read_text(encoding="utf-8"))
            result["cron_jobs"] = cron_data.get("jobs", [])
        except Exception as e:
            log.debug("Ignored: %s", e)

    # Read hooks config
    oc_config = oc_dir / "openclaw.json"
    if oc_config.exists():
        try:
            oc_cfg = json.loads(oc_config.read_text(encoding="utf-8"))
            hooks = oc_cfg.get("hooks", {})
            if hooks.get("enabled"):
                for preset in hooks.get("presets", []):
                    hook_cfg = hooks.get(preset, {})
                    result["hooks"].append({
                        "name": preset,
                        "account": hook_cfg.get("account", ""),
                        "label": hook_cfg.get("label", ""),
                    })
            gw = oc_cfg.get("gateway", {})
            result["gateway"] = {
                "port": gw.get("port", 18789),
                "auth_token_set": bool(gw.get("token")),
            }
        except Exception as e:
            log.debug("Ignored: %s", e)

    return result


def _validate_no_hardcoding():
    """Sprint 9: Verify no hardcoded user paths leaked into runtime config."""
    issues = []
    # Check that critical paths are user-agnostic
    home = str(Path.home())
    if str(_DATA_DIR).startswith("/home/") and "/." not in str(_DATA_DIR):
        # _DATA_DIR is under a specific user home — that's fine if via env var or default
        pass
    # Verify is_writable uses OS-level UID, not a hardcoded path
    # (Already fixed in this sprint)
    # Log validation result
    if issues:
        for i in issues:
            print(f"  WARNING: hardcoding detected — {i}")
    return len(issues) == 0


def _ping_agent(agent: dict) -> dict:
    """Real HTTP roundtrip ping to an agent endpoint. Returns latency, version, status."""
    import urllib.request, urllib.error, time as _time, secrets as _secrets

    agent_type = (agent.get("type") or agent.get("name") or "").lower()
    result = {"ok": False, "latency_ms": None, "version": None, "endpoint": None, "message": ""}

    def _ping_cli(binary: str, label: str) -> dict:
        """Check CLI reachability via --version using resolved install path."""
        cli = _resolve_cli(binary)
        if not cli:
            return {
                "ok": False,
                "latency_ms": None,
                "version": None,
                "endpoint": f"{label} CLI binary",
                "message": f"{binary} binary not found in PATH or common install dirs",
            }
        try:
            t0 = _time.monotonic()
            r = subprocess.run([cli, "--version"], capture_output=True, text=True, timeout=5)
            t1 = _time.monotonic()
            ver = (r.stdout or r.stderr or "").strip().split("\n")[0][:120]
            return {
                "ok": r.returncode == 0,
                "latency_ms": round((t1 - t0) * 1000),
                "version": ver or binary,
                "endpoint": f"{label} CLI binary ({cli})",
                "message": "CLI binary responded" if r.returncode == 0 else "CLI binary returned non-zero",
            }
        except Exception as e:
            return {
                "ok": False,
                "latency_ms": None,
                "version": None,
                "endpoint": f"{label} CLI binary ({cli})",
                "message": f"Error: {e}",
            }

    # Determine endpoint to ping based on agent type
    endpoints = []
    oc_cfg = {}
    try:
        oc_cfg = json.loads(OPENCLAW_STATE_DIR.joinpath("openclaw.json").read_text())
    except Exception as e:
        log.debug("Ignored: %s", e)

    if "codex" in agent_type:
        # Codex should be tested through its own CLI first.
        cli_ping = _ping_cli("codex", "Codex")
        if cli_ping["ok"]:
            return cli_ping
        # Fallback: if Codex is routed via OpenClaw gateway on this host, try gateway reachability.
        gw = oc_cfg.get("gateway", {})
        port = gw.get("port", 18789)
        token = (gw.get("auth", {}).get("token") or gw.get("token") or "").strip()
        endpoints.append(("OpenClaw Gateway", f"http://127.0.0.1:{port}/", token))
        result["message"] = cli_ping["message"]
    elif "openclaw" in agent_type:
        gw = oc_cfg.get("gateway", {})
        port = gw.get("port", 18789)
        token = (gw.get("auth", {}).get("token") or gw.get("token") or "").strip()
        endpoints.append(("OpenClaw Gateway", f"http://127.0.0.1:{port}/", token))
    elif "gemini" in agent_type:
        # Gemini CLI doesn't expose an HTTP endpoint — test binary availability.
        return _ping_cli("gemini", "Gemini")
    elif "claude" in agent_type:
        # Claude Code doesn't expose an HTTP endpoint — test binary availability.
        return _ping_cli("claude", "Claude")
    elif "ollama" in agent_type:
        endpoints.append(("Ollama", "http://127.0.0.1:11434/api/tags", ""))
    else:
        # Generic: try the agent's configured URL if any, or OpenClaw gateway
        gw = oc_cfg.get("gateway", {})
        port = gw.get("port", 18789)
        token = (gw.get("auth", {}).get("token") or gw.get("token") or "").strip()
        endpoints.append(("OpenClaw Gateway", f"http://127.0.0.1:{port}/", token))

    # HTTP roundtrip test with challenge token
    challenge = _secrets.token_urlsafe(16)
    for label, url, token in endpoints:
        try:
            req = urllib.request.Request(url, method="GET")
            req.add_header("User-Agent", "Porter-Ping/1.0")
            req.add_header("X-Porter-Challenge", challenge)
            if token:
                req.add_header("Authorization", f"Bearer {token}")

            t0 = _time.monotonic()
            with urllib.request.urlopen(req, timeout=10) as resp:
                body = resp.read(8192).decode("utf-8", errors="replace")
                t1 = _time.monotonic()

            latency = round((t1 - t0) * 1000)
            result["ok"] = True
            result["latency_ms"] = latency
            result["endpoint"] = label + " (" + url + ")"

            # Try to extract version from response
            try:
                data = json.loads(body)
                result["version"] = data.get("version") or data.get("name") or None
            except Exception as e:
                log.warning("Error: %s", e)
                # Non-JSON response is fine — the ping itself succeeded
                pass

            result["message"] = f"Roundtrip OK: {latency}ms"
            return result
        except urllib.error.HTTPError as e:
            t1 = _time.monotonic()
            latency = round((t1 - t0) * 1000)
            # Even a 401/403 means the endpoint is alive
            if e.code in (401, 403):
                result["ok"] = True
                result["latency_ms"] = latency
                result["endpoint"] = label + " (" + url + ")"
                result["message"] = f"Endpoint alive (HTTP {e.code}, auth required): {latency}ms"
                return result
            result["message"] = f"{label}: HTTP {e.code}"
        except urllib.error.URLError as e:
            result["message"] = f"{label}: Connection refused or unreachable"
        except Exception as e:
            result["message"] = f"{label}: {e}"

    return result

def _load_openclaw_skills() -> list:
    """Load OpenClaw skills — prefer CLI (authoritative) with filesystem fallback.
    Install status comes from OpenClaw's resolvedSkills in sessions.json."""
    import re as _re
    import subprocess as _sp
    # v0.31.84 — Try CLI first for authoritative skill list
    oc_bin = _resolve_cli("openclaw")
    if oc_bin:
        try:
            r = _sp.run([oc_bin, "skills", "list", "--json"],
                capture_output=True, text=True, timeout=15, env=_agent_env())
            if r.returncode == 0 and r.stdout.strip():
                data = json.loads(r.stdout)
                cli_skills = data if isinstance(data, list) else data.get("skills", [])
                if cli_skills:
                    # Normalize to expected format
                    normalized = []
                    for sk in cli_skills:
                        normalized.append({
                            "name": sk.get("name", sk.get("id", "")),
                            "id": sk.get("id", sk.get("name", "")),
                            "description": sk.get("description", ""),
                            "category": sk.get("category", ""),
                            "installed": sk.get("installed", sk.get("eligible", False)),
                            "manual": sk.get("manual", False),
                            "tags": sk.get("tags", []),
                        })
                    log.debug("Loaded %d skills from openclaw CLI", len(normalized))
                    return normalized
        except Exception as e:
            log.debug("openclaw skills CLI failed, falling back to filesystem: %s", e)
    # Filesystem fallback
    skills = []
    skill_dirs = []
    oc_dir = OPENCLAW_STATE_DIR
    if oc_dir.exists():
        for sandbox in (oc_dir / "sandboxes").glob("*/skills"):
            skill_dirs.append(sandbox)
    if not skill_dirs:
        return skills

    # Read active skills from OpenClaw session snapshots
    active_skills = set()
    sessions_file = oc_dir / "agents" / "main" / "sessions" / "sessions.json"
    if sessions_file.exists():
        try:
            sessions = json.loads(sessions_file.read_text(encoding="utf-8"))
            for _sk, sess in sessions.items():
                snap = sess.get("skillsSnapshot", {})
                for rs in snap.get("resolvedSkills", []):
                    def _norm_skill(s): return str(s or "").strip().lower().replace("_", "-")
                    if isinstance(rs, str):
                        active_skills.add(_norm_skill(rs))
                    elif isinstance(rs, dict):
                        active_skills.add(_norm_skill(rs.get("name", "")))
                        active_skills.add(_norm_skill(rs.get("id", "")))
        except Exception as e:
            log.debug("Ignored: %s", e)

    for skills_root in skill_dirs:
        for skill_dir in sorted(skills_root.iterdir()):
            if not skill_dir.is_dir():
                continue
            skill_md = skill_dir / "SKILL.md"
            if not skill_md.exists():
                continue
            try:
                raw = skill_md.read_text(encoding="utf-8")
                name = skill_dir.name
                description = ""
                emoji = ""
                homepage = ""
                requires_bins = []

                if raw.startswith("---"):
                    parts = raw.split("---", 2)
                    if len(parts) >= 3:
                        fm = parts[1]
                        for line in fm.strip().split("\n"):
                            line = line.strip()
                            if line.startswith("name:"):
                                name = line[5:].strip().strip('"').strip("'")
                            elif line.startswith("description:"):
                                description = line[12:].strip().strip('"').strip("'")
                            elif line.startswith("homepage:"):
                                homepage = line[9:].strip()
                            elif '"emoji":' in line:
                                m = _re.search(r'"emoji":\s*"([^"]*)"', line)
                                if m:
                                    emoji = m.group(1)
                            elif '"bins"' in line or '"anyBins"' in line:
                                m = _re.search(r'"(?:bins|anyBins)":\s*\[([^\]]*)\]', line)
                                if m:
                                    requires_bins = [b.strip().strip('"').strip("'") for b in m.group(1).split(',') if b.strip()]

                # Installed = appears in OpenClaw's active/resolved skills
                installed = _norm_skill(skill_dir.name) in active_skills or _norm_skill(name) in active_skills

                skills.append({
                    "id": skill_dir.name,
                    "name": name,
                    "description": description[:200] if description else "",
                    "emoji": emoji,
                    "homepage": homepage,
                    "has_docs": len(raw) > 100,
                    "installed": installed,
                    "requires": requires_bins,
                    "manual": False,
                    "path": str(skill_dir),
                })
            except Exception as e:
                log.warning("Error: %s", e)
                skills.append({"id": skill_dir.name, "name": skill_dir.name, "description": "",
                             "emoji": "", "homepage": "", "has_docs": False,
                             "installed": skill_dir.name in active_skills,
                             "requires": [], "manual": False, "path": str(skill_dir)})

    # Also load manual skills from runtime/skills/
    manual_dir = RUNTIME_DIR / "skills"
    if manual_dir.exists():
        for skill_dir in sorted(manual_dir.iterdir()):
            if not skill_dir.is_dir():
                continue
            skill_md = skill_dir / "SKILL.md"
            if not skill_md.exists():
                continue
            try:
                raw = skill_md.read_text(encoding="utf-8")
                name = skill_dir.name
                description = ""
                emoji = ""
                if raw.startswith("---"):
                    parts = raw.split("---", 2)
                    if len(parts) >= 3:
                        for line in parts[1].strip().split("\n"):
                            line = line.strip()
                            if line.startswith("name:"): name = line[5:].strip().strip('"').strip("'")
                            elif line.startswith("description:"): description = line[12:].strip().strip('"').strip("'")
                            elif '"emoji":' in line:
                                m = _re.search(r'"emoji":\s*"([^"]*)"', line)
                                if m: emoji = m.group(1)
                skills.append({
                    "id": skill_dir.name,
                    "name": name,
                    "description": description[:200] if description else "",
                    "emoji": emoji or "\u2699",
                    "homepage": "",
                    "has_docs": len(raw) > 100,
                    "installed": True,
                    "requires": [],
                    "manual": True,
                    "path": str(skill_dir),
                })
            except Exception as e:
                log.debug("Ignored: %s", e)
    return skills


def _load_openclaw_cron() -> dict:
    """Read OpenClaw cron jobs and recent run history."""
    result = {"jobs": [], "runs": []}
    oc_dir = OPENCLAW_STATE_DIR
    cron_file = oc_dir / "cron" / "jobs.json"
    if cron_file.exists():
        try:
            data = json.loads(cron_file.read_text(encoding="utf-8"))
            result["jobs"] = data.get("jobs", [])
        except Exception as e:
            log.debug("Ignored: %s", e)
    # Read recent runs
    runs_dir = oc_dir / "cron" / "runs"
    if runs_dir.exists():
        for rf in sorted(runs_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)[:20]:
            try:
                result["runs"].append({
                    "id": rf.stem,
                    "modified": rf.stat().st_mtime,
                    "size": rf.stat().st_size,
                })
            except Exception as e:
                log.debug("Ignored: %s", e)
    return result


def _detect_local_models() -> list:
    """Scan for locally available AI models and CLI agents.

    Checks:
    - CLI binaries: codex, claude, gemini (via shutil.which + --version)
    - Ollama models: via HTTP to /api/tags
    - OpenClaw gateway: via HTTP to health endpoint

    Returns list of model dicts with: id, name, type, version, source, size_gb, context_window
    """
    import shutil
    import subprocess
    models = []

    # Expand PATH for systemd services that may have limited paths
    home = str(Path.home())
    extra_paths = [
        str(Path(home, ".npm-global", "bin")),
        str(Path(home, ".local", "bin")),
        str(Path(home, ".cargo", "bin")),
        "/usr/local/bin",
        "/snap/bin",
    ]
    search_path = os.environ.get("PATH", "") + os.pathsep + os.pathsep.join(extra_paths)

    # CLI agents
    cli_agents = [
        {"bin": "codex", "name": "Codex CLI", "type": "cli", "provider": "openai"},
        {"bin": "claude", "name": "Claude CLI", "type": "cli", "provider": "anthropic"},
        {"bin": "gemini", "name": "Gemini CLI", "type": "cli", "provider": "google"},
    ]
    for agent in cli_agents:
        path = shutil.which(agent["bin"], path=search_path)
        if path:
            version = ""
            try:
                result = subprocess.run(
                    [path, "--version"],
                    capture_output=True, text=True, timeout=5
                )
                version = (result.stdout or result.stderr or "").strip().split("\n")[0][:80]
            except Exception as e:
                log.debug("Ignored: %s", e)
            models.append({
                "id": f"local-cli-{agent['bin']}",
                "name": agent["name"],
                "type": "cli_agent",
                "provider": agent["provider"],
                "version": version,
                "path": path,
                "source": "local_cli",
                "size_gb": None,
                "context_window": None,
            })

    # Ollama models
    try:
        import urllib.request
        req = urllib.request.Request("http://127.0.0.1:11434/api/tags", method="GET")
        req.add_header("Accept", "application/json")
        with urllib.request.urlopen(req, timeout=3) as resp:
            data = json.loads(resp.read())
            for m in data.get("models", []):
                name = m.get("name", "unknown")
                size_bytes = m.get("size", 0)
                details = m.get("details", {})
                models.append({
                    "id": f"local-ollama-{name}",
                    "name": name,
                    "type": "ollama",
                    "provider": "ollama",
                    "version": details.get("parameter_size", ""),
                    "path": None,
                    "source": "ollama",
                    "size_gb": round(size_bytes / 1e9, 1) if size_bytes else None,
                    "context_window": None,
                    "family": details.get("family", ""),
                    "quantization": details.get("quantization_level", ""),
                })
    except Exception as e:
        log.debug("Ignored: %s", e)  # Ollama not running or not reachable

    return models


def _load_porter_chat_sessions() -> list:
    """Load Porter's own chat sessions from the chats table."""
    try:
        conn = _db_conn()
        rows = conn.execute(
            "SELECT c.id, c.title, c.model_id, c.created_at, c.updated_at, "
            "(SELECT COUNT(*) FROM chat_messages WHERE chat_id=c.id) as msg_count "
            "FROM chats c ORDER BY c.updated_at DESC LIMIT 200"
        ).fetchall()
        conn.close()
        sessions = []
        for r in rows:
            backend = r[2] or "unknown"
            if "qwen" in backend.lower() or "ollama" in backend.lower():
                source_label = "ollama"
            elif "codex" in backend.lower():
                source_label = "codex"
            else:
                source_label = "porter"
            sessions.append({
                "id": r[0],
                "title": r[1] or "Untitled Chat",
                "model": r[2] or "unknown",
                "source": source_label,
                "first_ts": _epoch_to_iso(r[3]) if r[3] else "",
                "last_ts": _epoch_to_iso(r[4]) if r[4] else "",
                "messages": r[5] or 0,
                "turns": r[5] or 0,
            })
        return sessions
    except Exception:
        return []

def _epoch_to_iso(ts):
    """Convert epoch timestamp to ISO string."""
    try:
        import datetime
        return datetime.datetime.fromtimestamp(ts).isoformat()
    except Exception:
        return ""

def _load_session_summaries() -> list:
    """Load OpenClaw session summaries — prefer CLI (all-agent) with filesystem fallback."""
    import subprocess as _sp_sess
    # v0.31.84 — Use CLI for all-agent session aggregation
    oc_bin = _resolve_cli("openclaw")
    if oc_bin:
        try:
            r = _sp_sess.run([oc_bin, "sessions", "--json", "--all-agents"],
                capture_output=True, text=True, timeout=15, env=_agent_env())
            if r.returncode == 0 and r.stdout.strip():
                data = json.loads(r.stdout)
                sessions = data if isinstance(data, list) else data.get("sessions", [])
                if sessions:
                    # Normalize to expected format
                    normalized = []
                    for s in sessions:
                        normalized.append({
                            "session_id": s.get("sessionId", s.get("id", "")),
                            "agent_id": s.get("agentId", "main"),
                            "model": s.get("model", ""),
                            "msg_count": s.get("messageCount", s.get("msgCount", 0)),
                            "total_input": s.get("inputTokens", 0),
                            "total_output": s.get("outputTokens", 0),
                            "first_ts": s.get("firstTimestamp", s.get("createdAt", "")),
                            "last_ts": s.get("lastTimestamp", s.get("updatedAt", "")),
                            "channel": s.get("channel", ""),
                            "chat_type": s.get("chatType", ""),
                        })
                    log.debug("Loaded %d sessions from openclaw CLI (all-agents)", len(normalized))
                    return normalized
        except Exception as e:
            log.debug("openclaw sessions CLI failed, falling back to filesystem: %s", e)
    # Filesystem fallback (single-agent only)
    oc_dir = OPENCLAW_STATE_DIR
    sessions_dir = oc_dir / "agents" / "main" / "sessions"
    if not sessions_dir.exists():
        return []

    # Read session registry for metadata
    registry = {}
    reg_file = sessions_dir / "sessions.json"
    if reg_file.exists():
        try:
            registry = json.loads(reg_file.read_text(encoding="utf-8"))
        except Exception as e:
            log.debug("Ignored: %s", e)

    summaries = []
    for jsonl_file in sorted(sessions_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True):
        try:
            lines = jsonl_file.read_text(encoding="utf-8").strip().split("\n")
            if not lines:
                continue

            session_id = jsonl_file.stem
            first = json.loads(lines[0])
            msg_count = 0
            user_msgs = 0
            assistant_msgs = 0
            tool_calls = 0
            total_input = 0
            total_output = 0
            model = ""
            provider = ""
            first_ts = first.get("timestamp", "")
            last_ts = first_ts
            tools_used = set()

            for raw_line in lines:
                try:
                    entry = json.loads(raw_line)
                except Exception as e:
                    log.debug("Parse skip: %s", e)
                    continue
                etype = entry.get("type", "")
                ts = entry.get("timestamp", "")
                if ts:
                    last_ts = ts

                if etype == "message":
                    msg = entry.get("message", {})
                    role = msg.get("role", "")
                    if role == "user":
                        user_msgs += 1
                    elif role == "assistant":
                        assistant_msgs += 1
                    msg_count += 1
                    usage = entry.get("usage", {})
                    total_input += usage.get("input", 0)
                    total_output += usage.get("output", 0)
                    if entry.get("model"):
                        model = entry["model"]
                    if entry.get("provider"):
                        provider = entry["provider"]
                elif etype == "toolCall":
                    tool_calls += 1
                    tools_used.add(entry.get("tool", "unknown"))
                elif etype == "model_change":
                    if entry.get("modelId"):
                        model = entry["modelId"]
                    if entry.get("provider"):
                        provider = entry["provider"]

            # Find registry entry for this session
            reg_entry = None
            for _key, sess in registry.items():
                if sess.get("sessionId") == session_id:
                    reg_entry = sess
                    break

            session_name = ""
            if reg_entry:
                for _key, sess in registry.items():
                    if sess.get("sessionId") == session_id:
                        session_name = _key.replace("agent:main:", "")
                        break

            # Check for custom renamed name
            _custom_oc = _get_session_custom_names()
            _custom_name_oc = _custom_oc.get(session_id, "")
            summaries.append({
                "id": session_id,
                "name": _custom_name_oc or session_name or session_id[:12],
                "source": "openclaw",
                "file": jsonl_file.name,
                "first_ts": first_ts,
                "last_ts": last_ts,
                "messages": msg_count,
                "user_msgs": user_msgs,
                "assistant_msgs": assistant_msgs,
                "tool_calls": tool_calls,
                "tools_used": sorted(tools_used),
                "total_input_tokens": total_input,
                "total_output_tokens": total_output,
                "model": model,
                "provider": provider,
                "size_kb": round(jsonl_file.stat().st_size / 1024, 1),
                "in_registry": reg_entry is not None,
                "flushed": False,  # TODO: track flushed state
            })
        except Exception as e:
            log.debug("Parse skip: %s", e)
            continue

    return summaries


def _load_claude_session_summaries() -> list:
    """Read Claude Code session .jsonl files and extract metadata summaries."""
    claude_dir = Path.home() / ".claude" / "projects" / "-home-lobster"
    if not claude_dir.exists():
        return []

    summaries = []
    # Only process the 15 most recent files by mtime to keep it fast
    jsonl_files = sorted(claude_dir.glob("*.jsonl"), key=lambda f: f.stat().st_mtime, reverse=True)[:50]
    for jsonl_file in jsonl_files:
        try:
            session_id = jsonl_file.stem
            user_msgs = 0
            assistant_msgs = 0
            first_ts = ""
            last_ts = ""
            first_user_text = ""

            with open(jsonl_file, "r", encoding="utf-8") as f:
                for line in f:
                    try:
                        entry = json.loads(line)
                    except Exception as e:
                        log.debug("Parse skip: %s", e)
                        continue
                    etype = entry.get("type", "")
                    ts = entry.get("timestamp", "")
                    if ts and isinstance(ts, str):
                        if not first_ts:
                            first_ts = ts
                        last_ts = ts
                    if etype == "user":
                        user_msgs += 1
                        if not first_user_text:
                            msg = entry.get("message", {})
                            text_candidate = ""
                            if isinstance(msg, dict):
                                content = msg.get("content", "")
                                if isinstance(content, list):
                                    text_candidate = " ".join(b.get("text", "") for b in content if isinstance(b, dict) and b.get("type") == "text")
                                elif isinstance(content, str):
                                    text_candidate = content
                            elif isinstance(msg, str):
                                text_candidate = msg
                            text_candidate = text_candidate.strip()[:80].replace("\n", " ")
                            # Skip tool interrupts and empty messages
                            if text_candidate and not text_candidate.startswith("[Request interrupted") and not text_candidate.startswith("[Tool"):
                                first_user_text = text_candidate
                    elif etype == "assistant":
                        assistant_msgs += 1

            session_name = first_user_text or f"Session {session_id[:8]}"
            _custom_cl = _get_session_custom_names()
            _custom_name_cl = _custom_cl.get(session_id, "")
            summaries.append({
                "id": session_id,
                "name": _custom_name_cl or session_name,
                "source": "claude",
                "file": jsonl_file.name,
                "first_ts": first_ts,
                "last_ts": last_ts,
                "messages": user_msgs + assistant_msgs,
                "user_msgs": user_msgs,
                "assistant_msgs": assistant_msgs,
                "tool_calls": 0,
                "tools_used": [],
                "total_input_tokens": 0,
                "total_output_tokens": 0,
                "model": "claude",
                "provider": "anthropic",
                "size_kb": round(jsonl_file.stat().st_size / 1024, 1),
                "in_registry": False,
                "flushed": False,
            })
        except Exception as e:
            log.debug("Parse skip: %s", e)
            continue

    return summaries


def _load_gemini_session_summaries() -> list:
    """Load Gemini CLI session summaries from ~/.gemini/tmp/*/chats/*.json"""
    import glob as _glob
    home = Path.home()
    sessions = []
    chat_dirs = home / ".gemini" / "tmp"
    if not chat_dirs.exists():
        return sessions
    for json_file in sorted(chat_dirs.rglob("chats/*.json"), key=lambda p: p.stat().st_mtime, reverse=True)[:50]:
        try:
            with open(json_file, "r", encoding="utf-8") as f:
                data = json.load(f)
            sid = data.get("sessionId", json_file.stem)
            msgs = data.get("messages", [])
            start = data.get("startTime", "")
            end = data.get("lastUpdated", "")
            name = ""
            for m in msgs:
                content = m.get("content", [])
                if isinstance(content, list):
                    for block in content:
                        if isinstance(block, dict) and block.get("text"):
                            name = block["text"][:60].replace("\n", " ").strip()
                            break
                if name:
                    break
            # Check for custom renamed name
            _custom_gm = _get_session_custom_names()
            _custom_name_gm = _custom_gm.get(sid, "")
            sessions.append({
                "id": sid,
                "name": _custom_name_gm or name or sid[:12],
                "source": "gemini",
                "messages": len(msgs),
                "first_ts": start,
                "last_ts": end,
                "size_kb": round(json_file.stat().st_size / 1024, 1),
                "model": "gemini-cli",
                "flushed": False,
            })
        except Exception as e:
            log.debug("Gemini session parse error: %s", e)
    return sessions


def _get_session_custom_names() -> dict:
    """Return dict of session_id → custom name from session_names table."""
    try:
        conn = _db_conn()
        rows = conn.execute("SELECT session_id, name FROM session_names").fetchall()
        conn.close()
        return {r["session_id"]: r["name"] for r in rows}
    except Exception:
        return {}


def _session_summary(session_id: str, source: str) -> dict:
    """Return last 10 turns of a session for the summary modal."""
    turns = []
    try:
        if source == "claude":
            fpath = Path.home() / ".claude" / "projects" / "-home-lobster" / f"{session_id}.jsonl"
            if not fpath.exists():
                return {"ok": False, "error": "Session file not found"}
            with open(fpath, "r", encoding="utf-8") as f:
                for line in f:
                    try:
                        entry = json.loads(line)
                    except Exception:
                        continue
                    etype = entry.get("type", "")
                    if etype == "user":
                        msg = entry.get("message", {})
                        if isinstance(msg, dict):
                            content = msg.get("content", "")
                            if isinstance(content, list):
                                text = " ".join(b.get("text", "") for b in content if isinstance(b, dict) and b.get("type") == "text")
                            else:
                                text = str(content)
                        else:
                            text = str(msg)
                        if text.strip():
                            turns.append({"role": "user", "text": text.strip()[:500]})
                    elif etype == "assistant":
                        msg = entry.get("message", {})
                        if isinstance(msg, dict):
                            content = msg.get("content", "")
                            if isinstance(content, list):
                                text = " ".join(b.get("text", "") for b in content if isinstance(b, dict) and b.get("type") == "text")
                                # Fallback: thinking or tool_use blocks (Claude often has no text)
                                if not text.strip():
                                    for blk in content:
                                        if isinstance(blk, dict):
                                            if blk.get("type") == "thinking":
                                                text = "[thinking] " + str(blk.get("thinking", ""))[:200]
                                                break
                                            elif blk.get("type") == "tool_use":
                                                text = "[tool: " + str(blk.get("name", "unknown")) + "]"
                                                break
                            else:
                                text = str(content)
                        else:
                            text = str(msg)
                        if text.strip():
                            turns.append({"role": "assistant", "text": text.strip()[:500]})

        elif source == "openclaw":
            fpath = OPENCLAW_STATE_DIR / "agents" / "main" / "sessions" / f"{session_id}.jsonl"
            if not fpath.exists():
                return {"ok": False, "error": "Session file not found"}
            with open(fpath, "r", encoding="utf-8") as f:
                for line in f:
                    try:
                        entry = json.loads(line)
                    except Exception:
                        continue
                    role = entry.get("role", "")
                    text = entry.get("content", "")
                    if isinstance(text, list):
                        text = " ".join(b.get("text", "") for b in text if isinstance(b, dict))
                    if role in ("user", "assistant") and str(text).strip():
                        turns.append({"role": role, "text": str(text).strip()[:500]})

        elif source == "gemini":
            chat_dirs = Path.home() / ".gemini" / "tmp"
            if not chat_dirs.exists():
                return {"ok": False, "error": "Gemini sessions dir not found"}
            found = False
            for json_file in chat_dirs.rglob("chats/*.json"):
                try:
                    data = json.loads(json_file.read_text(encoding="utf-8"))
                    sid = data.get("sessionId", json_file.stem)
                    if sid != session_id:
                        continue
                    found = True
                    for m in data.get("messages", []):
                        role = m.get("role", "user")
                        content = m.get("content", [])
                        text = ""
                        if isinstance(content, list):
                            for block in content:
                                if isinstance(block, dict) and block.get("text"):
                                    text += block["text"] + " "
                        elif isinstance(content, str):
                            text = content
                        if text.strip():
                            turns.append({"role": role, "text": text.strip()[:500]})
                    break
                except Exception:
                    continue
            if not found:
                return {"ok": False, "error": "Gemini session not found"}
        else:
            return {"ok": False, "error": f"Unknown source: {source}"}

    except Exception as e:
        return {"ok": False, "error": str(e)}

    total = len(turns)
    last_10 = turns[-10:] if len(turns) > 10 else turns
    return {"ok": True, "session_id": session_id, "source": source, "turns": last_10, "total_turns": total}


def _log_flush_history(agent: str, session_id: str, destination: str, bytes_written: int):
    """Log a flush operation to the database."""
    try:
        from datetime import datetime, timezone
        conn = _db_conn()
        conn.execute(
            "INSERT INTO flush_history (timestamp, agent, session_id, destination, bytes_written) VALUES (?, ?, ?, ?, ?)",
            (datetime.now(timezone.utc).isoformat(), agent, session_id, destination, bytes_written)
        )
        conn.commit()
        conn.close()
    except Exception as e:
        log.warning("flush_history log failed: %s", e)


def _get_flush_history(limit: int = 10) -> list:
    """Get recent flush history entries."""
    try:
        conn = _db_conn()
        rows = conn.execute(
            "SELECT timestamp, agent, session_id, destination, bytes_written, status FROM flush_history ORDER BY id DESC LIMIT ?",
            (limit,)
        ).fetchall()
        conn.close()
        return [dict(r) for r in rows]
    except Exception as e:
        log.debug("flush_history read failed: %s", e)
        return []


def _get_memory_overview() -> dict:
    """Return complete memory topology across all detected models."""
    home = Path.home()

    def _finfo(p):
        """File info dict for a Path."""
        if not p.exists():
            return None
        st = p.stat()
        return {"name": p.name, "path": str(p), "size": st.st_size, "modified": st.st_mtime}

    def _dir_files(directory, names):
        """Return file info list for named files in a directory."""
        result = []
        for n in names:
            f = directory / n
            info = _finfo(f)
            if info:
                result.append(info)
        return result

    models = []

    # ── Claude Code ──
    claude_mem_dir = home / ".claude" / "projects" / "-home-lobster" / "memory"
    claude_sess_dir = home / ".claude" / "projects" / "-home-lobster"
    claude_instr = _finfo(home / "CLAUDE.md")
    claude_files = _dir_files(claude_mem_dir, ["MEMORY.md"]) if claude_mem_dir.exists() else []
    claude_sessions = list(claude_sess_dir.glob("*.jsonl")) if claude_sess_dir.exists() else []
    models.append({
        "id": "claude", "name": "Claude Code", "color": "#d97706",
        "detected": True, "stateless": False,
        "instruction_file": claude_instr,
        "memory_files": claude_files,
        "daily_logs": 0,
        "session_count": len(claude_sessions),
        "session_size_mb": round(sum(f.stat().st_size for f in claude_sessions) / (1024 * 1024), 1) if claude_sessions else 0,
    })

    # ── OpenClaw (Codex) ──
    oc_ws = OPENCLAW_STATE_DIR / "workspace"
    oc_sess_dir = OPENCLAW_STATE_DIR / "agents" / "main" / "sessions"
    oc_files = _dir_files(oc_ws, ["MEMORY.md", "AGENTS.md", "SOUL.md", "USER.md", "TOOLS.md", "IDENTITY.md"]) if oc_ws.exists() else []
    oc_daily_dir = oc_ws / "memory"
    oc_daily = len(list(oc_daily_dir.glob("*.md"))) if oc_daily_dir.exists() else 0
    oc_sessions = list(oc_sess_dir.glob("*.jsonl")) if oc_sess_dir.exists() else []
    models.append({
        "id": "openclaw", "name": "OpenClaw (Codex)", "color": "#059669",
        "detected": OPENCLAW_STATE_DIR.exists(), "stateless": False,
        "instruction_file": None,
        "memory_files": oc_files,
        "daily_logs": oc_daily,
        "session_count": len(oc_sessions),
        "session_size_mb": round(sum(f.stat().st_size for f in oc_sessions) / (1024 * 1024), 1) if oc_sessions else 0,
    })

    # ── Gemini CLI ──
    gemini_dir = home / ".gemini"
    gemini_files = _dir_files(gemini_dir, ["GEMINI.md"]) if gemini_dir.exists() else []
    gemini_hist = gemini_dir / "history"
    gemini_hist_count = sum(1 for _ in gemini_hist.rglob("*") if _.is_file()) if gemini_hist.exists() else 0
    models.append({
        "id": "gemini", "name": "Gemini CLI", "color": "#2563eb",
        "detected": gemini_dir.exists(), "stateless": False,
        "instruction_file": None,
        "memory_files": gemini_files,
        "daily_logs": 0,
        "session_count": gemini_hist_count,
        "session_size_mb": 0,
    })

    # ── Ollama (stateless) ──
    try:
        import urllib.request as _ur
        req = _ur.Request("http://127.0.0.1:11434/api/tags", method="GET")
        with _ur.urlopen(req, timeout=2) as resp:
            od = json.loads(resp.read())
            onames = [m.get("name", "") for m in od.get("models", [])]
        models.append({
            "id": "ollama", "name": "Ollama (" + ", ".join(onames[:3]) + ")" if onames else "Ollama",
            "color": "#6b7280", "detected": True, "stateless": False, "local": True,
            "instruction_file": None, "memory_files": [],
            "daily_logs": 0, "session_count": 0, "session_size_mb": 0,
        })
    except Exception as e:
        log.debug("Ignored: %s", e)

    # ── Shared memory plane ──
    shared_plane = {"path": str(MEMORY_DIR), "exists": MEMORY_DIR.exists(), "directories": [], "file_count": 0, "total_size": 0}
    if MEMORY_DIR.exists():
        for d in sorted(MEMORY_DIR.iterdir()):
            if d.is_dir():
                dfiles = [f for f in d.rglob("*") if f.is_file()]
                shared_plane["directories"].append({"name": d.name, "file_count": len(dfiles)})
                shared_plane["file_count"] += len(dfiles)
                shared_plane["total_size"] += sum(f.stat().st_size for f in dfiles)

    # Coordination files
    coord_files = []
    proj_path = Path.home() / "documents" / "projects.md"
    if proj_path.exists():
        pinfo = _finfo(proj_path)
        if pinfo:
            pinfo["description"] = "shared by all agents"
            coord_files.append(pinfo)

    return {"models": models, "shared_plane": shared_plane, "coordination_files": coord_files}


def _is_allowed_memory_path(path_str: str) -> bool:
    """Whitelist check — only allow read/write to known model memory locations."""
    try:
        p = Path(path_str).resolve()
    except Exception as e:
        log.warning("Error: %s", e)
        return False
    if p.suffix not in (".md", ".txt", ".json"):
        return False
    home = Path.home().resolve()
    allowed_dirs = [
        home / ".claude",
        home / ".openclaw" / "workspace",
        home / ".gemini",
    ]
    if MEMORY_DIR.exists():
        allowed_dirs.append(MEMORY_DIR.resolve())
    # Check exact file match (CLAUDE.md at home root)
    if p == (home / "CLAUDE.md").resolve():
        return True
    # Allow projects.md
    if p == (home / "documents" / "projects.md").resolve():
        return True
    # Check directory containment
    for ad in allowed_dirs:
        try:
            p.relative_to(ad)
            return True
        except ValueError:
            continue
    return False


def _flush_preview(session_id: str, source: str) -> dict:
    """Extract session data for preview WITHOUT writing anything."""
    if source == "claude":
        claude_dir = Path.home() / ".claude" / "projects" / "-home-lobster"
        jsonl_file = claude_dir / f"{session_id}.jsonl"
        if not jsonl_file.exists():
            return {"ok": False, "error": f"Session {session_id} not found"}

        first_user_msg = ""
        user_msgs = 0
        assistant_msgs = 0
        tool_call_count = 0
        tools_used = set()
        first_ts = ""
        last_ts = ""

        with open(jsonl_file, "r", encoding="utf-8") as f:
            for line in f:
                try:
                    entry = json.loads(line)
                except Exception as e:
                    log.debug("Skipped: %s", e)
                    continue
                etype = entry.get("type", "")
                ts = entry.get("timestamp", "")
                if ts and isinstance(ts, str):
                    if not first_ts: first_ts = ts
                    last_ts = ts
                if etype == "user":
                    user_msgs += 1
                    if not first_user_msg:
                        msg = entry.get("message", {})
                        content = msg.get("content", "")
                        if isinstance(content, list):
                            for block in content:
                                if isinstance(block, dict) and block.get("type") == "text":
                                    first_user_msg = block.get("text", "")[:300].replace("\n", " ").strip()
                                    break
                                elif isinstance(block, str):
                                    first_user_msg = block[:300].replace("\n", " ").strip()
                                    break
                        elif isinstance(content, str):
                            first_user_msg = content[:300].replace("\n", " ").strip()
                elif etype == "assistant":
                    assistant_msgs += 1
                elif etype in ("tool_use", "tool_result"):
                    tool_call_count += 1
                    tool_name = entry.get("name", entry.get("tool", ""))
                    if tool_name: tools_used.add(tool_name)

        msg_count = user_msgs + assistant_msgs
        size_mb = round(jsonl_file.stat().st_size / 1048576, 1)
        date_str = first_ts[:10] if first_ts else ""

        summary = f"## Session Flush: {date_str}\n"
        summary += f"- **Source:** Claude Code\n"
        summary += f"- **Session:** `{session_id[:12]}...`\n"
        summary += f"- **Messages:** {msg_count} ({tool_call_count} tool uses)\n"
        summary += f"- **Size:** {size_mb} MB\n"
        summary += f"- **Tools:** {', '.join(sorted(tools_used)) if tools_used else 'none'}\n"
        summary += f"- **Task:** {first_user_msg if first_user_msg else '(no user message found)'}\n"

        default_dest = str(MEMORY_DIR / "session_flushes.md")

    elif source == "openclaw":
        oc_dir = OPENCLAW_STATE_DIR
        sessions_dir = oc_dir / "agents" / "main" / "sessions"
        jsonl_file = sessions_dir / f"{session_id}.jsonl"
        if not jsonl_file.exists():
            return {"ok": False, "error": f"Session {session_id} not found"}

        lines = jsonl_file.read_text(encoding="utf-8").strip().split("\n")
        first_user_msg = ""
        model = ""
        provider = ""
        total_input = 0
        total_output = 0
        tool_calls = 0
        tools_used = set()
        first_ts = ""
        last_ts = ""
        msg_count = 0

        for raw_line in lines:
            try:
                entry = json.loads(raw_line)
            except Exception as e:
                log.debug("Skipped: %s", e)
                continue
            etype = entry.get("type", "")
            ts = entry.get("timestamp", "")
            if ts and not first_ts: first_ts = ts
            if ts: last_ts = ts
            if etype == "message":
                msg_obj = entry.get("message", {})
                role = msg_obj.get("role", "")
                if role == "user" and not first_user_msg:
                    content = msg_obj.get("content", [])
                    for block in content:
                        if isinstance(block, dict) and block.get("type") == "text":
                            first_user_msg = block.get("text", "")[:300].replace("\n", " ").strip()
                            break
                        elif isinstance(block, str):
                            first_user_msg = block[:300].replace("\n", " ").strip()
                            break
                usage = entry.get("usage", {})
                total_input += usage.get("input", 0)
                total_output += usage.get("output", 0)
                msg_count += 1
                if entry.get("model"): model = entry["model"]
                if entry.get("provider"): provider = entry["provider"]
            elif etype == "toolCall":
                tool_calls += 1
                tools_used.add(entry.get("tool", "unknown"))

        date_str = first_ts[:10] if first_ts else ""
        summary = f"## Session Flush: {date_str}\n"
        summary += f"- **Session:** `{session_id[:12]}...`\n"
        summary += f"- **Model:** {provider}/{model if model else 'unknown'}\n"
        summary += f"- **Messages:** {msg_count} ({tool_calls} tool calls)\n"
        summary += f"- **Tokens:** {total_input:,} in / {total_output:,} out\n"
        summary += f"- **Tools:** {', '.join(sorted(tools_used)) if tools_used else 'none'}\n"
        summary += f"- **Task:** {first_user_msg if first_user_msg else '(no user message found)'}\n"

        default_dest = str(MEMORY_DIR / "session_flushes.md")
    else:
        return {"ok": False, "error": f"Preview not supported for source: {source}"}

    # Get current target file size
    dest_path = Path(default_dest)
    dest_exists = dest_path.exists()
    dest_size = dest_path.stat().st_size if dest_exists else 0
    summary_bytes = len(summary.encode("utf-8"))

    return {
        "ok": True,
        "summary": summary,
        "destination": default_dest,
        "dest_exists": dest_exists,
        "dest_size_bytes": dest_size,
        "summary_bytes": summary_bytes,
        "first_user_msg": first_user_msg,
        "source": source,
        "session_id": session_id,
    }

def _archive_session(session_id: str, source: str) -> dict:
    """Archive a session (hide from default listing)."""
    try:
        conn = _db_conn()
        conn.execute("INSERT OR REPLACE INTO session_archive (session_id, source) VALUES (?,?)",
                     (session_id, source))
        conn.commit()
        conn.close()
        return {"ok": True, "session_id": session_id}
    except Exception as e:
        return {"ok": False, "error": str(e)}

def _unarchive_session(session_id: str) -> dict:
    """Unarchive a session."""
    try:
        conn = _db_conn()
        conn.execute("DELETE FROM session_archive WHERE session_id=?", (session_id,))
        conn.commit()
        conn.close()
        return {"ok": True, "session_id": session_id}
    except Exception as e:
        return {"ok": False, "error": str(e)}

def _delete_session_file(session_id: str, source: str) -> dict:
    """Permanently delete a session file + archive entry + learnings."""
    import os
    deleted_file = False
    # Resolve session file path by source
    paths_to_try = []
    if source == "openclaw":
        oc_sessions = OPENCLAW_STATE_DIR / "agents" / "main" / "sessions"
        paths_to_try.append(oc_sessions / f"{session_id}.jsonl")
    elif source == "claude":
        claude_dir = Path.home() / ".claude" / "projects"
        # Claude sessions are nested — search for the JSONL
        for p in claude_dir.rglob(f"{session_id}.jsonl"):
            paths_to_try.append(p)
    elif source == "gemini":
        gemini_dir = Path.home() / ".gemini" / "history"
        for p in gemini_dir.rglob(f"*{session_id}*"):
            paths_to_try.append(p)

    for fpath in paths_to_try:
        if fpath.exists():
            try:
                os.remove(fpath)
                deleted_file = True
                log.info("Deleted session file: %s", fpath)
            except Exception as e:
                log.warning("Failed to delete session file %s: %s", fpath, e)

    # Also archive it (in case file delete didn't work, still hide it)
    _archive_session(session_id, source)

    # Remove learnings
    try:
        conn = _db_conn()
        conn.execute("DELETE FROM session_learnings WHERE session_id=?", (session_id,))
        conn.execute("DELETE FROM session_custom_names WHERE session_id=?", (session_id,))
        conn.commit()
        conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return {"ok": True, "session_id": session_id, "file_deleted": deleted_file}

def _get_archived_session_ids() -> set:
    """Get set of archived session IDs."""
    try:
        conn = _db_conn()
        rows = conn.execute("SELECT session_id FROM session_archive").fetchall()
        conn.close()
        return {r[0] for r in rows}
    except Exception:
        return set()

def _extract_learnings_preview(session_id: str, source: str, force: bool = False) -> dict:
    """LLM-powered session analysis — persists results in DB."""
    # Check cache first (unless force refresh)
    if not force:
        try:
            conn = _db_conn()
            row = conn.execute("SELECT learnings, backend_used, extracted_at FROM session_learnings WHERE session_id=?", (session_id,)).fetchone()
            if row and row[0]:
                conn.close()
                return {
                    "ok": True, "learnings": row[0], "facts": [],
                    "llm_used": True, "cached": True,
                    "session_id": session_id, "source": source,
                }
            conn.close()
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Try to get basic preview data (may fail for some sources — that's OK)
    preview = _flush_preview(session_id, source)
    if not preview.get("ok"):
        preview = {"ok": True, "summary": "", "first_user_msg": ""}

    # Build transcript from session JSONL
    transcript = ""

    def _extract_text_from_content(content):
        """Pull text from content (string, list of blocks, or dict)."""
        if isinstance(content, str):
            return content
        if isinstance(content, list):
            for block in content:
                if isinstance(block, dict) and block.get("type") == "text":
                    return block.get("text", "")
                if isinstance(block, dict) and block.get("text"):
                    return block.get("text", "")
                if isinstance(block, str):
                    return block
        return ""

    if source == "gemini":
        # Gemini stores JSON files in ~/.gemini/tmp/*/chats/*.json
        gemini_tmp = Path.home() / ".gemini" / "tmp"
        if gemini_tmp.exists():
            for json_file in gemini_tmp.rglob("chats/*.json"):
                try:
                    data = json.loads(json_file.read_text(encoding="utf-8"))
                    if data.get("sessionId") == session_id:
                        for msg in data.get("messages", []):
                            mtype = msg.get("type", "")
                            role = "USER" if mtype == "user" else ("ASSISTANT" if mtype == "model" else "")
                            text = _extract_text_from_content(msg.get("content", []))
                            if role and text:
                                transcript += f"\n{role}: {text[:400]}\n"
                                if len(transcript) > 3000:
                                    break
                        break
                except Exception:
                    continue
    else:
        # Claude and OpenClaw use JSONL files
        jsonl_file = None
        if source == "claude":
            claude_dir = Path.home() / ".claude" / "projects" / "-home-lobster"
            jsonl_file = claude_dir / f"{session_id}.jsonl"
        elif source == "openclaw":
            jsonl_file = OPENCLAW_STATE_DIR / "agents" / "main" / "sessions" / f"{session_id}.jsonl"

        if jsonl_file and jsonl_file.exists():
            try:
                with open(jsonl_file, "r", encoding="utf-8") as f:
                    for line in f:
                        try:
                            entry = json.loads(line)
                        except Exception:
                            continue
                        etype = entry.get("type", "")
                        role = ""
                        text = ""
                        if etype == "user":
                            role = "USER"
                            text = _extract_text_from_content(entry.get("message", {}).get("content", ""))
                        elif etype == "assistant":
                            role = "ASSISTANT"
                            text = _extract_text_from_content(entry.get("message", {}).get("content", ""))
                        elif etype == "message":
                            msg_obj = entry.get("message", {})
                            role = msg_obj.get("role", "").upper()
                            text = _extract_text_from_content(msg_obj.get("content", []))
                        if role and text:
                            transcript += f"\n{role}: {text[:400]}\n"
                            if len(transcript) > 3000:
                                transcript += "\n[...truncated...]\n"
                                break
            except Exception as e:
                log.debug("Transcript extraction error: %s", e)

    # LLM analysis — structured extraction with scoped facts
    learnings = ""
    structured_facts = []
    llm_used = False
    if transcript.strip():
        # Get user's preferred name
        _user_name2 = ""
        try:
            _user_name2 = _config.get("display_name", "") or _config.get("preferences", {}).get("display_name", "")
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        _name_instr = f"\nIMPORTANT: Always refer to the user by their name \"{_user_name2}\", never as \"the user\" or \"user\"." if _user_name2 else ""
        prompt = (
            "Extract ONLY durable knowledge from this session worth remembering months from now." + _name_instr + "\n"
            "Be extremely selective. Fewer facts is better. 0 is fine if nothing is durable.\n\n"
            "Categorize each fact by scope:\n"
            "- agent: facts about a specific agent's behavior, preferences, or performance\n"
            "- project: facts about a specific project, codebase, or task\n"
            "- global: universally useful knowledge, patterns, or user preferences\n\n"
            "Return ONLY valid JSON:\n"
            '{"facts": [{"text": "concise actionable insight", "scope": "agent|project|global", "importance": 1-10}]}\n\n'
            "Rules:\n"
            "- Max 5 facts. Quality over quantity.\n"
            "- importance: 1=trivial, 5=moderate, 10=critical\n"
            "- Return ONLY the JSON object, no markdown fences, no explanation\n\n"
            "DO NOT extract:\n"
            "- Implementation details (specific code changes, version numbers, patches, bug fixes)\n"
            "- Session-specific observations (what happened this session, what was diagnosed)\n"
            "- Agent self-description (name, role, persona — these live in .md files)\n"
            "- Environment facts (what tools are installed, file paths, versions)\n"
            "- Task status or progress (what was completed, what is pending)\n"
            "- Generic/obvious knowledge anyone would know\n"
            "- Response style preferences (already in SOUL.md files)\n"
            "- Feature requests or tasks to build (these go in task trackers, not memory)\n"
            "- Project requirements or specs (e.g. \'should support X\', \'needs Y feature\')\n\n"
            "ONLY extract:\n"
            "- Durable user preferences that affect future interactions\n"
            "- Architectural decisions that won't change session-to-session\n"
            "- Hard-won debugging insights (reusable lessons, not specific bugs)\n"
            "- User-stated rules or constraints for future behavior\n\n"
            + transcript
        )
        # Try all available backends — API-based first, then CLI-based
        _api_backends = [bk for bk, info in PROVIDER_REGISTRY.items() if info.get("type") in ("api", "gateway")]
        _cli_backends = [bk for bk, info in PROVIDER_REGISTRY.items() if info.get("type") == "cli"]
        _local_backends = [bk for bk, info in PROVIDER_REGISTRY.items() if info.get("type") == "local"]
        for backend in _api_backends + _cli_backends + _local_backends:
            if backend not in PROVIDER_REGISTRY:
                continue
            try:
                result = dispatch_agent(prompt, backend, timeout=45)
                if result.get("text", "").strip():
                    raw = result["text"].strip()
                    llm_used = True
                    # Try to parse as JSON for structured facts
                    # Inline JSON parse (cortex parser removed)
                    try:
                        import json as _pj; parsed_json = _pj.loads(raw)
                    except Exception:
                        parsed_json = None
                    if parsed_json and "facts" in parsed_json:
                        structured_facts = parsed_json["facts"][:10]
                        # Build human-readable learnings text as fallback
                        _scope_labels = {"agent": "\U0001f916 Agent", "project": "\U0001f4c1 Project", "global": "\U0001f310 Global"}
                        learnings = "\n".join(
                            f"[{_scope_labels.get(f.get('scope','global'), '\U0001f310 Global')}] {f.get('text','')}"
                            for f in structured_facts if f.get("text")
                        )
                    else:
                        learnings = raw
                    break
            except Exception as e:
                log.debug("LLM extract [%s] error: %s", backend, e)
                continue

    # Persist to DB — session_learnings
    backend_used = ""
    _legacy_ids = []
    # Always persist extraction result (even empty) to prevent infinite retry loops
    try:
        conn = _db_conn()
        conn.execute(
            "INSERT OR REPLACE INTO session_learnings (session_id, source, learnings, backend_used) VALUES (?,?,?,?)",
            (session_id, source, learnings or "(no extractable learnings)", backend_used)
        )
        conn.commit()
        conn.close()
    except Exception as e:
        log.debug("Failed to persist learnings: %s", e)
    return {
        "ok": True,
        "learnings": learnings,
        "facts": _legacy_ids,
        "llm_used": llm_used,
        "cached": False,
        "session_id": session_id,
        "source": source,
    }


def _list_learning_destinations() -> list:
    """Scan for save targets — global first, then project, then agent MEMORY.md."""
    destinations = []

    # Global group (first — most common target)
    destinations.append({
        "path": str(MEMORY_DIR / "session_learnings.md"),
        "label": "Global — session_learnings.md",
        "group": "global"
    })

    # Project group: tasks/lessons.md in workspace
    try:
        projects = _project_list(include_all=True)
        for proj in projects:
            proj_name = proj.get("name", "Unknown")
            proj_id = proj.get("id", "")
            proj_dir = AGENT_WORKSPACE_DIR / "projects" / proj_id
            if not proj_dir.exists():
                proj_dir.mkdir(parents=True, exist_ok=True)
            lessons = proj_dir / "tasks" / "lessons.md"
            destinations.append({
                "path": str(lessons),
                "label": f"{proj_name} — lessons.md",
                "group": "project"
            })
    except Exception as e:
        log.debug("Project scan error: %s", e)

    # Agent group: each persona's MEMORY.md only (no daily logs)
    persona_names = {}
    try:
        conn = _db_conn()
        for row in conn.execute("SELECT id, name, avatar FROM personas ORDER BY sort_order, name").fetchall():
            persona_names[row[0]] = {"name": row[1], "avatar": row[2] or ""}
        conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    try:
        if PERSONAS_DIR.exists():
            for pid, info in persona_names.items():
                persona_dir = PERSONAS_DIR / pid
                if not persona_dir.is_dir():
                    continue
                display = info.get("name", pid)
                avatar = info.get("avatar", "")
                prefix = f"{avatar} {display}".strip() if avatar else display
                mem_file = persona_dir / "MEMORY.md"
                destinations.append({
                    "path": str(mem_file),
                    "label": f"{prefix} — MEMORY.md",
                    "group": "agent"
                })
    except Exception as e:
        log.debug("Persona scan error: %s", e)

    return destinations


def _flush_session_to_memory(session_id: str, project_id: str = None) -> dict:
    """Extract key learnings from a session and append to project MEMORY.md.

    Reads the session .jsonl, extracts:
    - First user message (task/intent)
    - Tool usage patterns
    - Token costs
    - Model used
    - Duration

    Writes a summary block to the project's MEMORY.md or global memory.
    """
    oc_dir = OPENCLAW_STATE_DIR
    sessions_dir = oc_dir / "agents" / "main" / "sessions"
    jsonl_file = sessions_dir / f"{session_id}.jsonl"
    if not jsonl_file.exists():
        return {"ok": False, "error": f"Session {session_id} not found"}

    lines = jsonl_file.read_text(encoding="utf-8").strip().split("\n")
    if not lines:
        return {"ok": False, "error": "Empty session file"}

    # Extract summary data
    first_user_msg = ""
    model = ""
    provider = ""
    total_input = 0
    total_output = 0
    tool_calls = 0
    tools_used = set()
    first_ts = ""
    last_ts = ""
    msg_count = 0

    for raw_line in lines:
        try:
            entry = json.loads(raw_line)
        except Exception as e:
            log.debug("Parse skip: %s", e)
            continue
        etype = entry.get("type", "")
        ts = entry.get("timestamp", "")
        if ts and not first_ts:
            first_ts = ts
        if ts:
            last_ts = ts

        if etype == "message":
            msg_obj = entry.get("message", {})
            role = msg_obj.get("role", "")
            if role == "user" and not first_user_msg:
                content = msg_obj.get("content", [])
                for block in content:
                    if isinstance(block, dict) and block.get("type") == "text":
                        text = block.get("text", "")
                        # Take first 200 chars as task description
                        first_user_msg = text[:200].replace("\n", " ").strip()
                        break
                    elif isinstance(block, str):
                        first_user_msg = block[:200].replace("\n", " ").strip()
                        break
            usage = entry.get("usage", {})
            total_input += usage.get("input", 0)
            total_output += usage.get("output", 0)
            msg_count += 1
            if entry.get("model"):
                model = entry["model"]
            if entry.get("provider"):
                provider = entry["provider"]
        elif etype == "toolCall":
            tool_calls += 1
            tools_used.add(entry.get("tool", "unknown"))

    # Build summary block
    import datetime
    date_str = first_ts[:10] if first_ts else datetime.datetime.now().strftime("%Y-%m-%d")

    summary = f"""
## Session Flush: {date_str}
- **Session:** `{session_id[:12]}...`
- **Model:** {provider}/{model if model else 'unknown'}
- **Messages:** {msg_count} ({tool_calls} tool calls)
- **Tokens:** {total_input:,} in / {total_output:,} out
- **Tools:** {', '.join(sorted(tools_used)) if tools_used else 'none'}
- **Task:** {first_user_msg if first_user_msg else '(no user message found)'}
"""

    # Determine target MEMORY.md
    target_path = None
    if project_id:
        # Find project workspace
        for proj in _project_list(include_all=True):
            if proj.get("id") == project_id:
                wp = proj.get("workspace_path", "")
                if wp:
                    target_path = Path(wp) / "MEMORY.md"
                break

    if not target_path:
        # Fall back to Porter's own memory dir
        target_path = MEMORY_DIR / "session_flushes.md"

    return {"ok": True, "message": "Session flushed", "distilled": {}}


def _flush_claude_session(session_id: str) -> dict:
    """Flush a Claude Code session to the shared memory plane.

    Reads the Claude .jsonl, extracts summary data (first user message,
    message counts, timestamps), and appends to session_flushes.md.
    """
    claude_dir = Path.home() / ".claude" / "projects" / "-home-lobster"
    jsonl_file = claude_dir / f"{session_id}.jsonl"
    if not jsonl_file.exists():
        return {"ok": False, "error": f"Claude session {session_id} not found"}

    first_user_msg = ""
    user_msgs = 0
    assistant_msgs = 0
    tool_call_count = 0
    tools_used = set()
    first_ts = ""
    last_ts = ""

    try:
        with open(jsonl_file, "r", encoding="utf-8") as f:
            for line in f:
                try:
                    entry = json.loads(line)
                except Exception as e:
                    log.debug("Parse skip: %s", e)
                    continue
                etype = entry.get("type", "")
                ts = entry.get("timestamp", "")
                if ts and isinstance(ts, str):
                    if not first_ts:
                        first_ts = ts
                    last_ts = ts

                if etype == "user":
                    user_msgs += 1
                    if not first_user_msg:
                        msg = entry.get("message", {})
                        content = msg.get("content", "")
                        if isinstance(content, list):
                            for block in content:
                                if isinstance(block, dict) and block.get("type") == "text":
                                    first_user_msg = block.get("text", "")[:200].replace("\n", " ").strip()
                                    break
                                elif isinstance(block, str):
                                    first_user_msg = block[:200].replace("\n", " ").strip()
                                    break
                        elif isinstance(content, str):
                            first_user_msg = content[:200].replace("\n", " ").strip()
                elif etype == "assistant":
                    assistant_msgs += 1
                elif etype == "tool_use" or etype == "tool_result":
                    tool_call_count += 1
                    tool_name = entry.get("name", entry.get("tool", ""))
                    if tool_name:
                        tools_used.add(tool_name)
    except Exception as e:
        return {"ok": False, "error": f"Failed to parse session: {e}"}

    msg_count = user_msgs + assistant_msgs
    import datetime
    date_str = first_ts[:10] if first_ts else datetime.datetime.now().strftime("%Y-%m-%d")
    size_mb = round(jsonl_file.stat().st_size / 1048576, 1)

    summary = f"""
## Session Flush: {date_str}
- **Source:** Claude Code
- **Session:** `{session_id[:12]}...`
- **Messages:** {msg_count} ({tool_call_count} tool uses)
- **Size:** {size_mb} MB
- **Tools:** {', '.join(sorted(tools_used)) if tools_used else 'none'}
- **Task:** {first_user_msg if first_user_msg else '(no user message found)'}
"""

    return {"ok": True, "message": "Session flushed", "distilled": {}}


def _flush_gemini_session(session_id: str) -> dict:
    """Flush a Gemini CLI session to GEMINI.md memory file."""
    import glob as _glob
    home = Path.home()
    # Find the session file
    target = None
    for json_file in (home / ".gemini" / "tmp").rglob("chats/*.json"):
        try:
            with open(json_file, "r") as f:
                data = json.load(f)
            if data.get("sessionId") == session_id:
                target = json_file
                break
        except Exception:
            continue
    if not target:
        return {"ok": False, "error": f"Gemini session {session_id} not found"}
    try:
        with open(target, "r", encoding="utf-8") as f:
            data = json.load(f)
        msgs = data.get("messages", [])
        start = data.get("startTime", "")[:10]
        msg_count = len(msgs)
        # Extract first user message
        first_msg = ""
        for m in msgs:
            content = m.get("content", [])
            if isinstance(content, list):
                for block in content:
                    if isinstance(block, dict) and block.get("text"):
                        first_msg = block["text"][:200].replace("\n", " ").strip()
                        break
            if first_msg:
                break
        summary = f"\n## Gemini Session Flush: {start}\n"
        summary += f"- **Messages:** {msg_count}\n"
        summary += f"- **Session:** `{session_id[:12]}...`\n"
        if first_msg:
            summary += f"- **Topic:** {first_msg}\n"
        return {"ok": True, "distilled": {}}
    except Exception as e:
        return {"ok": False, "error": str(e)}

def _reload_config_and_tasks():
    """Re-read config and task registry from disk (called by /api/reload)."""
    global _config
    _config = load_config()
    _treg_load()


def _treg_load() -> None:
    """Load all persisted task-registry entries from SQLite into _treg at startup."""
    global _treg
    TASKS_REGISTRY_DIR.mkdir(parents=True, exist_ok=True)
    
    # 1. One-time migration: Import existing JSON files if SQLite is empty
    conn = _db_conn()
    count = conn.execute("SELECT count(*) FROM tasks").fetchone()[0]
    if count == 0:
        log.info("Task table empty, migrating JSON files to SQLite...")
        for fp in TASKS_REGISTRY_DIR.glob("*.json"):
            try:
                t = json.loads(fp.read_text(encoding="utf-8"))
                if not isinstance(t, dict) or not t.get("id"): continue
                
                # Normalize timestamps
                for key in ("created_at", "updated_at", "completed_at"):
                    if isinstance(t.get(key), str):
                        try: t[key] = float(t[key])
                        except: t[key] = 0
                
                conn.execute("""
                    INSERT OR REPLACE INTO tasks 
                    (id, project_id, title, description, status, priority, phase, 
                     created_at, updated_at, completed_at, assigned_agent_id, assigned_persona_id, 
                     tokens_used, time_minutes, result, tags, sort_order)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """, (
                    t.get("id"), t.get("project_id"), t.get("title", "Untitled"),
                    t.get("description"), t.get("status", "pending"), t.get("priority", "normal"),
                    t.get("phase"), t.get("created_at", 0), t.get("updated_at"),
                    t.get("completed_at"), t.get("assigned_agent_id"), task.get("assigned_persona_id"), t.get("tokens_used", 0),
                    t.get("time_minutes") or t.get("time_spent_mins") or 0, t.get("result"),
                    json.dumps(t.get("tags", [])), t.get("sort_order", 0)
                ))
            except Exception as e:
                log.debug("Migration failed for %s: %s", fp.name, e)
        conn.commit()

    # 2. Load all from DB
    loaded: dict = {}
    rows = conn.execute("SELECT * FROM tasks").fetchall()
    conn.close()
    
    for r in rows:
        t = dict(r)
        # De-serialize tags
        try: t["tags"] = json.loads(t.get("tags", "[]"))
        except: t["tags"] = []
        # Normalize legacy status values
        if t.get("status") in ("done", "completed"):
            t["status"] = "complete"
        # Alias DB column → JS field name
        t["time_spent_mins"] = t.get("time_minutes", 0)
        loaded[t["id"]] = t
        
    with _treg_lock:
        _treg.clear()
        _treg.update(loaded)

def _treg_save(task: dict) -> None:
    """Persist a single task to SQLite."""
    try:
        conn = _db_conn()
        conn.execute("""
            INSERT OR REPLACE INTO tasks 
            (id, project_id, title, description, status, priority, phase, 
             created_at, updated_at, completed_at, assigned_agent_id, assigned_persona_id, 
             tokens_used, time_minutes, result, tags, sort_order)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (
            task.get("id"), task.get("project_id"), task.get("title", "Untitled"),
            task.get("description"), task.get("status", "pending"), task.get("priority", "normal"),
            task.get("phase"), task.get("created_at", 0), task.get("updated_at"),
            task.get("completed_at"), task.get("assigned_agent_id"), task.get("assigned_persona_id"), task.get("tokens_used", 0),
            task.get("time_minutes") or task.get("time_spent_mins") or 0, task.get("result"),
            json.dumps(task.get("tags", [])), task.get("sort_order", 0)
        ))
        conn.commit()
        conn.close()
    except Exception as e:
        log.error("Task DB save failed: %s", e)
    
    # Also update in-memory cache
    with _treg_lock:
        _treg[task["id"]] = task


def _load_projects_dashboard() -> dict:
    """Aggregate projects, model registry, and checkpoint tasks."""
    pf = _find_projects_file()
    projects, models = [], []
    if pf:
        try:
            raw      = pf.read_text(encoding='utf-8', errors='replace')
            projects = _parse_projects_md(raw)
            models   = _parse_model_registry(raw)
        except Exception as e:
            log.debug("Ignored: %s", e)
    # Annotate models with memory-file health + projects.md sync check
    for m in models:
        mf_raw = m.get('memory_files', '')
        paths  = re.findall(r'[`\'`]?([~/.][^\s`\']+\.md)[`\'`]?', mf_raw)
        m['memory_path']   = paths[0].replace('~', str(Path.home())) if paths else None
        m['memory_exists'] = False
        m['memory_ago']    = None
        m['synced']        = None
        if m['memory_path']:
            mp = Path(m['memory_path'])
            if mp.exists():
                m['memory_exists'] = True
                m['memory_ago']    = _time_ago(mp.stat().st_mtime)
                try:
                    m['synced'] = 'projects.md' in mp.read_text(encoding='utf-8', errors='replace')
                except Exception as e:
                    log.debug("Ignored: %s", e)
    sp = _find_sprint_plan()
    sprints = []
    if sp:
        try:
            sprints = _parse_sprint_plan(sp.read_text(encoding='utf-8', errors='replace'))
        except Exception as e:
            log.debug("Ignored: %s", e)
    return {
        'projects_file': str(pf) if pf else None,
        'projects':      projects,
        'models':        models,
        'tasks':         _scan_checkpoints(),
        'sprints':       sprints,
    }


def _project_activity_feed(project_id: str, limit: int = 20) -> list:
    """Return a merged recent activity feed for one project from trace + dispatch data."""
    pid = str(project_id or "").strip()
    if not pid:
        return []
    limit = max(1, min(int(limit or 20), 100))
    items = []
    proj = _project_by_id(pid) or {}
    now_ts = time.time()
    cutoff = float(proj.get("created_at") or 0)
    updated_at = float(proj.get("updated_at") or 0)
    if updated_at > cutoff:
        cutoff = updated_at
    if str(proj.get("name") or "").strip().lower() == "first mission":
        cutoff = max(cutoff, now_ts - 30 * 60)
    try:
        conn = _db_conn()
        trace_rows = conn.execute(
            """SELECT ts, agent_name, action, status, output_summary, task_id, trace_id
               FROM trace_steps WHERE project_id=? AND ts>=? ORDER BY ts DESC LIMIT ?""",
            (pid, cutoff, limit)
        ).fetchall()
        dispatch_rows = conn.execute(
            """SELECT created_at, persona_id, to_agent, status, response, error, task_id, run_id
               FROM agent_messages WHERE project_id=? AND created_at>=? ORDER BY created_at DESC LIMIT ?""",
            (pid, cutoff, limit)
        ).fetchall()
        conn.close()
        for r in trace_rows:
            summary = (r[4] or "")[:220]
            if not summary or summary == "(no summary recorded)":
                continue
            items.append({
                "ts": r[0] or 0,
                "source": "trace",
                "agent_name": r[1] or "",
                "action": r[2] or "",
                "status": r[3] or "",
                "summary": summary,
                "task_id": r[5] or "",
                "ref_id": r[6] or "",
            })
        for r in dispatch_rows:
            agent_name = str(r[1] or r[2] or "").strip()
            if agent_name:
                persona = _persona_by_id(agent_name)
                if persona:
                    if bool(persona.get("hidden")) or not bool(persona.get("public", 1)):
                        continue
                    agent_name = str(persona.get("name") or agent_name)
            summary = ((r[5] or "") if (r[3] or "") == "failed" else (r[4] or ""))[:220]
            if not summary or summary == "(no summary recorded)":
                continue
            items.append({
                "ts": r[0] or 0,
                "source": "dispatch",
                "agent_name": agent_name,
                "action": "reply" if (r[3] or "") == "complete" else (r[2] or "dispatch"),
                "status": r[3] or "",
                "summary": summary,
                "task_id": r[6] or "",
                "ref_id": r[7] or "",
            })
    except Exception as e:
        log.debug("Project activity feed failed for %s: %s", pid, e)
        return []
    # Always include project creation as baseline activity
    created_at = float(proj.get("created_at") or 0)
    if created_at:
        items.append({
            "ts": created_at,
            "type": "project",
            "agent": "",
            "action": "Project created",
            "status": "ok",
            "summary": proj.get("name", "Untitled") + " — " + (proj.get("description", "") or "No description")[:120],
            "task_id": "",
            "ref_id": pid,
        })
    items.sort(key=lambda x: float(x.get("ts") or 0), reverse=True)
    return items[:limit]


