# ── config helpers ────────────────────────────────────────────────────────

def _hash_password(password: str, salt: str) -> str:
    """Hash password with scrypt (memory-hard KDF). Returns hex string."""
    derived = hashlib.scrypt(
        password.encode(), salt=salt.encode(),
        n=16384, r=8, p=1, dklen=32
    )
    return derived.hex()

def _hash_password_legacy(password: str, salt: str) -> str:
    """Legacy SHA-256 hash — only used for migration check."""
    return hashlib.sha256((salt + password).encode()).hexdigest()

def _save_config(cfg: dict) -> None:
    """Write config to disk."""
    global _config
    CONFIG_PATH.write_text(json.dumps(cfg, indent=2))
    _config = cfg
    try:
        _invalidate_models_payload_cache()
        _invalidate_backend_version_cache()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
def load_config() -> dict:
    cfg: dict = {}
    if CONFIG_PATH.exists():
        try:
            cfg = json.loads(CONFIG_PATH.read_text())
        except Exception as e:
            log.debug("Ignored: %s", e)
            cfg = {}

    changed = False

    # ── auth defaults (first run) ──
    if "username" not in cfg:
        salt = secrets.token_hex(16)
        cfg.update({
            "username":      "admin",
            "full_name":     "",
            "display_name":  "Admin",
            "email":         "",
            "salt":          salt,
            "password_hash": _hash_password("porter", salt),
        })
        print("  [porter] First run — default login: admin / porter")
        print("  [porter] Change your password immediately in Settings.")
        changed = True

    # profile key migration
    if "full_name" not in cfg:
        cfg["full_name"] = ""
        changed = True

    # ── nodes migration (v0.8: node-first model replaces flat locations) ──
    if "nodes" not in cfg:
        hn = socket.gethostname()
        # migrate existing flat locations as mounts under the local node
        legacy = cfg.get("locations", [])
        if not legacy:
            legacy = [dict(m) for m in DEFAULT_MOUNTS]
        local_node = {
            "id":           hn,
            "label":        hn,
            "type":         "local",
            "hostname":     hn,
            "tailscale_ip": None,
            "mounts": [
                {"id": loc["id"], "label": loc.get("label", loc["id"]),
                 "path": loc.get("path", ""), "visible": True}
                for loc in legacy
            ],
        }
        cfg["nodes"] = [local_node]
        changed = True
    # keep legacy "locations" key only for external backward-compat reads;
    # all internal code now uses nodes[*].mounts

    # ── agents ──
    if "agents" not in cfg:
        cfg["agents"] = []
        changed = True

    # ── project registry ──
    # projects key removed — projects live in SQLite (migrated in Plan 05)
    if "active_project_id" not in cfg:
        cfg["active_project_id"] = None
        changed = True
    if _migrate_project_workspace_root():
        changed = True
    if _migrate_legacy_porter_app_project(cfg):
        changed = True
    if _ensure_launchpad_project(cfg):
        changed = True
    # v0.31.44 — Backfill owner on existing projects
    _admin_uname = cfg.get("username", "admin")
    for _bp in cfg.get("projects", []):
        if "owner" not in _bp:
            _bp["owner"] = _admin_uname
            changed = True
    if _normalize_project_registry_names(cfg):
        changed = True

    # ── preferences (merge so new keys are always present) ──
    prefs = cfg.setdefault("preferences", {})
    for k, v in DEFAULT_PREFERENCES.items():
        if k not in prefs:
            prefs[k] = v
            changed = True

    # ── api_keys ──
    if "api_keys" not in cfg:
        cfg["api_keys"] = {}
        changed = True

    # ── fleet lifecycle config ──
    fleet = cfg.setdefault("agent_fleet", {})
    for k, v in DEFAULT_AGENT_FLEET.items():
        if k not in fleet:
            fleet[k] = ({} if k == "devices" else v)
            changed = True
    if not isinstance(fleet.get("devices"), dict):
        fleet["devices"] = {}
        changed = True

    if changed:
        save_config(cfg)
    return cfg

def save_config(cfg: dict) -> None:
    CONFIG_PATH.write_text(json.dumps(cfg, indent=2))
    try:
        _invalidate_models_payload_cache()
        _invalidate_backend_version_cache()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
def _load_serve_dirs(cfg: dict) -> None:
    """Repopulate global SERVE_DIRS from nodes[*].mounts (local nodes only)."""
    SERVE_DIRS.clear()
    for node in cfg.get("nodes", []):
        if node.get("type") == "local":
            for mount in node.get("mounts", []):
                mid = mount.get("id"); mp = mount.get("path", "")
                if mid and mp:
                    SERVE_DIRS[mid] = Path(mp)
    # legacy fallback: flat locations array (pre-0.8 configs not yet migrated)
    if not SERVE_DIRS:
        for loc in cfg.get("locations", []):
            if loc.get("type") == "local" and loc.get("id") and loc.get("path"):
                SERVE_DIRS[loc["id"]] = Path(loc["path"])

def _refresh_claude_usage(agent_id: str) -> dict:
    """Fetch live Claude Code rate-limit utilisation via a count_tokens probe."""
    import urllib.request, urllib.error
    from datetime import datetime, timezone
    cred_path = Path.home() / ".claude" / ".credentials.json"
    if not cred_path.exists():
        return {"error": "~/.claude/.credentials.json not found"}
    try:
        creds = json.loads(cred_path.read_text())
        token = creds.get("claudeAiOauth", {}).get("accessToken", "")
        if not token:
            return {"error": "No OAuth access token in credentials"}
    except Exception as e:
        return {"error": f"Failed to read credentials: {e}"}

    payload = json.dumps({
        "model": "claude-sonnet-4-6",
        "messages": [{"role": "user", "content": "x"}]
    }).encode()
    req = urllib.request.Request(
        "https://api.anthropic.com/v1/messages/count_tokens",
        data=payload, method="POST"
    )
    req.add_header("content-type", "application/json")
    req.add_header("anthropic-version", "2023-06-01")
    req.add_header("authorization", f"Bearer {token}")

    def _build_snapshot(util_pct: int, resets_at_raw: str | None) -> dict:
        window_resets_at = None
        if resets_at_raw:
            try:
                # Header is a Unix timestamp (seconds)
                window_resets_at = datetime.fromtimestamp(
                    int(resets_at_raw), tz=timezone.utc).isoformat()
            except (ValueError, OSError):
                window_resets_at = resets_at_raw  # store as-is if unparseable
        if util_pct >= 100:   status = "exhausted"
        elif util_pct >= 90:  status = "rate_limited"
        elif util_pct >= 75:  status = "degraded"
        else:                 status = "available"
        return {
            "agent_id":         agent_id,
            "provider":         "claude_code",
            "captured_at":      datetime.now(timezone.utc).isoformat(),
            "status":           status,
            "usage_percent":    util_pct,
            "window_started_at": None,
            "window_resets_at": window_resets_at,
            "source_type":      "api_live",
        }

    def _extract_headers(hdrs) -> dict | None:
        # Prefer the unified 5-hour window header Claude Code uses
        for abbrev in ("5h", "7d"):
            u = hdrs.get(f"anthropic-ratelimit-unified-{abbrev}-utilization")
            r = hdrs.get(f"anthropic-ratelimit-unified-{abbrev}-reset")
            if u is not None:
                try:
                    return _build_snapshot(round(float(u) * 100), r)
                except ValueError as _e:
                    mlog.emit("debug", "ai", "ratelimit.parse_failed",
                              f"Unified rate-limit header parse failed: {_e}",
                              extra={"exc_type": "ValueError"})
        # Fallback: compute from standard token headers
        lim = hdrs.get("anthropic-ratelimit-tokens-limit")
        rem = hdrs.get("anthropic-ratelimit-tokens-remaining")
        rst = hdrs.get("anthropic-ratelimit-tokens-reset")
        if lim and rem:
            try:
                used_pct = round((1 - int(rem) / int(lim)) * 100)
                return _build_snapshot(used_pct, rst)
            except (ValueError, ZeroDivisionError) as _e:
                mlog.emit("debug", "ai", "ratelimit.parse_failed",
                          f"Fallback rate-limit header parse failed: {_e}",
                          extra={"exc_type": type(_e).__name__})
        return None

    try:
        with urllib.request.urlopen(req, timeout=10) as resp:
            snap = _extract_headers(resp.headers)
            if snap is None:
                return {"error": "No rate-limit headers in API response"}
            USAGE_DIR.mkdir(parents=True, exist_ok=True)
            (USAGE_DIR / f"{agent_id}.json").write_text(json.dumps(snap, indent=2))
            return {"ok": True, "snapshot": snap}
    except urllib.error.HTTPError as e:
        # Still try to read headers from error response (e.g. 429)
        snap = _extract_headers(e.headers)
        if snap:
            USAGE_DIR.mkdir(parents=True, exist_ok=True)
            (USAGE_DIR / f"{agent_id}.json").write_text(json.dumps(snap, indent=2))
            return {"ok": True, "snapshot": snap}
        body = e.read().decode(errors="replace")[:300]
        return {"error": f"HTTP {e.code}: {body}"}
    except Exception as e:
        return {"error": str(e)}


def _refresh_openclaw_usage(agent_id: str) -> dict:
    """Fetch live OpenClaw session usage via `openclaw sessions --json --all-agents`."""
    import subprocess
    from datetime import datetime, timezone
    # Capability-gated: only attempt if openclaw binary is reachable
    cap = _capabilities_cache.get("openclaw", {})
    if not cap.get("ok"):
        return {"error": "OpenClaw not available"}
    # Resolve openclaw binary — may be in ~/.npm-global/bin
    import shutil
    oc_bin = shutil.which("openclaw")
    if not oc_bin:
        for candidate in (
            str(Path.home() / ".npm-global" / "bin" / "openclaw"),
            "/usr/local/bin/openclaw",
        ):
            if Path(candidate).exists():
                oc_bin = candidate
                break
    if not oc_bin:
        return {"error": "openclaw binary not found"}
    try:
        r = subprocess.run(
            [oc_bin, "sessions", "--json", "--all-agents"],
            capture_output=True, text=True, timeout=15
        )
        if r.returncode != 0:
            return {"error": f"openclaw exit {r.returncode}: {(r.stderr or '')[:200]}"}
        data = __import__("json").loads(r.stdout)
    except FileNotFoundError:
        return {"error": "openclaw binary not found"}
    except Exception as e:
        return {"error": str(e)}
    # Aggregate: sum totalTokens / max contextTokens across active sessions
    sessions = data.get("sessions", [])
    if not sessions:
        return {"error": "No active sessions"}
    total_tokens = sum(s.get("totalTokens", 0) for s in sessions)
    ctx_window = max((s.get("contextTokens", 0) for s in sessions), default=0)
    if ctx_window <= 0:
        return {"error": "No context window data"}
    # Most recent session activity
    most_recent = max((s.get("updatedAt", 0) for s in sessions), default=0)
    # Context utilization across active sessions (biggest session's %)
    biggest = max(sessions, key=lambda s: s.get("totalTokens", 0))
    big_total = biggest.get("totalTokens", 0)
    big_ctx = biggest.get("contextTokens", 1)
    util_pct = min(100, round(big_total / big_ctx * 100))
    avail_pct = 100 - util_pct
    if util_pct >= 100:   status = "exhausted"
    elif util_pct >= 90:  status = "rate_limited"
    elif util_pct >= 75:  status = "degraded"
    else:                 status = "available"
    model = biggest.get("model", "")
    provider = biggest.get("modelProvider", "openclaw")
    snap = {
        "agent_id":         agent_id,
        "provider":         provider,
        "captured_at":      datetime.now(timezone.utc).isoformat(),
        "status":           status,
        "usage_percent":    util_pct,
        "window_started_at": None,
        "window_resets_at": None,
        "source_type":      "cli_live",
        "context_tokens":   big_ctx,
        "used_tokens":      big_total,
        "sessions_count":   len(sessions),
        "model":            model,
    }
    USAGE_DIR.mkdir(parents=True, exist_ok=True)
    (USAGE_DIR / f"{agent_id}.json").write_text(
        __import__("json").dumps(snap, indent=2))
    return {"ok": True, "snapshot": snap}


def _hash_agent_key(raw_key: str) -> str:
    # Use scrypt for agent keys (same strength as password hashing)
    salt = hashlib.sha256(b"porter-agent-key-salt").digest()
    h = hashlib.scrypt(raw_key.encode(), salt=salt, n=16384, r=8, p=1, dklen=32)
    return h.hex()

def _hash_agent_key_legacy(raw_key: str) -> str:
    """SHA-256 fallback for pre-v0.24.1 agent keys."""
    return hashlib.sha256(raw_key.encode()).hexdigest()

def _agent_by_id(agent_id: str) -> "dict | None":
    for a in _config.get("agents", []):
        if a.get("id") == agent_id:
            return a
    return None

# ── PEP/1 Phase 1 — Hub config helpers ────────────────────────────────────

PEP_REG_TOKEN_TTL = 900   # 15 minutes
PEP_AGENT_PORT    = 8878  # port agents listen on
PEP_HEARTBEAT_TTL = 180   # seconds before agent considered offline (3 missed @ 60s)
PEP_HOP_LIMIT     = 10    # reject PEP requests forwarded more than this many times
PEP_CB_WINDOW_S   = 60    # circuit-breaker error-rate observation window (seconds)
PEP_CB_ERROR_RATE = 0.30  # fraction of failures that trips the circuit
PEP_CB_MIN_REQS   = 3     # minimum requests in window before circuit can trip
PEP_CB_COOLDOWN_S = 60    # seconds circuit stays open before auto-reset

import threading as _threading
_pep_cb_lock = _threading.Lock()
_pep_cb: dict = {}   # node_id -> {"reqs": [ts,...], "errs": [ts,...], "open_at": float|None}

_metrics_lock = _threading.Lock()
_pep_metrics: dict = {
    "requests": {},   # (op, node_id) -> int
    "errors":   {},   # (op, node_id, code) -> int
    "latencies": [],  # [(op, latency_s), ...] -- capped at 2000
}

_treg_lock = _threading.Lock()
_treg: dict = {}   # task_id -> task dict
# _treg_load() moved to __main__ block — needs _db_init() first

def _hash_pep_token(raw: str) -> str:
    return hashlib.sha256(raw.encode()).hexdigest()

def _pep_agent_by_node(node_id: str) -> "dict | None":
    for a in _config.get("pep_agents", []):
        if a.get("node_id") == node_id:
            return a
    return None

def _pep_agent_by_token(raw_token: str) -> "dict | None":
    h = _hash_pep_token(raw_token)
    for a in _config.get("pep_agents", []):
        if a.get("token_hash") == h:
            return a
    return None

def _pep_cleanup_expired_tokens() -> None:
    now = time.time()
    tokens = [t for t in _config.get("pep_reg_tokens", [])
              if not t.get("used") and t.get("expires_at", 0) > now]
    _config["pep_reg_tokens"] = tokens

def _pep_safe_resolve(allowed_paths: list, req_path: str) -> "Path | None":
    """Resolve and validate req_path against agent's allowed_paths policy."""
    if not req_path or not allowed_paths:
        return None
    try:
        p = Path(req_path).resolve()
    except Exception as e:
        log.warning("Error: %s", e)
        return None
    for ap in allowed_paths:
        try:
            base = Path(ap).resolve()
            p.relative_to(base)
            return p
        except ValueError:
            continue
    return None

def _pep_node_online(node_id: str) -> bool:
    """True if PEP agent for node_id sent a heartbeat within PEP_HEARTBEAT_TTL."""
    agent = _pep_agent_by_node(node_id)
    if not agent:
        return False
    last = agent.get("last_seen", 0)
    return (time.time() - last) < PEP_HEARTBEAT_TTL

def _pep_node_circuit(node_id: str) -> dict:
    """Return circuit breaker snapshot for a node (safe to include in API responses)."""
    now = time.time()
    cutoff = now - PEP_CB_WINDOW_S
    with _pep_cb_lock:
        state = dict(_pep_cb.get(node_id, {}))
        reqs = [t for t in state.get("reqs", []) if t > cutoff]
        errs = [t for t in state.get("errs", []) if t > cutoff]
        is_open = bool(state.get("open_at"))
        resets_in_s = None
        if is_open:
            elapsed = now - state["open_at"]
            resets_in_s = max(0, int(PEP_CB_COOLDOWN_S - elapsed))
    return {
        "state":       "open" if is_open else "closed",
        "resets_in_s": resets_in_s,
        "reqs_1m":     len(reqs),
        "errs_1m":     len(errs),
    }

def _pep_proxy_fs(agent: dict, method: str, sub_path: str,
                  qs: dict, body: dict, hop_count: int = 0) -> "tuple[int, dict]":
    """Forward a FS request to a remote PEP agent. Returns (http_status, response_dict)."""
    import urllib.request, urllib.error
    raw_token = agent.get("_raw_token")  # set transiently after auth
    if not raw_token:
        return 503, {"error": {"code": "AGENT_NO_TOKEN", "message": "Agent token unavailable", "retryable": False}}
    tailscale_ip = agent.get("tailscale_ip", "")
    if not tailscale_ip:
        return 503, {"error": {"code": "NODE_NO_IP", "message": "Agent has no Tailscale IP", "retryable": False}}
    port = agent.get("agent_port", PEP_AGENT_PORT)
    url = f"http://{tailscale_ip}:{port}/pep/v1/fs/local{sub_path}"
    if qs:
        from urllib.parse import urlencode
        url += "?" + urlencode(qs)
    try:
        hop_hdr = str(hop_count + 1)
        if method == "GET":
            req = urllib.request.Request(url, headers={"Authorization": f"Bearer {raw_token}",
                                                        "X-Hop-Count": hop_hdr})
        else:
            payload = json.dumps(body).encode()
            req = urllib.request.Request(url, data=payload,
                headers={"Authorization": f"Bearer {raw_token}",
                         "Content-Type": "application/json",
                         "Content-Length": str(len(payload)),
                         "X-Hop-Count": hop_hdr},
                method=method)
        with urllib.request.urlopen(req, timeout=30) as resp:
            return resp.status, json.loads(resp.read())
    except urllib.error.HTTPError as e:
        try:
            body_err = json.loads(e.read())
        except Exception as e:
            log.warning("Error: %s", e)
            body_err = {"error": {"code": "AGENT_HTTP_ERROR", "message": str(e), "retryable": False}}
        return e.code, body_err
    except Exception as e:
        msg = str(e)[:300]
        code = "NODE_TIMEOUT" if "timed out" in msg.lower() else "NODE_OFFLINE"
        return 503, {"error": {"code": code, "message": msg, "retryable": True}}


_config: dict = {}   # loaded at startup

# ── session helpers ───────────────────────────────────────────────────────

def create_session(username: str, ip: str = None, ua: str = None) -> str:
    token = secrets.token_hex(32)
    expires = time.time() + SESSION_TTL
    try:
        conn = _db_conn()
        conn.execute(
            "INSERT INTO sessions (token, username, expires, ip_address, user_agent) VALUES (?, ?, ?, ?, ?)",
            (token, username, expires, ip, ua)
        )
        conn.commit()
        conn.close()
    except Exception as e:
        log.warning("Session DB write failed, using memory fallback: %s", e)
        _sessions[token] = {"username": username, "expires": expires, "ip": ip, "ua": ua}
    return token

def get_session(token: str, ip: str = None, ua: str = None) -> dict | None:
    # Check memory fallback first
    if token in _sessions:
        s = _sessions[token]
        if time.time() > s["expires"]:
            _sessions.pop(token, None)
            return None
        return s

    try:
        conn = _db_conn()
        now = time.time()
        row = conn.execute("""
            SELECT s.username, s.expires, s.ip_address, s.user_agent, u.role
            FROM sessions s
            LEFT JOIN users u ON s.username = u.username
            WHERE s.token = ?
        """, (token,)).fetchone()
        if not row:
            conn.close()
            return None
        if now > row["expires"]:
            conn.close()
            delete_session(token)
            return None
        
        # Update last_seen_at, and optionally ip/ua if they changed
        if ip or ua:
            conn.execute("UPDATE sessions SET last_seen_at = ?, ip_address = ?, user_agent = ? WHERE token = ?", 
                         (now, ip or row["ip_address"], ua or row["user_agent"], token))
        else:
            conn.execute("UPDATE sessions SET last_seen_at = ? WHERE token = ?", (now, token))
        
        conn.commit()
        conn.close()
        return {
            "username": row["username"], 
            "expires": row["expires"], 
            "ip": row["ip_address"], 
            "ua": row["user_agent"],
            "role": row["role"] or "operator"
        }
    except Exception as e:
        log.debug("Session DB read failed: %s", e)
        return None

def _check_project_access(session, project_id, required_role="member"):
    """Check if session user can access a project at the required role level.
    Role hierarchy: owner > editor > member > viewer.
    Admin users and project owners always pass.
    """
    _ROLE_LEVELS = {"owner": 4, "editor": 3, "member": 2, "viewer": 1}
    required_level = _ROLE_LEVELS.get(required_role, 2)
    if not session or not project_id:
        return False
    username = session.get("username", "")
    user_role = session.get("role", "")
    # Admin users bypass all checks
    if user_role == "admin":
        return True
    # Check project ownership
    proj = _project_by_id(project_id)
    if not proj:
        return False
    if proj.get("owner", "") == username:
        return True
    # Check collaborator role
    try:
        conn = _db_conn()
        row = conn.execute(
            "SELECT role FROM project_collaborators WHERE project_id=? AND username=?",
            (project_id, username)
        ).fetchone()
        conn.close()
        if row:
            collab_level = _ROLE_LEVELS.get(row[0] or "member", 2)
            return collab_level >= required_level
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return False


def _get_session_active_project(token):
    """Get the active_project_id for a specific session (per-user isolation)."""
    try:
        conn = _db_conn()
        row = conn.execute("SELECT active_project_id FROM sessions WHERE token=?", (token,)).fetchone()
        conn.close()
        if row and row[0]:
            return str(row[0]).strip()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Fallback to global config for agent/API requests
    return str(_config.get("active_project_id") or "").strip()


def _set_session_active_project(token, project_id):
    """Set the active_project_id for a specific session."""
    try:
        conn = _db_conn()
        conn.execute("UPDATE sessions SET active_project_id=? WHERE token=?", (project_id or "", token))
        conn.commit()
        conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Also update global config as fallback
    _config["active_project_id"] = project_id or None
    save_config(_config)


def delete_session(token: str) -> None:
    _sessions.pop(token, None)
    try:
        conn = _db_conn()
        conn.execute("DELETE FROM sessions WHERE token = ?", (token,))
        conn.commit()
        conn.close()
    except Exception as e:
        log.debug("Session DB delete failed: %s", e)

# ── runtime / memory helpers ───────────────────────────────────────────────

def porter_uri_to_path(uri: str) -> "Path | None":
    """Resolve a porter:// URI to an absolute Path, blocking traversal."""
    if not isinstance(uri, str) or not uri.startswith("porter://"):
        return None
    rest = uri[len("porter://"):]          # e.g. "runtime/checkpoints/foo" or "projects/bar.md"
    parts = rest.split("/", 1)
    ns = parts[0]
    tail = parts[1] if len(parts) > 1 else ""
    if ns == "runtime":
        base = RUNTIME_DIR
    elif ns in MEMORY_NAMESPACES:
        base = MEMORY_DIR / ns
    else:
        return None
    try:
        if tail:
            resolved = (base / tail).resolve()
        else:
            resolved = base.resolve()
        resolved.relative_to(base.resolve())   # raises ValueError on traversal
        return resolved
    except Exception as e:
        log.warning("Error: %s", e)
        return None

def ensure_runtime_dirs():
    for d in ("checkpoints", "leases", "drafts", "tmp", "usage", "schedule_runs", "idempotency", "logs"):
        (RUNTIME_DIR / d).mkdir(parents=True, exist_ok=True)


