def emit_trace_step(action: str, *, project_id: str = None, agent_id: str = None,
                    agent_name: str = None, stage: str = "execute", task_id: str = None,
                    input_summary: str = None, output_summary: str = None,
                    next_step: str = None, status: str = "running", duration_ms: int = 0,
                    tokens_in: int = 0, tokens_out: int = 0, tokens_cache: int = 0,
                    estimated_cost: float = 0, error: str = None, trace_id: str = None,
                    meta: dict = None):
    """Write a trace step to the trace_steps table + emit to MissionLog."""
    import time as _t
    tid = trace_id or _get_trace_id()
    try:
        conn = _db_conn()
        conn.execute(
            """INSERT INTO trace_steps (ts, trace_id, project_id, agent_id, agent_name,
               stage, task_id, input_summary, action, output_summary, next_step, status,
               duration_ms, tokens_in, tokens_out, tokens_cache, estimated_cost, error, meta)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (_t.time(), tid, project_id, agent_id, agent_name, stage, task_id,
             input_summary, action, output_summary, next_step, status,
             duration_ms, tokens_in, tokens_out, tokens_cache, estimated_cost, error,
             json.dumps(meta or {}))
        )
        conn.commit()
        conn.close()
    except Exception as e:
        log.debug("emit_trace_step error: %s", e)

    # Also emit to MissionLog for SSE broadcast
    mlog.emit("info", "trace", "step",
              f"{agent_name or 'unknown'}: {action}" + (f" [{status}]" if status != "running" else ""),
              trace_id=tid, run_id=task_id,
              extra={"project_id": project_id, "agent_id": agent_id, "stage": stage,
                     "tokens_in": tokens_in, "tokens_out": tokens_out})


def record_telemetry(*, project_id: str = None, agent_id: str = None,
                     agent_name: str = None, status: str = "complete",
                     tokens_in: int = 0, tokens_out: int = 0, tokens_cache: int = 0,
                     estimated_cost: float = 0, latency_ms: int = 0,
                     retries: int = 0, blocker_reason: str = None,
                     backend: str = None, action: str = None,
                     trace_id: str = None, run_id: str = None,
                     safety_class: str = "normal"):
    """Record a telemetry event for agent utilization tracking."""
    import time as _t
    eid = secrets.token_hex(8)
    tid = trace_id or _get_trace_id()
    try:
        conn = _db_conn()
        conn.execute(
            """INSERT INTO agent_telemetry (ts, event_id, trace_id, run_id, project_id,
               agent_id, agent_name, status, tokens_in, tokens_out, tokens_cache,
               estimated_cost, latency_ms, retries, blocker_reason, backend, action, safety_class)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (_t.time(), eid, tid, run_id, project_id, agent_id, agent_name, status,
             tokens_in, tokens_out, tokens_cache, estimated_cost, latency_ms,
             retries, blocker_reason, backend, action, safety_class)
        )
        conn.commit()
        conn.close()
    except Exception as e:
        log.debug("record_telemetry error: %s", e)


def _rollup_hourly():
    """Materialize hourly telemetry rollups from raw agent_telemetry events."""
    import time as _t, statistics
    now = _t.time()
    hour_start = now - (now % 3600) - 3600  # Previous complete hour
    hour_end = hour_start + 3600

    try:
        conn = _db_conn()
        # Check if we already have this hour's rollup
        existing = conn.execute(
            "SELECT COUNT(*) FROM telemetry_hourly WHERE hour_ts=?", (hour_start,)
        ).fetchone()[0]
        if existing > 0:
            conn.close()
            return  # Already rolled up

        # Aggregate per agent+project
        rows = conn.execute(
            """SELECT project_id, agent_id, agent_name, status, tokens_in, tokens_out,
                      tokens_cache, estimated_cost, latency_ms, retries
               FROM agent_telemetry WHERE ts >= ? AND ts < ?""",
            (hour_start, hour_end)
        ).fetchall()
        conn.close()

        if not rows:
            return

        # Group by (project_id, agent_id)
        groups = {}
        for r in rows:
            key = (r[0], r[1], r[2])  # project_id, agent_id, agent_name
            groups.setdefault(key, []).append(r)

        conn = _db_conn()
        for (pid, aid, aname), events in groups.items():
            complete = sum(1 for e in events if e[3] == "complete")
            failed = sum(1 for e in events if e[3] == "failed")
            blocked = sum(1 for e in events if e[3] == "blocked")
            tin = sum(e[4] or 0 for e in events)
            tout = sum(e[5] or 0 for e in events)
            tcache = sum(e[6] or 0 for e in events)
            cost = sum(e[7] or 0 for e in events)
            latencies = [e[8] for e in events if e[8] and e[8] > 0]
            retries = sum(e[9] or 0 for e in events)
            active_s = sum((e[8] or 0) / 1000 for e in events)

            p50 = int(statistics.median(latencies)) if latencies else 0
            p95 = int(sorted(latencies)[int(len(latencies) * 0.95)] if latencies else 0)
            lmax = max(latencies) if latencies else 0
            throughput = len(events) / 3600.0

            conn.execute(
                """INSERT INTO telemetry_hourly (hour_ts, project_id, agent_id, agent_name,
                   active_seconds, task_complete, task_failed, task_blocked,
                   tokens_in_total, tokens_out_total, tokens_cache_total, cost_total,
                   latency_p50, latency_p95, latency_max, throughput, retries_total)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                (hour_start, pid, aid, aname, active_s, complete, failed, blocked,
                 tin, tout, tcache, cost, p50, p95, lmax, throughput, retries)
            )
        conn.commit()
        conn.close()
        log.info("Hourly telemetry rollup complete: %d groups", len(groups))
    except Exception as e:
        log.error("Hourly rollup error: %s", e)


def _rollup_daily():
    """Materialize daily telemetry rollups from hourly rollups."""
    import time as _t
    now = _t.time()
    day_start = now - (now % 86400) - 86400  # Previous complete day
    day_end = day_start + 86400

    try:
        conn = _db_conn()
        existing = conn.execute(
            "SELECT COUNT(*) FROM telemetry_daily WHERE day_ts=?", (day_start,)
        ).fetchone()[0]
        if existing > 0:
            conn.close()
            return

        rows = conn.execute(
            """SELECT project_id, agent_id, agent_name,
                      SUM(active_seconds), SUM(task_complete), SUM(task_failed), SUM(task_blocked),
                      SUM(tokens_in_total), SUM(tokens_out_total), SUM(tokens_cache_total),
                      SUM(cost_total), AVG(latency_p50), MAX(latency_p95), MAX(latency_max),
                      AVG(throughput), SUM(retries_total)
               FROM telemetry_hourly WHERE hour_ts >= ? AND hour_ts < ?
               GROUP BY project_id, agent_id""",
            (day_start, day_end)
        ).fetchall()
        conn.close()

        if not rows:
            return

        conn = _db_conn()
        for r in rows:
            total_tasks = (r[4] or 0) + (r[5] or 0) + (r[6] or 0)
            efficiency = (r[4] or 0) / total_tasks if total_tasks > 0 else 0

            conn.execute(
                """INSERT INTO telemetry_daily (day_ts, project_id, agent_id, agent_name,
                   active_seconds, task_complete, task_failed, task_blocked,
                   tokens_in_total, tokens_out_total, tokens_cache_total, cost_total,
                   latency_p50, latency_p95, latency_max, throughput, retries_total,
                   efficiency_score)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                (day_start, r[0], r[1], r[2], r[3], r[4], r[5], r[6],
                 r[7], r[8], r[9], r[10], int(r[11] or 0), int(r[12] or 0),
                 int(r[13] or 0), r[14] or 0, r[15] or 0, efficiency)
            )
        conn.commit()
        conn.close()
        log.info("Daily telemetry rollup complete: %d groups", len(rows))
    except Exception as e:
        log.error("Daily rollup error: %s", e)


def _detect_anomalies():
    """v0.30.34 — Anomaly detection: compare latest hourly rollup against 7-day baselines.
    Flags when latency, token usage, or failure rate exceed 2x the rolling average."""
    import time as _adt
    try:
        conn = _db_conn()
        now = _adt.time()
        # Get the latest completed hour
        latest_hour = conn.execute(
            "SELECT MAX(hour_ts) FROM telemetry_hourly"
        ).fetchone()[0]
        if not latest_hour:
            conn.close()
            return
        # 7-day baseline window (168 hours)
        baseline_start = latest_hour - (7 * 86400)
        # Get baselines per agent: avg latency_p50, avg tokens, avg failure rate
        baselines = conn.execute(
            "SELECT agent_id, agent_name, "
            "AVG(latency_p50) as avg_lat, AVG(tokens_out_total) as avg_tokens, "
            "AVG(CASE WHEN (task_complete + task_failed) > 0 "
            "  THEN CAST(task_failed AS REAL) / (task_complete + task_failed) ELSE 0 END) as avg_fail_rate, "
            "COUNT(*) as sample_count "
            "FROM telemetry_hourly WHERE hour_ts >= ? AND hour_ts < ? "
            "GROUP BY agent_id HAVING sample_count >= 3",
            (baseline_start, latest_hour)
        ).fetchall()
        if not baselines:
            conn.close()
            return
        # Get latest hour data per agent
        latest = {}
        for row in conn.execute(
            "SELECT agent_id, agent_name, latency_p50, latency_p95, "
            "tokens_out_total, task_complete, task_failed, retries_total "
            "FROM telemetry_hourly WHERE hour_ts = ?", (latest_hour,)
        ).fetchall():
            latest[row[0]] = dict(row)
        conn.close()
        anomalies = []
        for bl in baselines:
            agent_id = bl[0]
            agent_name = bl[1] or agent_id[:8]
            avg_lat = bl[2] or 0
            avg_tokens = bl[3] or 0
            avg_fail = bl[4] or 0
            samples = bl[5]
            cur = latest.get(agent_id)
            if not cur:
                continue
            # Latency anomaly: p50 > 2x baseline
            if avg_lat > 0 and (cur.get("latency_p50") or 0) > avg_lat * 2:
                anomalies.append({
                    "agent_id": agent_id, "agent_name": agent_name,
                    "metric": "latency_p50", "type": "spike",
                    "current": cur.get("latency_p50"), "baseline": round(avg_lat),
                    "ratio": round((cur.get("latency_p50") or 0) / avg_lat, 1),
                    "detail": f"{agent_name} latency {cur.get('latency_p50')}ms vs {round(avg_lat)}ms avg (7d)"
                })
            # Token usage anomaly: > 2x baseline
            if avg_tokens > 100 and (cur.get("tokens_out_total") or 0) > avg_tokens * 2:
                anomalies.append({
                    "agent_id": agent_id, "agent_name": agent_name,
                    "metric": "tokens_out", "type": "spike",
                    "current": cur.get("tokens_out_total"), "baseline": round(avg_tokens),
                    "ratio": round((cur.get("tokens_out_total") or 0) / avg_tokens, 1),
                    "detail": f"{agent_name} tokens {cur.get('tokens_out_total')} vs {round(avg_tokens)} avg (7d)"
                })
            # Failure rate anomaly: > 2x baseline (min 2 failures)
            total = (cur.get("task_complete") or 0) + (cur.get("task_failed") or 0)
            cur_fail_rate = (cur.get("task_failed") or 0) / total if total > 0 else 0
            if avg_fail > 0 and cur_fail_rate > avg_fail * 2 and (cur.get("task_failed") or 0) >= 2:
                anomalies.append({
                    "agent_id": agent_id, "agent_name": agent_name,
                    "metric": "failure_rate", "type": "spike",
                    "current": round(cur_fail_rate, 2), "baseline": round(avg_fail, 2),
                    "ratio": round(cur_fail_rate / avg_fail, 1) if avg_fail > 0 else 0,
                    "detail": f"{agent_name} failure rate {round(cur_fail_rate*100)}% vs {round(avg_fail*100)}% avg (7d)"
                })
            # Retry anomaly: >5 retries in one hour is unusual
            if (cur.get("retries_total") or 0) > 5:
                anomalies.append({
                    "agent_id": agent_id, "agent_name": agent_name,
                    "metric": "retries", "type": "spike",
                    "current": cur.get("retries_total"), "baseline": 0,
                    "detail": f"{agent_name} had {cur.get('retries_total')} retries this hour"
                })
        # Report anomalies
        if anomalies:
            summary = f"Anomaly detection: {len(anomalies)} anomalies found"
            details = "; ".join(a["detail"] for a in anomalies[:5])
            mlog.emit("warn", "telemetry", "anomaly.detected", f"{summary}: {details}")
            _emit_event("telemetry:anomalies", {"anomalies": anomalies, "hour_ts": latest_hour})
            log.warning("Telemetry anomalies: %s", details)
            # Feed into AlertEngine for auto-remediation consideration
            for a in anomalies:
                if a["metric"] == "failure_rate" and a.get("ratio", 0) > 3:
                    mlog.emit("error", "telemetry", "anomaly.critical",
                        f"Critical: {a['detail']}")
            # v0.30.40 — Self-dispatch: react to anomalies
            try:
                _self_dispatch_on_anomaly(anomalies)
            except Exception as _e:
                mlog.emit("warn", "system", "exception.swallowed",
                          f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        else:
            log.debug("Anomaly detection: no anomalies (checked %d agents)", len(baselines))
    except Exception as e:
        log.debug("Anomaly detection error: %s", e)


def _telemetry_rollup_loop():
    """Background thread: runs hourly + daily rollups."""
    import time as _t
    with _wf_lock:
        _wf_registry["telemetry_rollup"]["started_at"] = _t.time()
    while True:
        _t.sleep(3600)  # Run every hour
        if not _wf_is_enabled("telemetry_rollup"):
            continue
        _wf_start_run("telemetry_rollup")
        _t0 = _t.time()
        try:
            _rollup_hourly()
            # v0.30.34 — Run anomaly detection after hourly rollup
            try:
                _detect_anomalies()
            except Exception as _ae:
                log.debug("Anomaly detection failed: %s", _ae)
            # Daily rollup at midnight-ish
            hour = int((_t.time() % 86400) / 3600)
            if hour == 0:
                _rollup_daily()
            _wf_record_run("telemetry_rollup", success=True, result="rollup complete", duration_s=_t.time()-_t0)
        except Exception as e:
            log.error("Telemetry rollup loop error: %s", e)
            _wf_record_run("telemetry_rollup", success=False, error=e, duration_s=_t.time()-_t0)


def _append_audit(action: str, target: str, actor: str,
                  actor_type: str = "session", details: dict | None = None,
                  project_id: str | None = None, session_id: str | None = None,
                  scope_source: str | None = None, chain_ref: str | None = None) -> None:
    from datetime import datetime, timezone
    entry = {
        "ts":         time.time(),
        "ts_iso":     datetime.now(timezone.utc).isoformat(),
        "actor":      actor,
        "actor_type": actor_type,
        "action":     action,
        "target":     target,
        "details":    details or {},
    }
    if project_id:  entry["project_id"]  = project_id
    if session_id:  entry["session_id"]  = session_id
    if scope_source: entry["scope_source"] = scope_source
    if chain_ref:   entry["chain_ref"]   = chain_ref
    RUNTIME_DIR.mkdir(parents=True, exist_ok=True)
    try:
        with open(AUDIT_LOG, "a") as f:
            f.write(json.dumps(entry) + "\n")
    except Exception as e:
        log.debug("Ignored: %s", e)  # audit failures must never break callers
    # v0.31.73 — Dual-write to SQLite
    try:
        _ac = _db_conn()
        _ac.execute(
            "INSERT INTO audit_log (ts, ts_iso, actor, actor_type, action, target, details, project_id, session_id, ip_address) "
            "VALUES (?,?,?,?,?,?,?,?,?,?)",
            (entry["ts"], entry["ts_iso"], entry["actor"], entry["actor_type"],
             entry["action"], entry["target"], json.dumps(entry.get("details", {})),
             entry.get("project_id"), entry.get("session_id"),
             entry.get("details", {}).get("ip") or entry.get("ip_address"))
        )
        _ac.commit()
        _ac.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
