def _safe_lease_running(lease_file, agent_id: str, now: float) -> bool:
    try:
        l = json.loads(Path(lease_file).read_text())
        return (l.get("owner") == agent_id and
                l.get("state") == "running" and
                l.get("expires_at", 0) > now)
    except Exception as e:
        log.warning("Error: %s", e)
        return False


def _smart_chat_title(user_msg, persona_name=""):
    """Generate a smart title: persona prefix + trimmed message."""
    import re
    msg = user_msg or ""
    # Strip context prefixes that get prepended to prompts
    msg = re.sub(r'^Conversation history:.*?New message:\s*', '', msg, flags=re.DOTALL).strip()
    msg = re.sub(r'^Context files:.*?User message:\s*', '', msg, flags=re.DOTALL).strip()
    msg = re.sub(r'^You are \w+\..*?---\s*', '', msg, flags=re.DOTALL).strip()
    # Strip @mentions and /commands
    msg = re.sub(r'@\w+', '', msg).strip()
    msg = re.sub(r'^/\w+\s*', '', msg).strip()
    # Remove filler words from start
    msg = re.sub(r'^(hey|hi|hello|please|can you|could you|help me|i want to|i need to|i\'d like to|tell me about|what is|what are)\s+', '', msg, flags=re.IGNORECASE).strip()
    # Remove trailing punctuation clutter
    msg = msg.strip('.,!? ')
    # Capitalize first letter
    if msg:
        msg = msg[0].upper() + msg[1:]
    # Truncate to ~50 chars at word boundary
    if len(msg) > 50:
        msg = msg[:47].rsplit(' ', 1)[0] + '...'
    if not msg:
        msg = 'New chat'
    # Prefix with persona name if present
    if persona_name:
        return persona_name + ': ' + msg
    return msg

def _save_chat_message(chat_id, model_id, user_msg, assistant_msg, project_id="", persona_name=""):
    """Append a message pair to a chat session in SQLite."""
    try:
        conn = _db_conn()
        now = time.time()
        # Check if chat exists, if not create it
        res = conn.execute("SELECT 1 FROM chats WHERE id = ?", (chat_id,)).fetchone()
        if not res:
            title = _smart_chat_title(user_msg, persona_name)
            _meta_dict = {}
            if persona_name:
                _meta_dict["persona_name"] = persona_name
            # v0.28.22 — save full dispatch context
            if model_id:
                _meta_dict["model"] = model_id
            if project_id:
                _meta_dict["project_id"] = project_id
            _meta = json.dumps(_meta_dict) if _meta_dict else "{}"
            conn.execute("""
                INSERT INTO chats (id, title, model_id, project_id, created_at, updated_at, metadata)
                VALUES (?, ?, ?, ?, ?, ?, ?)
            """, (chat_id, title, model_id, project_id or None, now, now, _meta))
        else:
            # Update metadata with current context
            _upd_meta = {}
            try:
                _meta_row = conn.execute("SELECT metadata FROM chats WHERE id = ?", (chat_id,)).fetchone()
                if _meta_row and _meta_row[0]:
                    _upd_meta = json.loads(_meta_row[0] or "{}")
            except Exception:
                _upd_meta = {}
            if persona_name:
                _upd_meta["persona_name"] = persona_name
            if model_id:
                _upd_meta["model"] = model_id
            if project_id:
                _upd_meta["project_id"] = project_id
            conn.execute("UPDATE chats SET updated_at = ?, model_id = ?, metadata = ? WHERE id = ?",
                        (now, model_id, json.dumps(_upd_meta) if _upd_meta else None, chat_id))
        
        # Insert messages
        conn.execute("INSERT INTO chat_messages (chat_id, role, content, timestamp, model_id) VALUES (?, ?, ?, ?, ?)",
                     (chat_id, "user", user_msg, now, model_id))
        conn.execute("INSERT INTO chat_messages (chat_id, role, content, timestamp, model_id) VALUES (?, ?, ?, ?, ?)",
                     (chat_id, "assistant", assistant_msg, now, model_id))
        conn.commit()
        conn.close()
    except Exception as e:
        log.warning("Chat save failed: %s", e)

def _chat_metadata(chat_id):
    try:
        cid = str(chat_id or "").strip()
        if not cid:
            return {}
        conn = _db_conn()
        row = conn.execute("SELECT metadata FROM chats WHERE id = ?", (cid,)).fetchone()
        conn.close()
        if not row or not row[0]:
            return {}
        return json.loads(row[0] or "{}")
    except Exception as e:
        log.debug("chat metadata load failed for %s: %s", chat_id, e)
        return {}

def _chat_update_metadata(chat_id, patch):
    try:
        cid = str(chat_id or "").strip()
        patch = dict(patch or {})
        if not cid or not patch:
            return
        conn = _db_conn()
        row = conn.execute("SELECT metadata FROM chats WHERE id = ?", (cid,)).fetchone()
        current = {}
        if row and row[0]:
            try:
                current = json.loads(row[0] or "{}")
            except Exception:
                current = {}
        current.update({k: v for k, v in patch.items() if v not in (None, "")})
        conn.execute("UPDATE chats SET metadata = ?, updated_at = ? WHERE id = ?",
                     (json.dumps(current), time.time(), cid))
        conn.commit()
        conn.close()
    except Exception as e:
        log.debug("chat metadata update failed for %s: %s", chat_id, e)

def _merge_stream_text(existing: str, chunk: str) -> str:
    base = str(existing or "")
    frag = str(chunk or "")
    if not frag:
        return base
    if not base:
        return frag
    if base.endswith((" ", "\n", "\t", "(", "[", "{", "/", "-", "—")):
        return base + frag
    if frag.startswith((" ", "\n", "\t", ".", ",", "!", "?", ";", ":", ")", "]", "}", "/", "-", "—")):
        return base + frag
    if base.endswith((".", "!", "?", ":", ";", ",")):
        return base + " " + frag
    if base[-1].isalnum() and frag[:1].isalnum():
        return base + " " + frag
    return base + frag

def ensure_chat_dirs():
    CHAT_DIR.mkdir(parents=True, exist_ok=True)

def ensure_memory_dirs():
    for ns in MEMORY_NAMESPACES:
        (MEMORY_DIR / ns).mkdir(parents=True, exist_ok=True)

def ensure_persona_dirs():
    """Create personas directory and RULES.md if missing."""
    PERSONAS_DIR.mkdir(parents=True, exist_ok=True)
    rules_path = PERSONAS_DIR / "RULES.md"
    if not rules_path.exists():
        rules_path.write_text("# Global Rules\n\nAll personas must follow these rules.\n\n" +
                              "\n".join(f"- {r.get('text', '')}" for r in _config.get("rules", [])) + "\n")


def _persona_is_locked(persona: dict | None) -> bool:
    return bool(persona and int(persona.get("is_locked") or 0))


def _persona_is_public(persona: dict | None) -> bool:
    return bool(persona and int(persona.get("is_public", 1) or 0))


def _persona_is_orchestrator_only(persona: dict | None) -> bool:
    return bool(persona and int(persona.get("orchestrator_only") or 0))


def _persona_role_family(persona: dict | None) -> str:
    if not persona:
        return "general"
    text = " ".join([
        str(persona.get("name", "") or ""),
        str(persona.get("role", "") or ""),
        str(persona.get("agent_group", "") or ""),
    ]).lower()
    if bool(persona.get("orchestrator_only")) or re.search(r"porter|orchestrat|director|chief of staff|command", text):
        return "orchestrator"
    if re.search(r"joke|comed|humou?r|funny|comic", text):
        return "comedy"
    if re.search(r"writer|copy|content|editor|story|script|social|marketing", text):
        return "writing"
    if re.search(r"research|analy|investig|insight|briefing|intelligence", text):
        return "research"
    if re.search(r"design|ux|ui|brand|visual|creative|art", text):
        return "design"
    if re.search(r"qa|quality|test|review|bug", text):
        return "qa"
    if re.search(r"engineer|developer|backend|frontend|full.?stack|software|code", text):
        return "engineering"
    if re.search(r"trading|finance|market|risk|portfolio|bitcoin|crypto|fund", text):
        return "finance"
    if re.search(r"ops|operations|coordinator|scheduler|operator|producer|project", text):
        return "operations"
    if re.search(r"sales|support|success|community|customer|crm|investor", text):
        return "relationship"
    return "general"


def _persona_character_label(persona: dict | None) -> str:
    return {
        "orchestrator": "Orchestrator",
        "comedy": "Comedian",
        "writing": "Writer",
        "research": "Researcher",
        "design": "Designer",
        "qa": "Reviewer",
        "engineering": "Builder",
        "finance": "Analyst",
        "operations": "Operator",
        "relationship": "Liaison",
        "general": "Specialist",
    }.get(_persona_role_family(persona), "Specialist")


