def _norm_skill_name(name: str | None) -> str:
    return str(name or "").strip().lower().replace("_", "-")


def _porter_skill_profile(available_skills: list[dict] | None = None) -> dict:
    skills = available_skills if available_skills is not None else _load_openclaw_skills()
    by_norm: dict[str, dict] = {}
    for sk in skills or []:
        for raw in (sk.get("id"), sk.get("name")):
            norm = _norm_skill_name(raw)
            if norm and norm not in by_norm:
                by_norm[norm] = sk

    def _entry(name: str, tier: str) -> dict | None:
        sk = by_norm.get(_norm_skill_name(name))
        skill_name = str((sk or {}).get("name") or (sk or {}).get("id") or name).strip()
        return {
            "id": str((sk or {}).get("id") or skill_name),
            "name": skill_name,
            "description": str((sk or {}).get("description") or "").strip(),
            "purpose": _PORTER_SKILL_PURPOSE.get(_norm_skill_name(name), ""),
            "tier": tier,
            "installed": bool((sk or {}).get("installed") or (sk or {}).get("manual") or bool(_PORTER_SKILL_PURPOSE.get(_norm_skill_name(name), ""))),
            "path": str((sk or {}).get("path") or ""),
        }

    core = [item for item in (_entry(name, "core") for name in _PORTER_PRIMARY_SKILLS) if item]
    internal = [item for item in (_entry(name, "internal") for name in _PORTER_INTERNAL_SKILLS) if item]
    reserve = [item for item in (_entry(name, "reserve") for name in _PORTER_RESERVE_SKILLS) if item]
    covered = {_norm_skill_name(item["id"]) for item in core + internal + reserve}
    available = []
    for sk in skills or []:
        sid = _norm_skill_name(sk.get("id") or sk.get("name"))
        if not sid or sid in covered:
            continue
        available.append({
            "id": str(sk.get("id") or sk.get("name") or ""),
            "name": str(sk.get("name") or sk.get("id") or ""),
            "description": str(sk.get("description") or "").strip(),
            "purpose": _PORTER_SKILL_PURPOSE.get(sid, ""),
            "tier": "available",
            "installed": bool(sk.get("installed") or sk.get("manual")),
            "path": str(sk.get("path") or ""),
        })
    return {
        "core": core,
        "internal": internal,
        "reserve": reserve,
        "available": available,
        "available_count": len(skills or []),
    }


def _ensure_porter_skill_profile() -> None:
    try:
        profile = _porter_skill_profile()
        target = [str(item.get("name") or "").strip() for item in (profile.get("core", []) + profile.get("internal", [])) if str(item.get("name") or "").strip()]
        if not target:
            return
        current = _persona_get_skill_names(PORTER_PERSONA_ID)
        if current != target:
            _persona_set_skill_names(PORTER_PERSONA_ID, target, managed_by_porter=True)
    except Exception as e:
        log.warning("Porter skill profile sync failed: %s", e)


def _appearance_palette_for_persona(name: str = "", role: str = "", temporary: bool = False) -> dict:
    seeds = [
        {"skin": "#f1c27d", "hair": "#2f4858", "shirt": "#2b6cb0", "accent": "#f6ad55", "eyes": "#1a202c"},
        {"skin": "#e0ac69", "hair": "#6b4f3a", "shirt": "#2f855a", "accent": "#f6e05e", "eyes": "#111827"},
        {"skin": "#c68642", "hair": "#1f2937", "shirt": "#7c3aed", "accent": "#f97316", "eyes": "#0f172a"},
        {"skin": "#8d5524", "hair": "#f8fafc", "shirt": "#b45309", "accent": "#22c55e", "eyes": "#111827"},
        {"skin": "#ffdbac", "hair": "#4a2500", "shirt": "#1e6f5c", "accent": "#29bb89", "eyes": "#2d2d2d"},
        {"skin": "#c49a6c", "hair": "#0d0d0d", "shirt": "#364f6b", "accent": "#52b2cf", "eyes": "#111111"},
        {"skin": "#f5cba7", "hair": "#8b4513", "shirt": "#7b2d26", "accent": "#d4a05a", "eyes": "#1c1c1c"},
        {"skin": "#6f4e37", "hair": "#2c1810", "shirt": "#4a6741", "accent": "#a8d08d", "eyes": "#0a0a0a"},
    ]
    raw = f"{name}|{role}|{int(temporary)}"
    idx = sum(ord(ch) for ch in raw) % len(seeds)
    palette = dict(seeds[idx])
    role_l = str(role or "").lower()
    if re.search(r"qa|test|quality|bug", role_l):
        palette["shirt"] = "#0f766e"
        palette["accent"] = "#22c55e"
    elif re.search(r"design|creative|ux|brand", role_l):
        palette["shirt"] = "#be185d"
        palette["accent"] = "#fb7185"
    elif re.search(r"research|analyst|strategy", role_l):
        palette["shirt"] = "#4338ca"
        palette["accent"] = "#38bdf8"
    elif re.search(r"release|ops|infra|deploy|sre", role_l):
        palette["shirt"] = "#374151"
        palette["accent"] = "#f59e0b"
    elif re.search(r"finance|market|crypto|trade", role_l):
        palette["shirt"] = "#14532d"
        palette["accent"] = "#10b981"
    if temporary:
        palette["accent"] = "#f59e0b"
    return palette


def _default_appearance_spec(name: str = "", role: str = "", temporary: bool = False) -> dict:
    palette = _appearance_palette_for_persona(name, role, temporary)
    role_l = str(role or "").lower()
    seed_val = sum(ord(ch) for ch in f"{name}|{role}")
    body_type = "slim" if seed_val % 2 == 0 else "broad"
    hair_broad = ["crop", "buzz", "spiky"]
    hair_slim = ["long", "bob", "ponytail", "crop"]
    hair_style = (hair_slim if body_type == "slim" else hair_broad)[seed_val % (4 if body_type == "slim" else 3)]
    accessory = "visor"
    archetype = "operator"
    role_marker = "command-badge"
    if re.search(r"qa|test|quality", role_l):
        accessory = "monocle"
        archetype = "auditor"
        role_marker = "check-grid"
    elif re.search(r"design|creative|ux", role_l):
        accessory = "headband"
        archetype = "maker"
        role_marker = "palette-band"
    elif re.search(r"research|analyst|strategy", role_l):
        accessory = "headset"
        archetype = "navigator"
        role_marker = "signal-lens"
    elif re.search(r"release|ops|infra|deploy|sre", role_l):
        accessory = "helmet"
        archetype = "warden"
        role_marker = "ops-crest"
    elif re.search(r"finance|market|crypto|trade", role_l):
        accessory = "visor"
        archetype = "broker"
        role_marker = "market-stripe"
    return {
        "system": "porter-avatar",
        "renderer": "porter-pixel-v1",
        "style": "minecraft",
        "palette": palette,
        "body_type": body_type,
        "hair_style": hair_style,
        "archetype": archetype,
        "outfit": "operator-jacket" if not temporary else "task-contractor",
        "accessory": accessory,
        "role_marker": role_marker,
        "temperament": "steady" if not temporary else "expeditionary",
        "temporary": bool(temporary),
    }


