def _dispatch_openclaw(message, model=None, timeout=120, agent_id=None):
    """Invoke OpenClaw agent CLI and return normalized response.
    Supports multi-agent routing — pass agent_id to target a specific agent."""
    import subprocess
    oc_bin = _resolve_cli("openclaw")
    if not oc_bin:
        return {"ok": False, "error": "openclaw CLI not found. Install: npm i -g openclaw"}
    agent_id = agent_id or "main"
    cmd = [oc_bin, "agent", "--agent", agent_id, "--message", message, "--json", "--timeout", str(timeout)]
    log.info("Agent bridge [openclaw]: agent=%s requested_model=%s msg=%s", agent_id, model or "", message[:80])
    result = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout + 10, env=_agent_env(), cwd=str(Path.home()))
    if result.returncode != 0:
        return {"ok": False, "error": result.stderr[:500] or "OpenClaw returned non-zero"}
    try:
        resp = json.loads(result.stdout)
    except (json.JSONDecodeError, ValueError):
        # Not JSON — return raw text
        return {"ok": True, "backend": "openclaw", "text": result.stdout.strip(),
                "model": "gpt-5.4", "duration_ms": 0, "tokens": {},
                "bridge": _bridge_runtime_semantics("openclaw", model)}
    # Extract text from multiple possible locations
    text = ""
    payloads = resp.get("result", {}).get("payloads", [])
    if payloads and isinstance(payloads, list):
        text = payloads[0].get("text", "") if isinstance(payloads[0], dict) else ""
    if not text:
        text = resp.get("result", {}).get("text", "")
    if not text:
        text = resp.get("text", "")
    if not text:
        # Last resort: try summary
        text = resp.get("summary", "") or resp.get("status", "No response text")
    meta = resp.get("result", {}).get("meta", {})
    return {
        "ok": True, "backend": "openclaw",
        "text": text,
        "run_id": resp.get("runId", ""),
        "model": meta.get("agentMeta", {}).get("model", "gpt-5.4"),
        "duration_ms": meta.get("durationMs", 0),
        "tokens": meta.get("agentMeta", {}).get("usage", {}),
        "bridge": _bridge_runtime_semantics("openclaw", model),
    }

def _dispatch_gemini(message, model=None, timeout=120):
    """Invoke Gemini CLI and return normalized response."""
    import subprocess
    gem_bin = _resolve_cli("gemini")
    if not gem_bin:
        return {"ok": False, "error": "Gemini CLI not found. Install: npm i -g @google/gemini-cli"}
    # Trim message to avoid timeouts on huge conversation histories
    if len(message) > 4000:
        message = message[-4000:]
    # Use -o text (not json) — Gemini CLI v0.31+ hangs with -o json
    cmd = [gem_bin, "-p", message, "-o", "text", "-y"]
    if model and model != "auto":
        cmd.extend(["-m", model])
    log.info("Agent bridge [gemini]: model=%s msg=%s", model or "auto", message[:80])
    _start = time.time()
    result = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout + 10, env=_agent_env(), cwd=str(Path.home()))
    _elapsed_ms = int((time.time() - _start) * 1000)
    if result.returncode != 0:
        err_msg = result.stderr[:300] or result.stdout[:300] or "Gemini returned non-zero"
        return {"ok": False, "error": err_msg}
    # Text output: strip YOLO mode banners and credential messages
    text = result.stdout
    _skip = ("YOLO mode", "Loaded cached", "Loaded saved", "[WARN]", "[ERROR]", "Warning:", "Error:")
    lines = text.split("\n")
    lines = [l for l in lines if not any(l.strip().startswith(s) for s in _skip)]
    text = "\n".join(lines).strip()
    return {
        "ok": True, "backend": "gemini",
        "text": text,
        "model": model or "gemini",
        "duration_ms": _elapsed_ms,
        "tokens": {"total": 0},
        "bridge": _bridge_runtime_semantics("gemini", model or "gemini"),
    }


def _dispatch_claude(message, model=None, timeout=180):
    """Invoke Claude Code CLI (claude -p) and return normalized response."""
    import subprocess
    cl_bin = _resolve_cli("claude")
    if not cl_bin:
        return {"ok": False, "error": "Claude CLI not found. Install: npm i -g @anthropic-ai/claude-code"}
    cmd = [cl_bin, "-p", "--output-format", "json", message]
    if model:
        cmd.extend(["--model", model])
    log.info("Agent bridge [claude]: msg=%s", message[:80])
    result = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout + 10, env=_agent_env(), cwd=str(Path.home()))
    if result.returncode != 0:
        return {"ok": False, "error": (result.stderr or "Claude CLI returned non-zero")[:500]}
    # Parse JSON output
    try:
        resp = json.loads(result.stdout)
        text = resp.get("result", "") or resp.get("response", "") or resp.get("content", "")
        if not text and isinstance(resp, dict):
            # Try to find text in nested structure
            for key in ("text", "message", "output"):
                if key in resp:
                    text = resp[key]
                    break
        if not text:
            text = result.stdout.strip()
        usage = resp.get("usage", {})
    except (json.JSONDecodeError, ValueError):
        text = result.stdout.strip()
        usage = {}
    return {
        "ok": True, "backend": "claude",
        "text": text,
        "model": model or "claude-code",
        "duration_ms": 0,
        "tokens": {"input": usage.get("input_tokens", 0), "output": usage.get("output_tokens", 0)},
        "bridge": _bridge_runtime_semantics("claude", model or "claude-code"),
    }

def _dispatch_codex(message, model=None, timeout=120):
    """Invoke OpenAI Codex CLI (codex exec) and return normalized response."""
    import subprocess
    cdx_bin = _resolve_cli("codex")
    if not cdx_bin:
        return {"ok": False, "error": "Codex CLI not found. Install: npm i -g @openai/codex"}
    codex_model = (model or os.environ.get("PORTER_CODEX_MODEL", "").strip() or "gpt-5.4")
    cmd = [cdx_bin, "exec", "--ephemeral", "--json", "--skip-git-repo-check", "-m", codex_model, message]
    log.info("Agent bridge [codex]: model=%s msg=%s", codex_model, message[:80])
    result = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout + 10, env=_agent_env(), cwd=str(Path.home()))
    # Parse JSONL output — extract assistant text and usage
    text = ""
    usage = {}
    errors = []
    for line in (result.stdout or "").strip().split("\n"):
        if not line.strip():
            continue
        try:
            evt = json.loads(line)
            if evt.get("type") == "item.completed":
                item = evt.get("item", {})
                if item.get("type") == "agent_message":
                    msg_text = item.get("text", "") or ""
                    if not msg_text:
                        parts = []
                        for part in (item.get("content", []) or []):
                            if not isinstance(part, dict):
                                continue
                            if isinstance(part.get("text"), str) and part.get("text"):
                                parts.append(part.get("text"))
                        if parts:
                            msg_text = "".join(parts).strip()
                    if msg_text:
                        text = msg_text
                elif item.get("type") == "error":
                    msg = item.get("message", "")
                    if msg:
                        errors.append(msg)
            elif evt.get("type") == "turn.completed":
                usage = evt.get("usage", {})
            elif evt.get("type") == "error":
                msg = evt.get("message", "")
                if msg:
                    errors.append(msg)
        except Exception as e:
            log.debug("JSONL parse skip: %s", e)
            continue
    if not text:
        err_msg = (result.stderr or "").strip()
        if not err_msg and errors:
            err_msg = " | ".join(errors[-3:])
        if not err_msg:
            err_msg = "Codex returned no assistant text"
        return {"ok": False, "error": err_msg[:500]}
    return {
        "ok": True, "backend": "codex",
        "text": text,
        "model": codex_model,
        "duration_ms": 0,
        "tokens": {"input": usage.get("input_tokens", 0), "output": usage.get("output_tokens", 0)},
        "bridge": _bridge_runtime_semantics("codex", codex_model),
    }

def _dispatch_ollama(message, model=None, timeout=120):
    """Invoke Ollama via HTTP API and return normalized response."""
    import urllib.request
    ollama_model = model or "qwen2.5-coder:1.5b"
    payload = json.dumps({"model": ollama_model, "prompt": message, "stream": False}).encode()
    req = urllib.request.Request(
        "http://127.0.0.1:11434/api/generate",
        data=payload,
        headers={"Content-Type": "application/json"},
    )
    log.info("Agent bridge [ollama]: model=%s msg=%s", ollama_model, message[:80])
    resp = urllib.request.urlopen(req, timeout=timeout)
    data = json.loads(resp.read())
    return {
        "ok": True, "backend": "ollama",
        "text": data.get("response", ""),
        "model": ollama_model,
        "duration_ms": int(data.get("total_duration", 0) / 1e6),  # ns → ms
        "tokens": {"total": data.get("eval_count", 0)},
        "bridge": _bridge_runtime_semantics("ollama", ollama_model),
    }

def _svg_escape(text: str) -> str:
    """Escape text for safe SVG embedding."""
    return str(text).replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")





def _build_dispatch_chain_svg(chain_id: str) -> str:
    """Left-to-right chain diagram for a dispatch chain."""
    try:
        conn = _db_conn()
        rows = conn.execute(
            "SELECT from_agent, to_agent, status, duration_ms FROM agent_messages "
            "WHERE chain_id=? ORDER BY step_num",
            (chain_id,)
        ).fetchall()
        conn.close()
    except Exception:
        return ""
    if not rows:
        return '<svg width="200" height="50" xmlns="http://www.w3.org/2000/svg"><text x="100" y="30" text-anchor="middle" fill="#888" font-size="12">No steps found</text></svg>'

    group_colors = {
        "orchestrator": "#ef4444", "strategy": "#6366f1", "creative": "#ec4899",
        "technical": "#06b6d4", "operations": "#f59e0b"
    }

    w = max(400, len(rows) * 160 + 40)
    h = 60
    nodes = ""
    edges = ""

    for i, (from_a, to_a, status, dur) in enumerate(rows):
        x = 20 + i * 150
        y = 12
        color = "#22c55e" if status == "complete" else "#ef4444" if status == "failed" else "#f59e0b"
        label = _svg_escape(to_a[:12])

        # Node rect
        nodes += f'<rect x="{x}" y="{y}" width="120" height="36" rx="8" fill="{color}" opacity="0.15" stroke="{color}" stroke-width="1.5"/>'
        nodes += f'<text x="{x + 60}" y="{y + 22}" text-anchor="middle" fill="{color}" font-size="11" font-weight="600">{label}</text>'

        # Status dot
        dot_color = "#22c55e" if status == "complete" else "#ef4444" if status == "failed" else "#f59e0b"
        nodes += f'<circle cx="{x + 110}" cy="{y + 8}" r="4" fill="{dot_color}" opacity="0.8"/>'

        # Edge to next node
        if i < len(rows) - 1:
            edges += f'<line x1="{x + 120}" y1="{y + 18}" x2="{x + 150}" y2="{y + 18}" stroke="var(--border2, #555)" stroke-width="1.5" stroke-dasharray="4,3"><animate attributeName="stroke-dashoffset" from="7" to="0" dur="0.8s" repeatCount="indefinite"/></line>'

    return f'<svg width="{w}" height="{h}" viewBox="0 0 {w} {h}" xmlns="http://www.w3.org/2000/svg">{edges}{nodes}</svg>'


