def _cli_help_text(binary: str, args=None) -> str:
    args = tuple(args or [])
    key = (binary,) + args
    cached = _cli_help_cache.get(key)
    if cached and (time.time() - cached[0]) < 3600:
        return cached[1]
    path = _resolve_cli(binary)
    if not path:
        return ""
    try:
        result = subprocess.run([path, *args, "--help"], capture_output=True, text=True, timeout=8, env=_agent_env(), cwd=str(Path.home()))
        text = ((result.stdout or "") + "\n" + (result.stderr or "")).strip()
    except Exception:
        text = ""
    _cli_help_cache[key] = (time.time(), text)
    return text


def _gemini_auth_mode() -> str:
    if os.environ.get("GEMINI_API_KEY") or os.environ.get("GOOGLE_API_KEY"):
        return "api_key"
    gdir = Path.home() / ".gemini"
    if (gdir / "oauth_creds.json").exists():
        return "oauth"
    return "unknown"


def _normalize_gemini_model_id(model_id: str, auth_mode: str = "") -> str:
    text = _clean_runtime_model_id(model_id)
    if not text:
        return ""
    low = text.lower()
    if auth_mode == "oauth":
        if "flash-lite" in low:
            return "gemini-2.5-flash-lite"
        if "flash" in low:
            return "gemini-2.5-flash"
        if "pro" in low:
            return "gemini-2.5-pro"
    return text


def _backend_runtime_info(backend: str) -> dict:
    backend = str(backend or "").strip().lower()
    now = time.time()
    fp = _cli_binary_fingerprint(backend)
    if backend == "gemini":
        fp = f"{fp}|{_gemini_auth_mode()}"
    cached = _backend_runtime_cache["data"].get(backend)
    cache_ts = float(_backend_runtime_cache["ts"].get(backend) or 0.0)
    cache_fp = _backend_runtime_cache["fp"].get(backend, "")
    if cached and cache_fp == fp and (now - cache_ts) < 60:
        return dict(cached)
    spec = dict(BACKEND_RUNTIME_SPECS.get(backend) or {})
    info = {"backend": backend, "spec": spec}
    if backend == "gemini":
        help_text = _cli_help_text("gemini")
        auth_mode = _gemini_auth_mode()
        info.update({
            "auth_mode": auth_mode,
            "supports_json_output": "--output-format" in help_text and "json" in help_text.lower(),
            "supports_model_flag": "-m, --model" in help_text or "--model" in help_text,
            "supports_headless": "-p, --prompt" in help_text or "--prompt" in help_text,
            "recommended_smoke_model": "gemini-2.5-flash" if auth_mode in ("oauth", "unknown") else "",
        })
    elif backend == "claude":
        help_text = _cli_help_text("claude")
        info.update({
            "supports_json_output": "--output-format" in help_text and "json" in help_text.lower(),
            "supports_model_flag": "--model" in help_text,
            "supports_headless": "-p, --print" in help_text or "--print" in help_text,
        })
    elif backend == "codex":
        help_text = _cli_help_text("codex", ("exec",))
        info.update({
            "supports_json_output": "--json" in help_text,
            "supports_model_flag": "--model" in help_text,
            "supports_headless": True,
        })
    elif backend == "openclaw":
        help_text = _cli_help_text("openclaw", ("agent",))
        info.update({
            "supports_json_output": "--json" in help_text,
            "supports_model_flag": False,
            "supports_headless": True,
        })
    elif backend == "ollama":
        info.update({
            "supports_json_output": True,
            "supports_model_flag": True,
            "supports_headless": True,
        })
    info.update(_bridge_runtime_semantics(backend))
    info["chips"] = _runtime_chip_definitions(backend, info, {})
    _backend_runtime_cache["data"][backend] = dict(info)
    _backend_runtime_cache["ts"][backend] = now
    _backend_runtime_cache["fp"][backend] = fp
    return info


def _probe_backend_versions(force: bool = False):
    """Detect installed/current versions quickly and refresh latest checks on a slower cadence."""
    import time as _t
    now = _t.time()
    if force:
        _invalidate_backend_version_cache()
    if _backend_version_cache["data"] and (now - _backend_version_cache["ts"]) < 30:
        return _backend_version_cache["data"]

    versions = {}

    def _extract_semverish(text):
        text = str(text or "").strip()
        if not text:
            return ""
        m = re.search(r"\b\d{4}\.\d+\.\d+\b", text)
        if m:
            return m.group(0)
        m = re.search(r"\bv?\d+\.\d+\.\d+\b", text)
        if m:
            return m.group(0).lstrip("v")
        m = re.search(r"\bv?\d+\.\d+\b", text)
        if m:
            return m.group(0).lstrip("v")
        return ""

    def _resolve_bin(name):
        """Prefer user-local installs over system PATH to avoid stale distro shims."""
        for d in (str(Path.home() / ".npm-global" / "bin"), str(Path.home() / ".local" / "bin"), "/usr/local/bin", "/usr/bin", "/bin"):
            c = Path(d) / name
            if c.exists():
                return str(c)
        p = shutil.which(name)
        if p:
            return p
        return None

    def _cli_version(name, parse_fn=None):
        """Run binary --version, return version string or empty."""
        path = _resolve_bin(name)
        if not path:
            return {"version": "", "detected": False, "path": ""}
        try:
            _env = dict(os.environ)
            _home = str(Path.home())
            _extra = f"{_home}/.npm-global/bin:{_home}/.local/bin:/usr/local/bin"
            _env["PATH"] = _extra + ":" + _env.get("PATH", "")
            _env["HOME"] = _home
            result = subprocess.run([path, "--version"], capture_output=True, text=True, timeout=5, env=_env)
            out = (result.stdout or result.stderr or "").strip()
            ver = parse_fn(out) if parse_fn else out.split()[-1] if out else ""
            return {"version": ver, "detected": True, "path": path} if ver else {"version": "", "detected": False, "path": path}
        except Exception:
            return {"version": "", "detected": False, "path": path}

    def _npm_latest(pkg_name):
        try:
            result = subprocess.run(["npm", "view", pkg_name, "version"], capture_output=True, text=True, timeout=3, env=_agent_env())
            latest = (result.stdout or "").strip().splitlines()
            latest = latest[-1].strip() if latest else ""
            return _extract_semverish(latest)
        except Exception:
            return ""

    def _http_json(url, timeout=3):
        try:
            import urllib.request
            with urllib.request.urlopen(url, timeout=timeout) as resp:
                return json.loads(resp.read().decode("utf-8"))
        except Exception:
            return None

    def _github_latest_release(repo):
        data = _http_json(f"https://api.github.com/repos/{repo}/releases/latest", timeout=4)
        if not isinstance(data, dict):
            return ""
        return _extract_semverish(data.get("tag_name", ""))

    # OpenClaw
    versions["openclaw"] = _cached_capability_version("openclaw")
    if not versions["openclaw"].get("detected"):
        versions["openclaw"] = _cli_version("openclaw", _extract_semverish)

    # Ollama
    versions["ollama"] = _cli_version("ollama", _extract_semverish)
    try:
        import urllib.request, json as _j2
        req = urllib.request.Request("http://127.0.0.1:11434/api/version", method="GET")
        with urllib.request.urlopen(req, timeout=3) as resp:
            data = _j2.loads(resp.read())
            api_ver = _extract_semverish(data.get("version", ""))
            if api_ver:
                versions["ollama"]["version"] = api_ver
                versions["ollama"]["detected"] = True
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Claude CLI — prefer cached capability result to avoid redundant process spawn on tab load
    versions["claude"] = _cached_capability_version("claude")
    if not versions["claude"].get("detected"):
        versions["claude"] = _cli_version("claude", _extract_semverish)

    # Gemini — CLI startup is relatively slow, so reuse capability cache when available
    versions["gemini"] = _cached_capability_version("gemini")
    if not versions["gemini"].get("detected"):
        versions["gemini"] = _cli_version("gemini", _extract_semverish)

    # Codex — also check ~/.codex/version.json for latest available
    _cdx_ver = _cached_capability_version("codex")
    if not _cdx_ver.get("detected"):
        _cdx_ver = _cli_version("codex", _extract_semverish)
    try:
        _cdx_vjson = json.loads((Path.home() / ".codex" / "version.json").read_text())
        _cdx_latest = _cdx_vjson.get("latest_version", "")
        if _cdx_latest:
            _cdx_ver["latest"] = _extract_semverish(_cdx_latest) or str(_cdx_latest)
            _cdx_ver["update_cmd"] = "npm i -g @openai/codex"
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    versions["codex"] = _cdx_ver

    # Google Workspace CLI
    versions["gws"] = _cli_version("gws")

    latest_cache = dict(_backend_latest_cache.get("data") or {})
    latest_stale = force or ((now - float(_backend_latest_cache.get("ts") or 0)) >= 21600)
    if latest_stale:
        refreshed = {}
        try:
            oc_update = json.loads((OPENCLAW_STATE_DIR / "update-check.json").read_text(encoding="utf-8"))
            oc_latest = _extract_semverish(oc_update.get("lastNotifiedVersion", ""))
            if oc_latest:
                refreshed["openclaw"] = {"latest": oc_latest, "update_cmd": "npm uninstall -g openclaw && npm i -g openclaw"}
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        if not refreshed.get("openclaw"):
            _oc_latest = _npm_latest("openclaw")
            if _oc_latest:
                refreshed["openclaw"] = {"latest": _oc_latest, "update_cmd": "npm uninstall -g openclaw && npm i -g openclaw"}
        _cl_latest = _npm_latest("@anthropic-ai/claude-code")
        if _cl_latest:
            refreshed["claude"] = {"latest": _cl_latest, "update_cmd": "npm i -g @anthropic-ai/claude-code"}
        _gm_latest = _npm_latest("@google/gemini-cli")
        if _gm_latest:
            refreshed["gemini"] = {"latest": _gm_latest, "update_cmd": "npm i -g @google/gemini-cli"}
        _cdx_latest = _npm_latest("@openai/codex")
        if _cdx_latest:
            refreshed["codex"] = {"latest": _cdx_latest, "update_cmd": "npm i -g @openai/codex"}
        _ollama_latest = _github_latest_release("ollama/ollama")
        if _ollama_latest:
            refreshed["ollama"] = {"latest": _ollama_latest, "update_cmd": "curl -fsSL https://ollama.com/install.sh | sh"}
        latest_cache = refreshed
        _backend_latest_cache["data"] = latest_cache
        _backend_latest_cache["ts"] = now

    for _bk, _latest in latest_cache.items():
        if _bk in versions and isinstance(_latest, dict):
            versions[_bk].update({k: v for k, v in _latest.items() if v})

    _backend_version_cache["data"] = versions
    _backend_version_cache["ts"] = now
    return versions


def _model_display_name(model_id: str) -> str:
    """Prefer runtime IDs over stale marketing labels; lightly normalize when obvious."""
    text = str(model_id or "").strip()
    if not text:
        return ""
    slug = text.split("/")[-1]
    pretty = slug.replace("_", "-")
    if pretty.startswith("gpt-"):
        return pretty.upper()
    if pretty.startswith("claude-"):
        return "Claude " + pretty[len("claude-"):].replace("-", " ").title()
    if pretty.startswith("gemini-"):
        return "Gemini " + pretty[len("gemini-"):].replace("-", " ").title()
    return pretty


def _bridge_runtime_semantics(backend: str, model_id: str = "") -> dict:
    backend = str(backend or "").strip().lower()
    model_id = str(model_id or "").strip()
    if backend == "openclaw":
        control_mode = "agent-default"
        notes = ["OpenClaw currently treats Porter model selection as advisory."]
        if model_id and model_id not in ("auto", "main"):
            notes.append("Exact model switching is not available on this OpenClaw path yet.")
        return {
            "control_mode": control_mode,
            "supports_exact_model": False,
            "honors_model_selection": False,
            "bridge_target": "main",
            "notes": notes,
        }
    if backend == "gemini":
        auth_mode = _gemini_auth_mode()
        exact = auth_mode == "api_key"
        return {
            "control_mode": "exact" if exact else "alias",
            "supports_exact_model": exact,
            "honors_model_selection": True,
            "bridge_target": model_id,
            "notes": ["OAuth mode may remap Gemini aliases at runtime."] if auth_mode == "oauth" else [],
        }
    return {
        "control_mode": "exact",
        "supports_exact_model": True,
        "honors_model_selection": True,
        "bridge_target": model_id,
        "notes": [],
    }


def _runtime_chip_definitions(backend: str, runtime: dict | None = None, available: dict | None = None) -> list[dict]:
    backend = str(backend or "").strip().lower()
    runtime = runtime or {}
    available = available or {}
    chips = []
    if backend == "openclaw":
        chips.append({
            "label": "Gateway Bridge",
            "tooltip": "Porter reaches OpenClaw through its gateway runtime instead of talking directly to a model API.",
        })
        if runtime.get("honors_model_selection") is False:
            chips.append({
                "label": "Advisory Selection",
                "tooltip": "OpenClaw treats Porter model selection as advisory on this path instead of switching to an exact model target.",
            })
    elif backend == "gemini":
        auth_mode = str(runtime.get("auth_mode") or "unknown").strip().lower()
        chips.append({
            "label": "CLI Runtime",
            "tooltip": "Porter uses the Gemini runtime available in this environment and its current auth/session state.",
        })
        chips.append({
            "label": "Exact Selection" if runtime.get("control_mode") == "exact" else "Alias Selection",
            "tooltip": "Exact selection means Porter can ask for a specific model ID directly. Alias selection means the Gemini CLI may remap the requested model at runtime.",
        })
        if auth_mode == "oauth":
            chips.append({
                "label": "OAuth Profile",
                "tooltip": "This Gemini runtime is using OAuth mode, so model aliases and auth prompts are managed by that environment session.",
            })
    elif backend == "claude":
        chips.append({
            "label": "CLI Runtime",
            "tooltip": "Porter uses the Claude runtime available in this environment and its current auth/session state.",
        })
        if runtime.get("supports_json_output"):
            chips.append({
                "label": "Structured Output",
                "tooltip": "Porter can ask the Claude CLI for structured output during tests and bridge dispatch bookkeeping.",
            })
    elif backend == "codex":
        chips.append({
            "label": "CLI Runtime",
            "tooltip": "Porter uses the Codex runtime available in this environment and its current auth/session state.",
        })
        chips.append({
            "label": "Structured Output",
            "tooltip": "Porter uses Codex JSON/JSONL event output so bridge telemetry and parsing stay reliable.",
        })
    elif backend == "ollama":
        chips.append({
            "label": "HTTP Runtime",
            "tooltip": "Porter talks to the Ollama runtime over HTTP at the configured host and port for this environment.",
        })
    if available.get("resolved") and runtime.get("honors_model_selection") is False:
        chips.append({
            "label": "Model Preference",
            "tooltip": "The model picker still matters for operator intent and diagnostics, but this backend cannot honor it as an exact runtime switch yet.",
        })
    return chips


def _clean_runtime_model_id(model_id: str) -> str:
    model_id = str(model_id or "").strip()
    if not model_id:
        return ""
    low = model_id.lower()
    if low.startswith("<") and low.endswith(">"):
        return ""
    if low in {"synthetic", "<synthetic>", "auto"}:
        return ""
    return model_id


def _canonical_model_key(model_id: str) -> str:
    model_id = _clean_runtime_model_id(model_id)
    if not model_id:
        return ""
    return model_id.split("/")[-1].strip().lower()


def _unique_model_catalog(entries, preferred_id=""):
    """Dedupe model entries while preserving order and honoring a preferred active ID."""
    preferred_id = str(preferred_id or "").strip()
    seen = set()
    ordered = []
    pending = []
    for entry in entries or []:
        if not isinstance(entry, dict):
            continue
        model_id = _clean_runtime_model_id(entry.get("id", ""))
        canonical = _canonical_model_key(model_id)
        if not model_id or canonical in seen:
            continue
        seen.add(canonical)
        item = {
            "id": model_id,
            "name": str(entry.get("name") or _model_display_name(model_id) or model_id),
            "default": False,
        }
        if model_id == preferred_id:
            ordered.insert(0, item)
        else:
            pending.append(item)
    ordered.extend(pending)
    if ordered:
        ordered[0]["default"] = True
    return ordered




def _discover_openclaw_models(active_choice=""):
    oc_bin = _resolve_cli("openclaw")
    if not oc_bin:
        return []
    try:
        result = subprocess.run([oc_bin, "models", "list", "--json"], capture_output=True, text=True, timeout=15, env=_agent_env(), cwd=str(Path.home()))
        raw = ((result.stdout or "").strip() or (result.stderr or "").strip())
        if result.returncode == 0 and raw:
            payload = json.loads(raw[raw.find("{"):]) if "{" in raw else {}
            models = []
            for item in payload.get("models", []):
                if not isinstance(item, dict):
                    continue
                model_id = _clean_runtime_model_id(item.get("key") or item.get("id") or "")
                if not model_id or item.get("missing"):
                    continue
                models.append({
                    "id": model_id,
                    "name": str(item.get("name") or _model_display_name(model_id) or model_id),
                    "default": "default" in (item.get("tags") or []) or "configured" in (item.get("tags") or []),
                })
            if models:
                preferred = next((m["id"] for m in models if m.get("default")), "") or active_choice
                return _unique_model_catalog(models, preferred)
    except Exception as e:
        log.debug("OpenClaw model discovery failed: %s", e)
    return []


def _discover_models_from_claude_history(active_choice=""):
    claude_dir = Path.home() / ".claude" / "projects"
    if not claude_dir.exists():
        return []
    observed = {}
    for jsonl_file in sorted(claude_dir.rglob("*.jsonl"), key=lambda p: p.stat().st_mtime, reverse=True)[:80]:
        try:
            with open(jsonl_file, "r", encoding="utf-8") as fh:
                for idx, line in enumerate(fh):
                    if idx >= 400:
                        break
                    try:
                        entry = json.loads(line)
                    except Exception:
                        continue
                    model_id = ""
                    msg = entry.get("message", {})
                    if isinstance(msg, dict):
                        model_id = _clean_runtime_model_id(msg.get("model") or "")
                    if not model_id:
                        model_id = _clean_runtime_model_id(entry.get("model") or "")
                    if model_id:
                        observed.setdefault(model_id, {"id": model_id, "name": _model_display_name(model_id) or model_id})
        except Exception as e:
            log.debug("Claude model scan skip %s: %s", jsonl_file, e)
    return _unique_model_catalog(list(observed.values()), active_choice)


def _discover_models_from_gemini_history(active_choice=""):
    gemini_root = Path.home() / ".gemini" / "tmp"
    if not gemini_root.exists():
        return []
    runtime = _backend_runtime_info("gemini")
    auth_mode = runtime.get("auth_mode", "")
    observed = {}
    for json_file in sorted(gemini_root.rglob("chats/*.json"), key=lambda p: p.stat().st_mtime, reverse=True)[:80]:
        try:
            data = json.loads(json_file.read_text(encoding="utf-8"))
        except Exception:
            continue
        stack = [data]
        while stack:
            cur = stack.pop()
            if isinstance(cur, dict):
                for k, v in cur.items():
                    if k == "model" and isinstance(v, str) and v.strip():
                        model_id = _normalize_gemini_model_id(v, auth_mode)
                        observed.setdefault(model_id, {"id": model_id, "name": _model_display_name(model_id) or model_id})
                    elif isinstance(v, (dict, list)):
                        stack.append(v)
            elif isinstance(cur, list):
                stack.extend(cur)
    if auth_mode == "oauth":
        for stable in ("gemini-2.5-flash", "gemini-2.5-pro"):
            observed.setdefault(stable, {"id": stable, "name": _model_display_name(stable) or stable})
    return _unique_model_catalog(list(observed.values()), active_choice)


def _legacy_config_models(backend):
    bc = _config.get("backend_config", {}).get(backend, {})
    models = bc.get("models", [])
    cleaned = []
    for m in models:
        if not isinstance(m, dict):
            continue
        model_id = _clean_runtime_model_id(m.get("id", ""))
        if not model_id:
            continue
        item = dict(m)
        item["id"] = model_id
        cleaned.append(item)
    return cleaned


def _get_available_models(backend):
    """Return models for a backend. Runtime discovery is authoritative; config is fallback only."""
    prefs = _config.get("preferences", {})
    active_models = prefs.get("active_models", {})
    active_choice = str(active_models.get(backend, "")).strip()
    now = time.time()
    cached = _backend_model_cache["data"].get(backend)
    cache_ts = float(_backend_model_cache["ts"].get(backend) or 0)
    if cached is not None and (now - cache_ts) < 90:
        return cached

    if backend == "codex":
        # Read from Codex CLI models cache (auto-updated by codex)
        try:
            cache_path = Path.home() / ".codex" / "models_cache.json"
            if cache_path.exists():
                data = json.loads(cache_path.read_text(encoding="utf-8"))
                models = []
                for m in sorted(data.get("models", []), key=lambda x: x.get("priority", 99)):
                    if m.get("visibility") == "hide":
                        continue
                    slug = m.get("slug", "")
                    if slug:
                        models.append({"id": slug, "name": m.get("display_name", slug), "default": len(models) == 0})
                if models:
                    _backend_model_cache["data"][backend] = models
                    _backend_model_cache["ts"][backend] = now
                    return models
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        models = _unique_model_catalog(_legacy_config_models("codex"), active_choice)
        _backend_model_cache["data"][backend] = models
        _backend_model_cache["ts"][backend] = now
        return models
    if backend == "ollama":
        try:
            import urllib.request, json as _j
            bc = _config.get("backend_config", {}).get("ollama", {})
            _oll_host = bc.get("host", "127.0.0.1")
            _oll_port = bc.get("port", 11434)
            req = urllib.request.Request(f"http://{_oll_host}:{_oll_port}/api/tags", method="GET")
            with urllib.request.urlopen(req, timeout=3) as resp:
                data = _j.loads(resp.read())
                models = []
                for m in data.get("models", []):
                    name = m.get("name", "")
                    if name:
                        models.append({"id": name, "name": name, "default": len(models) == 0})
                _backend_model_cache["data"][backend] = models
                _backend_model_cache["ts"][backend] = now
                return models
        except Exception:
            models = _unique_model_catalog(_legacy_config_models("ollama"), active_choice)
            _backend_model_cache["data"][backend] = models
            _backend_model_cache["ts"][backend] = now
            return models
    if backend == "openclaw":
        models = _discover_openclaw_models(active_choice)
    elif backend == "claude":
        models = _discover_models_from_claude_history(active_choice)
    elif backend == "gemini":
        models = _discover_models_from_gemini_history(active_choice)
    else:
        models = []

    fallback = _legacy_config_models(backend)
    if active_choice and not any(m.get("id") == active_choice for m in models):
        fallback = ([{"id": active_choice, "name": _model_display_name(active_choice) or active_choice}] + fallback)
    models = _unique_model_catalog(models + fallback, active_choice)
    _backend_model_cache["data"][backend] = models
    _backend_model_cache["ts"][backend] = now
    return models


def _get_active_model(backend):
    """Return the active model ID for a backend. Resolves 'auto' to default."""
    prefs = _config.get("preferences", {})
    active_models = prefs.get("active_models", {})
    choice = active_models.get(backend, "auto")
    if choice == "auto":
        models = _get_available_models(backend)
        for m in models:
            if m.get("default"):
                return m["id"]
        return models[0]["id"] if models else ""
    return choice


def _record_bridge_benchmark(benchmark_kind: str, backend: str, requested_model: str = "",
                             resolved_model: str = "", ok: bool = False, latency_ms: int = 0,
                             error: str = "", metadata: dict | None = None) -> None:
    try:
        conn = _db_conn()
        conn.execute(
            """INSERT INTO bridge_benchmarks
               (benchmark_kind, backend, requested_model, resolved_model, ok, latency_ms, error, metadata, created_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (
                str(benchmark_kind or "dispatch")[:40],
                str(backend or "")[:40],
                str(requested_model or "")[:160],
                str(resolved_model or "")[:160],
                1 if ok else 0,
                max(0, int(latency_ms or 0)),
                str(error or "")[:500],
                json.dumps(metadata or {}, ensure_ascii=True),
                time.time(),
            ),
        )
        conn.commit()
        conn.close()
        _invalidate_bridge_benchmark_cache()
    except Exception as e:
        log.debug("Bridge benchmark record failed: %s", e)


def _bridge_benchmark_summary(window_s: int = 86400) -> dict:
    now = time.time()
    cache_key = str(int(window_s or 86400))
    cached = (_bridge_benchmark_summary_cache.get("data") or {}).get(cache_key)
    if cached and (now - float(_bridge_benchmark_summary_cache.get("ts") or 0.0)) < 30.0:
        return dict(cached)
    out = {}
    try:
        conn = _db_conn()
        since = now - max(300, int(window_s or 86400))
        for backend in PROVIDER_REGISTRY:
            rows = conn.execute(
                """SELECT benchmark_kind, requested_model, resolved_model, ok, latency_ms, created_at
                   FROM bridge_benchmarks
                   WHERE backend=? AND created_at>=?
                   ORDER BY created_at DESC LIMIT 200""",
                (backend, since),
            ).fetchall()
            latencies = [int(r["latency_ms"] or 0) for r in rows if int(r["latency_ms"] or 0) > 0]
            test_rows = [r for r in rows if str(r["benchmark_kind"] or "") == "connectivity"]
            success_count = sum(1 for r in rows if int(r["ok"] or 0))
            sample_count = len(rows)
            success_rate = int(round((success_count / sample_count) * 100)) if sample_count else 0
            p50 = 0
            p95 = 0
            if latencies:
                ordered = sorted(latencies)
                p50 = ordered[max(0, min(len(ordered) - 1, len(ordered) // 2))]
                p95 = ordered[max(0, min(len(ordered) - 1, math.ceil(len(ordered) * 0.95) - 1))]
            latest = dict(rows[0]) if rows else {}
            out[backend] = {
                "samples": sample_count,
                "success_rate": success_rate,
                "p50_ms": p50,
                "p95_ms": p95,
                "test_samples": len(test_rows),
                "latest_kind": str(latest.get("benchmark_kind") or ""),
                "latest_requested_model": str(latest.get("requested_model") or ""),
                "latest_resolved_model": str(latest.get("resolved_model") or ""),
                "latest_ok": bool(latest.get("ok")) if latest else False,
                "latest_at": float(latest.get("created_at") or 0),
            }
        conn.close()
    except Exception as e:
        log.debug("Bridge benchmark summary failed: %s", e)
    _bridge_benchmark_summary_cache.setdefault("data", {})[cache_key] = dict(out)
    _bridge_benchmark_summary_cache["ts"] = now
    return out


def _benchmark_adjusted_route(preferred: str, message: str = "") -> tuple:
    preferred = str(preferred or "").strip().lower()
    if not preferred:
        return (preferred, None)
    summary = _bridge_benchmark_summary(86400)
    pref_stats = summary.get(preferred) or {}
    pref_pressure = _bridge_scheduler_backend_pressure(preferred)
    if int(pref_stats.get("samples") or 0) < 3:
        if pref_pressure.get("saturated") and pref_pressure.get("waiting", 0) > 0:
            return _resolve_with_fallback(preferred, message)
        return (preferred, None) if _probe_provider(preferred) and not _backend_is_circuit_open(preferred) else _resolve_with_fallback(preferred, message)
    pref_success = int(pref_stats.get("success_rate") or 0)
    pref_p50 = int(pref_stats.get("p50_ms") or 0)
    # v0.31.44 — Fast path: if preferred is healthy and not saturated, skip alternatives
    if _probe_provider(preferred) and not _backend_is_circuit_open(preferred) and not pref_pressure.get("saturated"):
        return (preferred, None)
    prefs = _config.get("preferences", {})
    chain = prefs.get("fallback_chain", _DEFAULT_FALLBACK_CHAIN)
    best = preferred
    best_score = None
    for backend in [preferred] + [bk for bk in chain if bk != preferred]:
        if not backend:
            continue
        if not _probe_provider(backend) or _backend_is_circuit_open(backend):
            continue
        stats = summary.get(backend) or {}
        pressure = _bridge_scheduler_backend_pressure(backend)
        samples = int(stats.get("samples") or 0)
        success_rate = int(stats.get("success_rate") or 0)
        p50 = int(stats.get("p50_ms") or 0)
        if backend != preferred and samples < 3:
            continue
        if backend != preferred and success_rate + 5 < pref_success:
            continue
        # Lower score is better. Preserve preferred unless the alternative is materially faster.
        effective_p50 = p50 or 999999
        effective_p50 += int(pressure.get("avg_wait_ms", 0) or 0)
        effective_p50 += int(pressure.get("waiting", 0) or 0) * 300
        if pressure.get("saturated"):
            effective_p50 += 1000
        score = effective_p50 - (success_rate * 20)
        if backend == preferred:
            best_score = score
            continue
        faster_enough = pref_p50 and effective_p50 and effective_p50 <= int(pref_p50 * 0.75)
        if best_score is not None and faster_enough and score < best_score:
            best = backend
            best_score = score
    if best != preferred:
        mlog.emit("info", "routing", "route.benchmark_override",
                  f"Benchmark override: {preferred} → {best}",
                  preferred=preferred, override=best,
                  extra={"preferred": pref_stats, "chosen": summary.get(best) or {}})
        return (best, None)
    return _resolve_with_fallback(preferred, message)


def _openclaw_gateway_settings() -> dict:
    """Load OpenClaw gateway port/token. Config priority: Porter config > discovered runtime config."""
    bc = _config.get("backend_config", {}).get("openclaw", {})
    port = int(bc.get("gateway_port", 0) or bc.get("port", 0) or 0) or 18789
    host = str(bc.get("host", "")).strip() or "127.0.0.1"
    token = str(bc.get("auth_token", "")).strip()
    source = "Porter config override" if any(str(bc.get(k, "")).strip() for k in ("auth_token", "host")) or int(bc.get("gateway_port", 0) or bc.get("port", 0) or 0) else "Discovered runtime config"
    # Fall back to the discovered runtime config if no token is stored in Porter config.
    if not token or source == "Discovered runtime config":
        try:
            oc_cfg = json.loads((OPENCLAW_STATE_DIR / "openclaw.json").read_text(encoding="utf-8"))
            gw = oc_cfg.get("gateway", {}) if isinstance(oc_cfg, dict) else {}
            if not int(bc.get("gateway_port", 0) or bc.get("port", 0) or 0):
                port = int(gw.get("port") or oc_cfg.get("gatewayPort") or 18789)
            if not str(bc.get("host", "")).strip():
                bind = str(gw.get("bind") or oc_cfg.get("gatewayBind") or "").strip().lower()
                host = "127.0.0.1" if bind in ("", "loopback", "127.0.0.1", "localhost") else (bind or host)
            auth = gw.get("auth", {}) if isinstance(gw, dict) else {}
            if not token:
                token = str(auth.get("token") or gw.get("token") or oc_cfg.get("authToken") or "").strip()
        except Exception as e:
            log.debug("OpenClaw gateway config read failed: %s", e)
    return {"host": host, "port": port, "token": token, "source": source}


def _model_repair_hint(backend: str, detail: str = "") -> dict:
    """Return operator-facing repair hints for known backend failure modes."""
    backend = str(backend or "").strip().lower()
    text = str(detail or "").lower()
    hint = {}
    if backend == "openclaw":
        if any(tok in text for tok in ("cannot find module", "module not found", "err_module_not_found", "syntaxerror", "typeerror", "node:internal")):
            hint["repair_hint"] = "OpenClaw CLI install appears broken. Reinstall the CLI, then re-open/auth the gateway."
            hint["reinstall_cmd"] = "npm uninstall -g openclaw && npm i -g openclaw"
        elif "duplicate_service_units" in text or "competing service units" in text or "supervisor conflict" in text:
            hint["repair_hint"] = "OpenClaw has competing service units or supervisors. Reinstall will not fix that; disable the duplicate unit so only one gateway service owns the port."
            hint["repair_cmd"] = "systemctl status openclaw-gateway"
            hint["followup_hint"] = "Check both /etc/systemd/system/openclaw-gateway.service and ~/.config/systemd/user/openclaw-gateway.service."
        elif "service_restart_loop" in text or "service restart" in text or "restarting itself every few seconds" in text:
            hint["repair_hint"] = "OpenClaw gateway is entering a service restart loop. This is runtime breakage in OpenClaw, not just a bad model test."
            hint["repair_cmd"] = "openclaw status"
            hint["followup_hint"] = "Review the OpenClaw gateway service/logs before changing Porter config."
        elif "paired devices exist" in text or "connected and reconnected" in text or "reconnect loop" in text:
            hint["repair_hint"] = "OpenClaw looks paired but unstable. If it loops between connected and reconnected, stop the gateway and reset devices/paired.json plus devices/pending.json, then pair again."
            hint["repair_cmd"] = "openclaw gateway stop"
            hint["followup_hint"] = "Then back up or clear ~/.openclaw/devices/paired.json and ~/.openclaw/devices/pending.json before re-pairing."
        elif "agent_path_flaky" in text or "agent runs are intermittent" in text:
            hint["repair_hint"] = "OpenClaw gateway is up, but real agent runs are intermittent. Recheck the active gateway service, then test one direct agent run before blaming Porter."
            hint["repair_cmd"] = "openclaw agent --agent main --message \"Reply with just the word OK\" --json --timeout 45"
            hint["followup_hint"] = "If this flaps between success and 1006/timeout, inspect the active openclaw-gateway service and its journal."
        elif "gateway not running" in text:
            hint["repair_hint"] = "OpenClaw gateway is down. Run doctor --fix or stop/reset pairing state if the UI keeps reconnecting."
            hint["repair_cmd"] = "openclaw doctor --fix"
        elif "auth" in text or "token" in text or "unauthorized" in text:
            hint["repair_hint"] = "OpenClaw auth looks invalid. Refresh the auth token or reconnect the gateway profile."
        elif "timed out" in text or "timeout" in text:
            hint["repair_hint"] = "OpenClaw did not answer in time. Check whether the gateway is crash-looping or blocked on startup."
        else:
            if text.strip():
                hint["repair_hint"] = "Check OpenClaw bridge health, agent execution, and auth before changing the install."

    elif backend == "claude":
        hint["reinstall_cmd"] = "npm i -g @anthropic-ai/claude-code"
        if "auth" in text or "login" in text or "token" in text:
            hint["repair_hint"] = "Claude Code needs authentication or token refresh before model tests can succeed."
    elif backend == "gemini":
        hint["reinstall_cmd"] = "npm i -g @google/gemini-cli"
        if "auth" in text or "oauth" in text or "authorize" in text or "login" in text:
            hint["repair_hint"] = "Gemini CLI needs authentication before model tests can succeed."
    elif backend == "codex":
        hint["reinstall_cmd"] = "npm i -g @openai/codex"
        if "auth" in text or "login" in text or "token" in text:
            hint["repair_hint"] = "Codex CLI needs authentication before model tests can succeed."
    return hint


_openclaw_diag_cache = {"ts": 0.0, "data": None}


def _openclaw_runtime_diagnosis() -> dict:
    """Best-effort OpenClaw diagnosis for operator-facing failures."""
    now = time.time()
    cached = _openclaw_diag_cache.get("data")
    if cached and (now - float(_openclaw_diag_cache.get("ts") or 0)) < 30:
        return cached

    diag = {
        "gateway_running": False,
        "gateway_listening": False,
        "node_version": "",
        "issues": [],
        "doctor_summary": [],
        "paired_devices": 0,
        "pending_devices": 0,
        "pairing_temp_files": 0,
        "service_restart_loop": False,
        "token_mismatch": False,
        "log_path": "",
        "duplicate_service_units": False,
        "service_unit_paths": [],
        "recent_agent_success": False,
        "recent_agent_failure": False,
    }

    try:
        r = subprocess.run(["pgrep", "-f", "openclaw-gateway"], capture_output=True, text=True, timeout=3)
        diag["gateway_running"] = (r.returncode == 0 and bool((r.stdout or "").strip()))
        if not diag["gateway_running"]:
            diag["issues"].append("gateway_not_running")
    except Exception:
        diag["issues"].append("gateway_status_unknown")

    try:
        settings = _openclaw_gateway_settings()
        with socket.create_connection((str(settings.get("host") or "127.0.0.1"), int(settings.get("port") or 18789)), timeout=1.0):
            diag["gateway_listening"] = True
    except Exception:
        diag["gateway_listening"] = False

    try:
        node_r = subprocess.run(["node", "-v"], capture_output=True, text=True, timeout=3, env=_agent_env())
        node_ver = (node_r.stdout or node_r.stderr or "").strip()
        diag["node_version"] = node_ver
        m = re.search(r"v?(\d+)", node_ver)
        if m and int(m.group(1)) < 22:
            diag["issues"].append("node_below_22")
    except Exception:
        diag["issues"].append("node_version_unknown")

    oc_bin = _resolve_cli("openclaw")
    if oc_bin:
        try:
            dr = subprocess.run([oc_bin, "doctor"], capture_output=True, text=True, timeout=20, env=_agent_env(), cwd=str(Path.home()))
            out = (dr.stdout or "") + "\n" + (dr.stderr or "")
            for raw in out.splitlines():
                line = raw.strip()
                if not line:
                    continue
                if "Gateway not running" in line:
                    diag["issues"].append("doctor_gateway_not_running")
                    diag["doctor_summary"].append("Doctor reports gateway not running.")
                elif "below the required Node 22+" in line:
                    diag["issues"].append("doctor_node_requirement")
                    diag["doctor_summary"].append("Doctor reports Node below required 22+ runtime.")
                elif "embedded run agent end" in line and "timed out" in line.lower():
                    diag["issues"].append("embedded_timeout")
                    diag["doctor_summary"].append("Embedded fallback timed out.")
        except subprocess.TimeoutExpired:
            diag["issues"].append("doctor_timeout")
            diag["doctor_summary"].append("OpenClaw doctor timed out.")
        except Exception:
            diag["issues"].append("doctor_failed")

    try:
        devices_dir = OPENCLAW_STATE_DIR / "devices"
        paired_path = devices_dir / "paired.json"
        pending_path = devices_dir / "pending.json"
        if paired_path.exists():
            paired_data = json.loads(paired_path.read_text(encoding="utf-8") or "{}")
            if isinstance(paired_data, dict):
                diag["paired_devices"] = len([k for k in paired_data.keys() if str(k).strip()])
        if pending_path.exists():
            pending_data = json.loads(pending_path.read_text(encoding="utf-8") or "{}")
            if isinstance(pending_data, dict):
                diag["pending_devices"] = len([k for k in pending_data.keys() if str(k).strip()])
        if devices_dir.exists():
            diag["pairing_temp_files"] = len(list(devices_dir.glob("*.tmp")))
        if diag["pending_devices"] > 0:
            diag["issues"].append("pairing_pending")
        if diag["paired_devices"] > 0 and not diag["gateway_running"]:
            diag["issues"].append("paired_but_gateway_down")
            diag["doctor_summary"].append("Paired devices exist but the gateway is not running.")
        if diag["pairing_temp_files"] > 0:
            diag["issues"].append("pairing_temp_files")
    except Exception as e:
        log.debug("OpenClaw pairing diagnosis failed: %s", e)

    unit_paths = [
        Path("/etc/systemd/system/openclaw-gateway.service"),
        Path.home() / ".config" / "systemd" / "user" / "openclaw-gateway.service",
    ]
    try:
        existing_units = [str(p) for p in unit_paths if p.exists()]
        diag["service_unit_paths"] = existing_units
    except Exception as e:
        log.debug("OpenClaw unit diagnosis failed: %s", e)

    try:
        log_dir = Path("/tmp/openclaw")
        log_path = log_dir / f"openclaw-{datetime.utcnow().strftime('%Y-%m-%d')}.log"
        if log_path.exists():
            diag["log_path"] = str(log_path)
            lines = log_path.read_text(encoding="utf-8", errors="replace").splitlines()[-160:]
            restart_times = []
            token_mismatch_times = []
            success_times = []
            failure_times = []
            now_dt = datetime.now(timezone.utc)
            for line in lines:
                low = line.lower()
                evt_time = None
                rec = None
                try:
                    rec = json.loads(line)
                    raw_time = ""
                    if isinstance(rec, dict):
                        raw_time = str(rec.get("time") or (rec.get("_meta") or {}).get("date") or "").strip()
                    if raw_time:
                        evt_time = datetime.fromisoformat(raw_time.replace("Z", "+00:00"))
                        if evt_time.tzinfo is None:
                            evt_time = evt_time.replace(tzinfo=timezone.utc)
                except Exception:
                    evt_time = None
                if evt_time and isinstance(rec, dict):
                    line0 = str(rec.get("0") or "")
                    if "\"status\": \"ok\"" in line0 and "\"summary\": \"completed\"" in line0:
                        success_times.append(evt_time)
                    if "\"stopReason\": \"error\"" in line0 or "embedded run agent end" in low and "iserror=true" in low:
                        failure_times.append(evt_time)
                if "token_mismatch" in low or "unauthorized" in low:
                    if evt_time:
                        token_mismatch_times.append(evt_time)
                if "reason=service restart" in low or "killing 1 stale gateway process(es) before restart" in low or "signal sigterm received" in low:
                    if evt_time:
                        restart_times.append(evt_time)
            recent_restarts = [ts for ts in restart_times if abs((now_dt - ts).total_seconds()) <= 90]
            recent_token_mismatch = [ts for ts in token_mismatch_times if abs((now_dt - ts).total_seconds()) <= 300]
            recent_success = [ts for ts in success_times if abs((now_dt - ts).total_seconds()) <= 300]
            recent_failure = [ts for ts in failure_times if abs((now_dt - ts).total_seconds()) <= 300]
            if recent_success:
                diag["recent_agent_success"] = True
            if recent_failure:
                diag["recent_agent_failure"] = True
            if len(recent_restarts) >= 2:
                diag["service_restart_loop"] = True
                diag["issues"].append("service_restart_loop")
                diag["doctor_summary"].append("Gateway is restarting itself every few seconds.")
            if len(diag.get("service_unit_paths") or []) >= 2 and recent_restarts:
                diag["duplicate_service_units"] = True
                diag["issues"].append("duplicate_service_units")
                diag["doctor_summary"].append("Competing OpenClaw service units likely caused the restart loop.")
            if recent_token_mismatch:
                diag["token_mismatch"] = True
                diag["issues"].append("token_mismatch")
                diag["doctor_summary"].append("Gateway auth token mismatch was seen in recent logs.")
            if recent_success and recent_failure:
                diag["issues"].append("agent_path_flaky")
                diag["doctor_summary"].append("Gateway is up, but agent runs are intermittent.")
    except Exception as e:
        log.debug("OpenClaw log diagnosis failed: %s", e)

    if diag["gateway_running"] or diag["gateway_listening"]:
        diag["issues"] = [issue for issue in diag["issues"] if issue != "doctor_gateway_not_running"]
        diag["doctor_summary"] = [msg for msg in diag["doctor_summary"] if "gateway not running" not in msg.lower()]
    if re.search(r"v?(22|23|24|25)\b", diag.get("node_version") or ""):
        diag["issues"] = [issue for issue in diag["issues"] if issue != "doctor_node_requirement"]
        diag["doctor_summary"] = [msg for msg in diag["doctor_summary"] if "node below required 22+" not in msg.lower()]

    # Normalize + dedupe
    diag["issues"] = sorted(set(diag["issues"]))
    diag["doctor_summary"] = list(dict.fromkeys(diag["doctor_summary"]))[:3]
    _openclaw_diag_cache["ts"] = now
    _openclaw_diag_cache["data"] = diag
    return diag


def _check_gateway_status() -> dict:
    """Check openclaw-gateway process state and detect rapid PID churn."""
    global _gw_pid_history
    now = time.time()
    pid = None
    try:
        r = subprocess.run(["pgrep", "-f", "openclaw-gateway"], capture_output=True, text=True, timeout=3)
        if r.returncode == 0:
            pids = []
            for line in (r.stdout or "").splitlines():
                line = line.strip()
                if line.isdigit():
                    pids.append(int(line))
            if pids:
                pid = max(pids)
    except Exception as e:
        log.debug("Gateway pgrep failed: %s", e)

    if pid is not None:
        if not _gw_pid_history or _gw_pid_history[-1][0] != pid:
            _gw_pid_history.append((pid, now))

    _gw_pid_history = [(p, ts) for (p, ts) in _gw_pid_history if (now - ts) <= 60]
    recent_pids = sorted({p for (p, _) in _gw_pid_history})
    restart_count_60s = len(recent_pids)
    crash_looping = restart_count_60s >= 3

    uptime_s = None
    if pid is not None:
        try:
            proc_stat = Path(f"/proc/{pid}/stat").read_text(encoding="utf-8", errors="replace").split()
            start_ticks = float(proc_stat[21])
            clk_tck = float(os.sysconf("SC_CLK_TCK"))
            sys_uptime = float(Path("/proc/uptime").read_text(encoding="utf-8").split()[0])
            boot_ts = now - sys_uptime
            proc_start_ts = boot_ts + (start_ticks / clk_tck)
            uptime_s = max(0.0, now - proc_start_ts)
        except Exception as e:
            log.debug("Gateway uptime parse failed: %s", e)

    version = _capabilities_cache.get("openclaw", {}).get("version")
    version_short = ""
    if version:
        version_short = str(version).splitlines()[0].strip()
        version_short = re.sub(r"^openclaw\s+", "", version_short, flags=re.IGNORECASE)
        version_short = version_short[:40]
    settings = _openclaw_gateway_settings()
    diagnosis = _openclaw_runtime_diagnosis()
    diag_summary = list(diagnosis.get("doctor_summary") or [])
    node_issue = any(issue in diagnosis.get("issues", []) for issue in ("node_below_22", "doctor_node_requirement"))
    repair_detail = " ".join(diag_summary or diagnosis.get("issues", []))
    if (diagnosis.get("gateway_running") or diagnosis.get("gateway_listening")) and diagnosis.get("recent_agent_failure"):
        if diagnosis.get("recent_agent_success"):
            repair_detail = "agent_path_flaky"
        else:
            repair_detail = "agent execution failed timeout"
    repair = _model_repair_hint("openclaw", repair_detail) if repair_detail.strip() else {}
    return {
        "ok": True,
        "running": pid is not None,
        "pid": pid,
        "uptime_s": uptime_s,
        "listening": bool(diagnosis.get("gateway_listening")),
        "crash_looping": crash_looping,
        "restart_count_60s": restart_count_60s,
        "version": version,
        "version_short": version_short,
        "host": settings.get("host"),
        "port": settings.get("port"),
        "config_source": settings.get("source"),
        "auth_configured": bool(settings.get("token")),
        "diagnosis_summary": diag_summary[:3],
        "node_issue": node_issue,
        "service_restart_loop": bool(diagnosis.get("service_restart_loop")),
        "token_mismatch": bool(diagnosis.get("token_mismatch")),
        "log_path": diagnosis.get("log_path", ""),
        "duplicate_service_units": bool(diagnosis.get("duplicate_service_units")),
        "service_unit_paths": list(diagnosis.get("service_unit_paths") or []),
        "paired_devices": int(diagnosis.get("paired_devices") or 0),
        "pending_devices": int(diagnosis.get("pending_devices") or 0),
        "recent_agent_success": bool(diagnosis.get("recent_agent_success")),
        "recent_agent_failure": bool(diagnosis.get("recent_agent_failure")),
        "repair_hint": repair.get("repair_hint", ""),
        "repair_cmd": repair.get("repair_cmd", ""),
        "followup_hint": repair.get("followup_hint", ""),
        "reinstall_cmd": repair.get("reinstall_cmd", ""),
    }


def _models_cache_fingerprint() -> str:
    try:
        cfg_stat = CONFIG_PATH.stat()
        cfg_fp = f"{cfg_stat.st_size}:{cfg_stat.st_mtime_ns}"
    except Exception:
        cfg_fp = "cfg:missing"
    cli_fp = "|".join(f"{bk}:{_cli_binary_fingerprints.get(bk, '')}" for bk in sorted(PROVIDER_REGISTRY))
    return f"{cfg_fp}|{cli_fp}"


def _lightweight_provider_available(name: str) -> bool:
    cap = _capabilities_cache.get(name) or {}
    if isinstance(cap, dict) and "ok" in cap:
        return bool(cap.get("ok"))
    if name == "ollama":
        return _resolve_cli("ollama") is not None
    return _resolve_cli(name) is not None


def _providers_payload(lightweight: bool = False) -> list:
    providers = []
    availability = {}
    if lightweight:
        for name in PROVIDER_REGISTRY:
            availability[name] = _lightweight_provider_available(name)
    else:
        import concurrent.futures as _cf
        with _cf.ThreadPoolExecutor(max_workers=min(5, len(PROVIDER_REGISTRY))) as ex:
            future_map = {ex.submit(_probe_provider, name): name for name in PROVIDER_REGISTRY}
            for fut, name in ((f, future_map[f]) for f in future_map):
                try:
                    availability[name] = bool(fut.result(timeout=4))
                except Exception:
                    availability[name] = False
    for name, info in PROVIDER_REGISTRY.items():
        _meta = _backend_meta(name)
        available = availability.get(name)
        if available is None:
            available = _probe_provider(name)
        providers.append({
            "id": name,
            "available": available,
            "type": info["type"],
            "label": info["label"],
            "description": _meta.get("description", ""),
            "install_hint": INSTALL_HINTS.get(name, ""),
        })
    return providers


def _models_activity_payload(include_recent: bool = True) -> dict:
    import time as _act_t
    _act_now = _act_t.time()
    _act_since = _act_now - 86400
    activity = {}
    try:
        _act_conn = _db_conn()
        _stale_cutoff = _act_now - 600
        _act_conn.execute(
            "UPDATE agent_messages SET status='failed' "
            "WHERE status='in_progress' AND created_at<?",
            (_stale_cutoff,)
        )
        _act_conn.commit()
        for _bk in PROVIDER_REGISTRY:
            _act_active = _act_conn.execute(
                "SELECT run_id, message, created_at FROM agent_messages "
                "WHERE to_agent=? AND status='in_progress' ORDER BY created_at DESC LIMIT 3",
                (_bk,)
            ).fetchall()
            _act_stats = _act_conn.execute(
                "SELECT COUNT(*) as total, "
                "SUM(CASE WHEN status='complete' THEN 1 ELSE 0 END) as complete, "
                "SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) as failed, "
                "AVG(CASE WHEN status='complete' THEN duration_ms END) as avg_ms "
                "FROM agent_messages WHERE to_agent=? AND created_at>?",
                (_bk, _act_since)
            ).fetchone()
            _act_recent = []
            if include_recent:
                _act_recent = _act_conn.execute(
                    "SELECT run_id, status, substr(message,1,80) as preview, "
                    "duration_ms, created_at FROM agent_messages "
                    "WHERE to_agent=? ORDER BY created_at DESC LIMIT 5",
                    (_bk,)
                ).fetchall()
            activity[_bk] = {
                "active": [{"run_id": r[0], "prompt": r[1][:80] if r[1] else "", "started_at": r[2]} for r in _act_active],
                "stats": {
                    "total": _act_stats[0] or 0,
                    "complete": _act_stats[1] or 0,
                    "failed": _act_stats[2] or 0,
                    "avg_ms": int(_act_stats[3] or 0),
                },
                "recent": [{"run_id": r[0], "status": r[1], "preview": r[2] or "",
                           "duration_ms": r[3] or 0, "created_at": r[4]} for r in _act_recent],
                "_partial": not include_recent,
            }
        _act_conn.close()
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return activity


def _models_available_payload(lightweight: bool = False) -> dict:
    prefs = _config.get("preferences", {})
    active_models = prefs.get("active_models", {})
    backends_out = {}
    import concurrent.futures as _avail_cf
    _bk_list = list(PROVIDER_REGISTRY.keys())
    def _fetch_bk_models(bk):
        choice = active_models.get(bk, "auto")
        cached_models = _backend_model_cache["data"].get(bk) or []
        if lightweight and cached_models:
            models = cached_models
        elif lightweight:
            resolved_guess = choice if choice != "auto" else ""
            catalog_seed = []
            if resolved_guess:
                catalog_seed.append({"id": resolved_guess, "name": _model_display_name(resolved_guess) or resolved_guess})
            models = _unique_model_catalog(catalog_seed, resolved_guess)
        else:
            models = _get_available_models(bk)
        resolved = _get_active_model(bk) if not lightweight else (choice if choice != "auto" else (models[0]["id"] if models else ""))
        catalog = ([{"id": "auto", "name": "Auto"}] + models) if len(models) > 0 else [{"id": "auto", "name": "Auto"}]
        return bk, {"active": choice, "resolved": resolved, "models": catalog}
    if lightweight:
        for bk in _bk_list:
            _, data = _fetch_bk_models(bk)
            backends_out[bk] = data
    else:
        with _avail_cf.ThreadPoolExecutor(max_workers=max(1, min(len(_bk_list), 8))) as _avail_ex:
            for bk, data in _avail_ex.map(_fetch_bk_models, _bk_list):
                backends_out[bk] = data
    return backends_out


def _models_snapshot(force_versions: bool = False) -> dict:
    _refresh_cli_cache_fingerprints()
    # Cap checks moved to background — too slow for HTTP handler (8s+)
    now = time.time()
    fp = _models_cache_fingerprint()
    if (not force_versions and _models_snapshot_cache.get("data")
            and _models_snapshot_cache.get("fp") == fp
            and (now - float(_models_snapshot_cache.get("ts") or 0.0)) < 120.0):
        return dict(_models_snapshot_cache["data"])
    payload = {
        "ok": True,
        "providers": _providers_payload(),
        "activity": {},
        "backends": _models_available_payload(),
        "benchmarks": _bridge_benchmark_summary(86400),
        "scheduler": _bridge_scheduler_summary(),
        "versions": _probe_backend_versions(force=force_versions),
        "runtimes": {bk: _backend_runtime_info(bk) for bk in PROVIDER_REGISTRY},
    }
    _models_snapshot_cache["data"] = dict(payload)
    _models_snapshot_cache["ts"] = now
    _models_snapshot_cache["fp"] = fp
    return payload


def _models_bootstrap() -> dict:
    _refresh_cli_cache_fingerprints()
    # Cap checks moved to background — too slow for HTTP handler
    now = time.time()
    fp = _models_cache_fingerprint()
    if (_models_bootstrap_cache.get("data")
            and _models_bootstrap_cache.get("fp") == fp
            and (now - float(_models_bootstrap_cache.get("ts") or 0.0)) < 120.0):
        return dict(_models_bootstrap_cache["data"])
    payload = {
        "ok": True,
        "providers": _providers_payload(lightweight=True),
        "activity": {},
        "backends": _models_available_payload(lightweight=True),
        "benchmarks": _bridge_benchmark_summary(86400),
        "scheduler": _bridge_scheduler_summary(),
        "versions": _bootstrap_backend_versions(),
        "runtimes": {bk: _backend_runtime_info(bk) for bk in PROVIDER_REGISTRY},
    }
    _models_bootstrap_cache["data"] = dict(payload)
    _models_bootstrap_cache["ts"] = now
    _models_bootstrap_cache["fp"] = fp
    return payload


def _gateway_stop() -> dict:
    """Stop gateway process; supervisor/TUI may respawn it depending on host setup."""
    try:
        subprocess.run(["pkill", "-f", "openclaw-gateway"], timeout=5, capture_output=True)
        return {"ok": True, "message": "Gateway stop signal sent"}
    except Exception as e:
        return {"ok": False, "error": str(e)[:200]}


def _gateway_restart() -> dict:
    """Restart gateway by killing process; runtime supervisor should respawn it."""
    try:
        subprocess.run(["pkill", "-f", "openclaw-gateway"], timeout=5, capture_output=True)
        return {"ok": True, "message": "Gateway restart signal sent"}
    except Exception as e:
        return {"ok": False, "error": str(e)[:200]}


def _test_model_connectivity(backend_id: str, model: str = "") -> dict:
    """Test connectivity for a specific backend + model. All config from porter_config.json."""
    import urllib.request

    backend_id = str(backend_id or "").strip()
    if not backend_id:
        return {"ok": False, "model": "", "error": "backend required"}

    backend = backend_id.lower()
    alias = {"openclaw-gateway": "openclaw", "gemini_cli": "gemini", "claude_code": "claude"}
    backend = alias.get(backend, backend)

    # Resolve "auto" to actual model
    if not model or model == "auto":
        model = _get_active_model(backend) or ""
    bridge_meta = _bridge_runtime_semantics(backend, model)

    t0 = time.time()
    try:
        if backend == "openclaw":
            # OpenClaw gateway is WebSocket — use CLI, not HTTP
            oc_bin = _resolve_cli("openclaw")
            if not oc_bin:
                result = {"ok": False, "backend": backend, "model": model, "error": "openclaw CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            cmd = [oc_bin, "agent", "--agent", "main", "--message", "Reply with just the word OK", "--json", "--timeout", "45"]
            attempts = []
            for attempt in range(2):
                r = subprocess.run(cmd, capture_output=True, text=True, timeout=55, env=_agent_env(), cwd=str(Path.home()))
                out = (r.stdout or "").strip()
                text = ""
                latest_obj = None
                # Try parsing entire stdout as single JSON first (pretty-printed output)
                try:
                    _whole = json.loads(out)
                    if isinstance(_whole, dict):
                        latest_obj = _whole
                except Exception as _e:
                    mlog.emit("warn", "system", "exception.swallowed",
                              f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
                # Fall back to line-by-line JSONL parsing
                if latest_obj is None:
                    for line in out.split("\n"):
                        if not line.strip():
                            continue
                        try:
                            evt = json.loads(line)
                            if isinstance(evt, dict):
                                latest_obj = evt
                            if evt.get("type") == "item.completed":
                                item = evt.get("item", {})
                                if item.get("type") == "agent_message":
                                    text = item.get("text", "") or ""
                        except Exception:
                            continue
                if not text and isinstance(latest_obj, dict):
                    result_obj = latest_obj.get("result", {}) if isinstance(latest_obj.get("result"), dict) else {}
                    payloads = result_obj.get("payloads", []) if isinstance(result_obj, dict) else []
                    if isinstance(payloads, list):
                        for payload in payloads:
                            if isinstance(payload, dict) and str(payload.get("text", "")).strip():
                                text = str(payload.get("text", "")).strip()
                                break
                    if not text and str(result_obj.get("text", "")).strip():
                        text = str(result_obj.get("text", "")).strip()
                    if not text and str(latest_obj.get("summary", "")).strip().lower() == "completed" and str(latest_obj.get("status", "")).strip().lower() == "ok":
                        text = "OK"
                if text:
                    latency_ms = int((time.time() - t0) * 1000)
                    result = {"ok": True, "model": model, "response": text.strip()[:200], "latency_ms": latency_ms, "bridge": bridge_meta}
                    if attempt:
                        result["execution_state"] = "flaky"
                        result["attempts"] = attempt + 1
                    else:
                        result["execution_state"] = "healthy"
                    return result
                err = ""
                for line in out.split("\n"):
                    try:
                        evt = json.loads(line)
                        if evt.get("type") in ("error", "turn.failed"):
                            err = evt.get("message", "") or str(evt.get("error", {}).get("message", ""))
                    except Exception:
                        continue
                if not err and isinstance(latest_obj, dict):
                    if str(latest_obj.get("status", "")).strip().lower() not in ("", "ok"):
                        err = str(latest_obj.get("summary", "") or latest_obj.get("status", "") or "")
                if not err:
                    err = (r.stderr or "").strip()[:200] or "No response from gateway"
                attempts.append({
                    "error": err[:200],
                    "stderr": (r.stderr or "").strip()[:500],
                    "transient": ("1006" in err.lower() or "timed out" in err.lower() or "timeout" in err.lower() or "1006" in (r.stderr or "").lower()),
                })
                if not attempts[-1]["transient"] or attempt == 1:
                    break
                time.sleep(1.0)
            last = attempts[-1] if attempts else {"error": "No response from gateway", "stderr": ""}
            log.warning("Model test fail [openclaw]: model=%s err=%s stderr=%s", model, last.get("error", ""), last.get("stderr", ""))
            result = {"ok": False, "backend": backend, "model": model, "error": last.get("error", "")[:200], "execution_state": "broken", "attempts": len(attempts), "bridge": bridge_meta}
            if any(a.get("transient") for a in attempts):
                result["execution_state"] = "flaky"
            result.update(_model_repair_hint(backend, (last.get("stderr", "") or "") + "\n" + last.get("error", "")))
            diagnosis = _openclaw_runtime_diagnosis()
            if diagnosis.get("doctor_summary"):
                result["diagnosis"] = diagnosis
            if diagnosis.get("gateway_running") or diagnosis.get("gateway_listening"):
                if result.get("execution_state") == "flaky":
                    result["repair_hint"] = "Gateway looks healthy, but real OpenClaw agent runs are intermittent. Retry once and inspect gateway logs if 1006/timeouts continue."
                else:
                    result["repair_hint"] = "Gateway is up, but real OpenClaw agent execution failed. Inspect the active gateway service and last stderr."
            elif "embedded_timeout" in diagnosis.get("issues", []):
                result["repair_hint"] = "OpenClaw gateway failed and embedded fallback also timed out. This is runtime breakage, not just a slow model."
            return result

        if backend == "codex":
            cdx = _resolve_cli("codex")
            if not cdx:
                result = {"ok": False, "backend": backend, "model": model, "error": "codex CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            _cdx_model = model or "gpt-5.4"
            cmd = [cdx, "exec", "--ephemeral", "--json", "--skip-git-repo-check",
                   "-m", _cdx_model, "Reply with just the word OK"]
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=30, env=_agent_env(), cwd=str(Path.home()))
            latency_ms = int((time.time() - t0) * 1000)
            text = ""
            for line in (r.stdout or "").strip().split("\n"):
                if not line.strip():
                    continue
                try:
                    evt = json.loads(line)
                    if evt.get("type") == "item.completed":
                        item = evt.get("item", {})
                        if item.get("type") == "agent_message":
                            msg = item.get("text", "") or ""
                            if not msg:
                                parts = [p.get("text", "") for p in (item.get("content", []) or []) if isinstance(p, dict) and p.get("text")]
                                if parts:
                                    msg = "".join(parts).strip()
                            if msg:
                                text = msg
                except Exception:
                    continue
            if text:
                return {"ok": True, "model": model, "response": text.strip()[:200], "latency_ms": latency_ms, "bridge": bridge_meta}
            _cdx_err = (r.stderr or "").strip()[:200] or "Codex returned no text"
            log.warning("Model test fail [codex]: model=%s err=%s stdout=%s", model, _cdx_err, (r.stdout or "").strip()[:500])
            result = {"ok": False, "backend": backend, "model": model, "error": _cdx_err}
            result.update(_model_repair_hint(backend, _cdx_err))
            return result

        if backend == "ollama":
            bc = _config.get("backend_config", {}).get("ollama", {})
            _oll_host = bc.get("host", "127.0.0.1")
            _oll_port = bc.get("port", 11434)
            model_name = model or "qwen2.5-coder:1.5b"
            payload = {"model": model_name, "prompt": "Reply OK", "stream": False}
            req = urllib.request.Request(
                f"http://{_oll_host}:{_oll_port}/api/generate",
                data=json.dumps(payload).encode("utf-8"),
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urllib.request.urlopen(req, timeout=15) as resp:
                body = json.loads(resp.read().decode("utf-8", errors="replace") or "{}")
            latency_ms = int((time.time() - t0) * 1000)
            return {"ok": True, "backend": backend, "model": model, "response": str(body.get("response", "OK")).strip()[:200], "latency_ms": latency_ms, "bridge": bridge_meta}

        if backend == "gemini":
            gem = _resolve_cli("gemini")
            if not gem:
                result = {"ok": False, "backend": backend, "model": model, "error": "gemini CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            runtime = _backend_runtime_info("gemini")
            _gem_model = str(model or "").strip()
            if not _gem_model or _gem_model in ("auto", "gemini"):
                _gem_model = runtime.get("recommended_smoke_model") or _get_active_model("gemini") or "gemini-2.5-flash"
            _gem_model = _normalize_gemini_model_id(_gem_model, runtime.get("auth_mode", ""))
            cmd = [gem]
            if runtime.get("supports_headless"):
                cmd.extend(["-p", "Reply with just OK", "-y"])
            else:
                cmd.append("Reply with just OK")
            if runtime.get("supports_model_flag") and _gem_model:
                cmd.extend(["-m", _gem_model])
            if runtime.get("supports_json_output"):
                cmd.extend(["--output-format", "json"])
            _gem_env = _agent_env()
            _gem_env["GEMINI_CLI_YOLO"] = "1"  # suppress YOLO prompts
            _gem_timeout = 75 if "preview" in str(_gem_model or "").lower() else 45
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=_gem_timeout, env=_gem_env, cwd=str(Path.home()))
            _gem_stdout = (r.stdout or "").strip()
            if "Please visit the following URL to authorize" in _gem_stdout or "accounts.google.com/o/oauth2" in _gem_stdout:
                _gem_fail_msg = "Gemini CLI requires OAuth re-authorization"
                result = {"ok": False, "backend": backend, "model": model, "error": _gem_fail_msg, "runtime": {"auth_mode": runtime.get("auth_mode", ""), "resolved_model": _gem_model}, "bridge": bridge_meta}
                result.update(_model_repair_hint(backend, "auth oauth reauthorize"))
                result["repair_hint"] = "Gemini CLI is asking for OAuth login again. Re-authenticate Gemini before relying on model tests."
                return result
            if r.returncode != 0:
                _gem_err = (r.stderr or "").strip()
                # Filter out YOLO mode info lines
                _gem_err = "\n".join(l for l in _gem_err.split("\n") if "YOLO" not in l and "cached credentials" not in l.lower()).strip()
                _gem_fail_msg = (_gem_err or _gem_stdout or "Gemini failed").strip()[:200]
                log.warning("Model test fail [gemini]: model=%s rc=%s err=%s stdout=%s", model, r.returncode, _gem_fail_msg, (r.stdout or "").strip()[:500])
                result = {"ok": False, "backend": backend, "model": model, "error": _gem_fail_msg, "bridge": bridge_meta}
                result.update(_model_repair_hint(backend, _gem_fail_msg))
                result["runtime"] = {"auth_mode": runtime.get("auth_mode", ""), "resolved_model": _gem_model}
                return result
            latency_ms = int((time.time() - t0) * 1000)
            _gem_text = _gem_stdout
            if runtime.get("supports_json_output"):
                try:
                    payload = json.loads(_gem_text)
                    if isinstance(payload, dict):
                        _gem_text = str(payload.get("text") or payload.get("response") or payload.get("output") or payload.get("result") or "OK")
                except Exception as _e:
                    mlog.emit("warn", "system", "exception.swallowed",
                              f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
            return {"ok": True, "backend": backend, "model": model, "response": _gem_text.strip()[:200] or "OK", "latency_ms": latency_ms, "runtime": {"auth_mode": runtime.get("auth_mode", ""), "resolved_model": _gem_model}, "bridge": bridge_meta}

        if backend == "claude":
            claude_bin = _resolve_cli("claude")
            if not claude_bin:
                result = {"ok": False, "backend": backend, "model": model, "error": "claude CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            runtime = _backend_runtime_info("claude")
            cmd = [claude_bin]
            if runtime.get("supports_headless"):
                cmd.extend(["-p", "Reply with just OK"])
            else:
                cmd.append("Reply with just OK")
            if runtime.get("supports_model_flag") and model and model != "auto" and model != "claude":
                cmd.extend(["--model", model])
            if runtime.get("supports_json_output"):
                cmd.extend(["--output-format", "json"])
            # Unset CLAUDECODE to allow nested invocation from within Claude Code
            _env = _agent_env()
            _env.pop("CLAUDECODE", None)
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=30, env=_env, cwd=str(Path.home()))
            if r.returncode != 0:
                _cl_fail_msg = (r.stderr or r.stdout or "Claude failed").strip()[:200]
                log.warning("Model test fail [claude]: model=%s rc=%s err=%s stdout=%s", model, r.returncode, _cl_fail_msg, (r.stdout or "").strip()[:500])
                result = {"ok": False, "backend": backend, "model": model, "error": _cl_fail_msg, "bridge": bridge_meta}
                result.update(_model_repair_hint(backend, _cl_fail_msg))
                return result
            latency_ms = int((time.time() - t0) * 1000)
            _cl_text = (r.stdout or "OK").strip()
            if runtime.get("supports_json_output"):
                try:
                    payload = json.loads(_cl_text)
                    if isinstance(payload, dict):
                        _cl_text = str(payload.get("result") or payload.get("text") or payload.get("output") or "OK")
                except Exception as _e:
                    mlog.emit("warn", "system", "exception.swallowed",
                              f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
            return {"ok": True, "backend": backend, "model": model, "response": _cl_text[:200], "latency_ms": latency_ms, "bridge": bridge_meta}

        result = {"ok": False, "backend": backend, "model": model, "error": f"Unknown backend: {backend}", "bridge": bridge_meta}
        result.update(_model_repair_hint(backend, result["error"]))
        return result
    except subprocess.TimeoutExpired:
        log.warning("Model test timeout: backend=%s model=%s", backend, model)
        result = {"ok": False, "backend": backend, "model": model, "error": "Timed out", "bridge": bridge_meta}
        result.update(_model_repair_hint(backend, result["error"]))
        return result
    except Exception as e:
        log.warning("Model test error: backend=%s model=%s err=%s", backend, model, str(e))
        result = {"ok": False, "backend": backend, "model": model, "error": str(e)[:200], "bridge": bridge_meta}
        result.update(_model_repair_hint(backend, result["error"]))
        return result


