# ═══════════════════════════════════════════════════════════════════════════════
# PROCESS MANAGER — detect, kill, restart model gateway processes
# ═══════════════════════════════════════════════════════════════════════════════

_MANAGED_PROCESSES = {
    "openclaw": {"patterns": ["openclaw", "openclaw-tui", "openclaw-gateway"], "restart_cmd": None},
    "gemini": {"patterns": ["gemini"], "restart_cmd": None},
    "codex": {"patterns": ["codex"], "restart_cmd": None},
    "ollama": {"patterns": ["ollama"], "restart_cmd": ["systemctl", "--user", "restart", "ollama"]},
}

def _process_list() -> list:
    """List all model-related processes with status info."""
    import subprocess
    results = []
    try:
        ps = subprocess.run(
            ["ps", "aux"], capture_output=True, text=True, timeout=5
        )
        lines = ps.stdout.strip().split("\n")
        for line in lines[1:]:  # Skip header
            parts = line.split(None, 10)
            if len(parts) < 11:
                continue
            cmd = parts[10].lower()
            pid = int(parts[1])
            # Check if this is a managed process
            for svc, info in _MANAGED_PROCESSES.items():
                for pattern in info["patterns"]:
                    if pattern in cmd:
                        cpu = float(parts[2])
                        mem = float(parts[3])
                        stat = parts[7]
                        # Calculate runtime from /proc
                        runtime_s = 0
                        try:
                            with open(f"/proc/{pid}/stat") as f:
                                stat_parts = f.read().split()
                                starttime = int(stat_parts[21])
                                with open("/proc/uptime") as uf:
                                    uptime = float(uf.read().split()[0])
                                clk_tck = 100  # SC_CLK_TCK
                                runtime_s = int(uptime - (starttime / clk_tck))
                        except Exception as _e:
                            mlog.emit("warn", "system", "exception.swallowed",
                                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
                        results.append({
                            "service": svc,
                            "pid": pid,
                            "cpu_pct": cpu,
                            "mem_pct": mem,
                            "state": stat,
                            "runtime_s": runtime_s,
                            "cmd": parts[10][:100],
                            "stalled": _is_process_stalled(pid, cpu, runtime_s, stat),
                        })
                        break
    except Exception as e:
        log.debug("Process list error: %s", e)
    return results


def _is_process_stalled(pid: int, cpu: float, runtime_s: int, state: str) -> bool:
    """Heuristic: is this process stalled?
    Only flags terminal-attached interactive processes (TUI) as stalled.
    Background daemons sleeping at 0% CPU is normal.
    """
    # Zombie process = always stalled
    if "Z" in state:
        return True
    # Terminal-attached ('+' in state) and sleeping for 4+ hours with 0% CPU = stalled TUI
    if "+" in state and runtime_s > 14400 and cpu < 0.1:
        return True
    return False


def _process_kill(pid: int, force: bool = False) -> dict:
    """Kill a process safely."""
    import signal, os
    try:
        # Verify the process is a managed one
        procs = _process_list()
        target = None
        for p in procs:
            if p["pid"] == pid:
                target = p
                break
        if not target:
            return {"ok": False, "error": f"PID {pid} is not a managed process"}
        sig = signal.SIGKILL if force else signal.SIGTERM
        os.kill(pid, sig)
        mlog.emit("warn", "process", "process.kill",
            f"Killed {target['service']} PID {pid} ({'SIGKILL' if force else 'SIGTERM'})",
            backend=target["service"])
        _emit_event("process:kill", {"pid": pid, "service": target["service"], "force": force})
        return {"ok": True, "pid": pid, "service": target["service"], "signal": "SIGKILL" if force else "SIGTERM"}
    except ProcessLookupError:
        return {"ok": True, "pid": pid, "note": "process already dead"}
    except PermissionError:
        return {"ok": False, "error": f"Permission denied for PID {pid}"}
    except Exception as e:
        return {"ok": False, "error": str(e)}


def _process_restart(service: str) -> dict:
    """Restart a managed service."""
    import subprocess
    if service not in _MANAGED_PROCESSES:
        return {"ok": False, "error": f"Unknown service: {service}"}

    # First kill all existing processes for this service
    procs = _process_list()
    killed = 0
    for p in procs:
        if p["service"] == service:
            _process_kill(p["pid"], force=True)
            killed += 1

    # Try to restart
    info = _MANAGED_PROCESSES[service]
    if info.get("restart_cmd"):
        try:
            r = subprocess.run(info["restart_cmd"], capture_output=True, text=True, timeout=15)
            return {"ok": r.returncode == 0, "method": "command", "killed": killed,
                    "output": (r.stdout + r.stderr)[:200]}
        except Exception as e:
            return {"ok": False, "error": str(e), "killed": killed}

    # For services without restart commands, just kill and let them be restarted externally
    mlog.emit("info", "process", "process.restart",
        f"Restarted {service} (killed {killed} processes)", backend=service)
    return {"ok": True, "method": "kill_only", "killed": killed,
            "note": f"Killed {killed} {service} processes. External restart needed."}


# AGENT WATCHDOG — auto-detect stalls, validate responses, reboot agents
# ═══════════════════════════════════════════════════════════════════════════════

_watchdog_running = False
_watchdog_stats = {"checks": 0, "reboots": 0, "validations_failed": 0, "last_check": 0}
_WATCHDOG_INTERVAL = 30  # seconds between checks
_STALL_THRESHOLD = 180   # seconds before a step is considered stalled
_DISPATCH_STALL = 120    # seconds before a dispatch is considered stalled


def _validate_response(text: str, backend: str = "") -> dict:
    """Check if a model response is actually useful or garbage.
    Returns {"valid": bool, "reason": str, "confidence": float}
    """
    if not text or not text.strip():
        return {"valid": False, "reason": "empty response", "confidence": 1.0}

    text = text.strip()

    # Too short to be useful
    if len(text) < 10:
        return {"valid": False, "reason": "response too short", "confidence": 0.9}

    # Repetition detection: same sentence repeated 3+ times
    sentences = [s.strip() for s in text.split('.') if s.strip()]
    if len(sentences) >= 3:
        from collections import Counter
        counts = Counter(sentences)
        most_common = counts.most_common(1)
        if most_common and most_common[0][1] >= 3:
            return {"valid": False, "reason": "repetitive output", "confidence": 0.95}

    # Refusal/error patterns
    refusal_patterns = [
        "i cannot", "i can't", "i'm unable", "as an ai", "i don't have access",
        "error:", "exception:", "traceback", "connection refused", "timed out",
        "rate limit", "quota exceeded", "unauthorized", "forbidden",
    ]
    text_lower = text.lower()
    for p in refusal_patterns:
        if p in text_lower and len(text) < 200:
            return {"valid": False, "reason": f"refusal/error: {p}", "confidence": 0.8}

    # OpenClaw-specific: sometimes returns HTML instead of text
    if backend == "openclaw" and text.startswith("<!") and "<html" in text_lower[:100]:
        return {"valid": False, "reason": "HTML response instead of text", "confidence": 1.0}

    # Looks valid
    return {"valid": True, "reason": "ok", "confidence": 1.0}


def _reboot_stalled_step(step: dict, run_id: str) -> dict:
    """Reassign a stalled orchestration step to a different backend."""
    step_id = step["id"]
    old_backend = step.get("assigned_backend", "")
    project_id = ""
    task_id = ""
    try:
        step_ctx = json.loads(step.get("input_data", "") or "{}")
        project_id = str(step_ctx.get("project_id") or "").strip()
        task_id = str(step_ctx.get("task_id") or "").strip()
    except Exception:
        step_ctx = {}
    if not project_id:
        try:
            conn = _db_conn()
            run_row = conn.execute("SELECT context FROM orchestration_runs WHERE id=?", (run_id,)).fetchone()
            conn.close()
            if run_row and run_row["context"]:
                run_ctx = json.loads(run_row["context"] or "{}")
                project_id = str(run_ctx.get("project_id") or "").strip()
                task_id = task_id or str(run_ctx.get("task_id") or "").strip()
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    new_backend, new_persona_id = _orch_select_executor(step, project_id=project_id, task_id=task_id, exclude_backends=[old_backend])
    if not new_backend:
        return {"ok": False, "reason": "no alternative executors available"}
    try:
        conn = _db_conn()
        conn.execute(
            "UPDATE orchestration_steps SET status='pending', assigned_backend=?, assigned_persona_id=?, progress_pct=0 WHERE id=?",
            (new_backend, new_persona_id or "", step_id)
        )
        conn.execute(
            "INSERT INTO orchestration_events (run_id, step_id, event_type, backend, message) VALUES (?, ?, 'watchdog_reboot', ?, ?)",
            (run_id, step_id, new_backend, f"Watchdog rebooted: {old_backend} stalled, reassigned to {new_backend}")
        )
        conn.commit()
        conn.close()
    except Exception as e:
        return {"ok": False, "reason": str(e)}

    _emit_event("watchdog:reboot", {"run_id": run_id, "step_id": step_id, "from": old_backend, "to": new_backend, "persona_id": new_persona_id or "", "project_id": project_id, "task_id": task_id})
    mlog.emit("warn", "watchdog", "watchdog.reboot",
        f"Step {step_id} rebooted: {old_backend} -> {new_backend}", run_id=run_id, backend=new_backend,
        extra={"persona_id": new_persona_id or "", "project_id": project_id, "task_id": task_id})
    _watchdog_stats["reboots"] += 1
    return {"ok": True, "from": old_backend, "to": new_backend, "persona_id": new_persona_id or "", "project_id": project_id, "task_id": task_id}


def _openclaw_health_check() -> dict:
    """Comprehensive OpenClaw health check — gateway, channels, security, doctor."""
    import subprocess
    result = {"ok": False, "gateway": {}, "channels": {}, "security": {}, "doctor": {}}
    oc_settings = _openclaw_gateway_settings()
    gw_host = oc_settings.get("host", "127.0.0.1")
    gw_port = oc_settings.get("port", 18789)
    auth_token = oc_settings.get("token", "")

    # 1. Gateway HTTP probe
    try:
        import urllib.request
        req = urllib.request.Request(f"http://{gw_host}:{gw_port}/health",
            headers={"Authorization": f"Bearer {auth_token}"})
        resp = urllib.request.urlopen(req, timeout=5)
        data = json.loads(resp.read())
        result["gateway"] = {"reachable": True, "status": data}
        result["ok"] = True
    except Exception as e:
        result["gateway"] = {"reachable": False, "error": str(e)}

    # 2. Channel status (are messaging channels healthy?)
    oc_bin = _resolve_cli("openclaw")
    if oc_bin:
        try:
            r = subprocess.run([oc_bin, "channels", "status", "--json"],
                capture_output=True, text=True, timeout=10, env=_agent_env())
            if r.returncode == 0 and r.stdout.strip():
                result["channels"] = json.loads(r.stdout)
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        # 3. Security audit
        try:
            r = subprocess.run([oc_bin, "security", "--json"],
                capture_output=True, text=True, timeout=10, env=_agent_env())
            if r.returncode == 0 and r.stdout.strip():
                result["security"] = json.loads(r.stdout)
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
        # 4. Doctor (comprehensive diagnostics)
        try:
            r = subprocess.run([oc_bin, "doctor", "--json"],
                capture_output=True, text=True, timeout=15, env=_agent_env())
            if r.returncode == 0 and r.stdout.strip():
                result["doctor"] = json.loads(r.stdout)
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    return result


def _openclaw_restart() -> dict:
    """Attempt to restart the OpenClaw gateway."""
    import subprocess
    try:
        # Try systemd first
        r = subprocess.run(["systemctl", "--user", "restart", "openclaw-gateway.service"],
            capture_output=True, text=True, timeout=10)
        if r.returncode == 0:
            return {"ok": True, "method": "systemd"}
        # Try direct start
        r2 = subprocess.run([str(Path.home() / ".npm-global/bin/openclaw"), "gateway", "start"],
            capture_output=True, text=True, timeout=15)
        return {"ok": r2.returncode == 0, "method": "direct", "output": r2.stdout[:200]}
    except Exception as e:
        return {"ok": False, "error": str(e)}


def _agent_watchdog_loop():
    """Background loop: detect stalled steps and dispatches, reboot them."""
    global _watchdog_running
    _watchdog_running = True
    log.info("Agent watchdog started (interval=%ds, stall=%ds)", _WATCHDOG_INTERVAL, _STALL_THRESHOLD)

    while _watchdog_running:
        try:
            time.sleep(_WATCHDOG_INTERVAL)
            _watchdog_stats["checks"] += 1
            _watchdog_stats["last_check"] = time.time()
            now = time.time()

            conn = _db_conn()

            # 1. Check for stalled orchestration steps
            stalled_steps = conn.execute(
                "SELECT os.*, or2.id as run_id FROM orchestration_steps os "
                "JOIN orchestration_runs or2 ON os.run_id = or2.id "
                "WHERE os.status = 'running' AND os.started_at > 0 AND os.started_at < ? "
                "AND or2.status = 'running'",
                (now - _STALL_THRESHOLD,)
            ).fetchall()

            for step in stalled_steps:
                step_d = dict(step)
                log.warning("Watchdog: stalled step %s (backend=%s, running for %ds)",
                    step_d["id"], step_d.get("assigned_backend", "?"),
                    int(now - step_d.get("started_at", now)))
                _reboot_stalled_step(step_d, step_d["run_id"])

            # 2. Check for stalled persona dispatches (agent_messages stuck in_progress)
            stalled_dispatches = conn.execute(
                "SELECT run_id, to_agent, message, ts FROM agent_messages "
                "WHERE status = 'in_progress' AND ts < ?",
                (now - _DISPATCH_STALL,)
            ).fetchall()

            for disp in stalled_dispatches:
                log.warning("Watchdog: stalled dispatch %s to %s (running for %ds)",
                    disp["run_id"], disp["to_agent"],
                    int(now - disp["ts"]))
                # Mark as failed so it doesn't block
                conn.execute(
                    "UPDATE agent_messages SET status='failed', error='Watchdog: stall timeout' WHERE run_id=? AND status='in_progress'",
                    (disp["run_id"],)
                )
                mlog.emit("warn", "watchdog", "watchdog.dispatch_stall",
                    f"Dispatch {disp['run_id']} to {disp['to_agent']} timed out",
                    run_id=disp["run_id"], backend=disp["to_agent"])

            # 3. Check for expired orchestration run leases
            expired_leases = conn.execute(
                "SELECT id, run_id, assigned_backend FROM orchestration_steps "
                "WHERE status = 'running' AND lease_expires_at > 0 AND lease_expires_at < ?",
                (now,)
            ).fetchall()

            for exp in expired_leases:
                exp_d = dict(exp)
                log.warning("Watchdog: lease expired for step %s", exp_d["id"])
                _reboot_stalled_step(exp_d, exp_d["run_id"])

            # 4. Validate recent responses from untrusted backends (OpenClaw)
            recent_responses = conn.execute(
                "SELECT run_id, to_agent, response, status FROM agent_messages "
                "WHERE status = 'complete' AND to_agent = 'openclaw' "
                "AND completed_at > ? AND response IS NOT NULL",
                (now - _WATCHDOG_INTERVAL * 2,)
            ).fetchall()

            for resp in recent_responses:
                validation = _validate_response(resp["response"] or "", backend="openclaw")
                if not validation["valid"]:
                    log.warning("Watchdog: invalid openclaw response for %s: %s",
                        resp["run_id"], validation["reason"])
                    conn.execute(
                        "UPDATE agent_messages SET status='failed', error=? WHERE run_id=? AND to_agent='openclaw' AND status='complete'",
                        (f"Watchdog validation failed: {validation['reason']}", resp["run_id"])
                    )
                    _watchdog_stats["validations_failed"] += 1
                    mlog.emit("warn", "watchdog", "watchdog.validation_failed",
                        f"OpenClaw response invalid: {validation['reason']}",
                        run_id=resp["run_id"], backend="openclaw")

            # 4a. Resume stalled orchestration runs (pending steps with no running executor)
            stalled_runs = conn.execute(
                "SELECT DISTINCT run_id FROM orchestration_steps WHERE status='pending' "
                "AND run_id IN (SELECT id FROM orchestration_runs WHERE status='running')"
            ).fetchall()
            for sr in stalled_runs:
                rid = sr["run_id"]
                running_count = conn.execute(
                    "SELECT COUNT(*) as c FROM orchestration_steps WHERE run_id=? AND status='running'",
                    (rid,)
                ).fetchone()
                if running_count and running_count["c"] == 0:
                    log.info("Watchdog: resuming stalled run %s", rid)
                    conn.execute(
                        "INSERT INTO orchestration_events (run_id, event_type, message) VALUES (?, 'watchdog_resume', 'Watchdog resumed stalled run')",
                        (rid,)
                    )
                    threading.Thread(target=_orch_execute_run, args=(rid,), daemon=True, name=f"orch-resume-{rid}").start()
                    _emit_event("watchdog:run_resumed", {"run_id": rid})
                    mlog.emit("info", "watchdog", "watchdog.run_resumed", f"Resumed stalled run {rid}", run_id=rid)

            conn.commit()
            conn.close()


            # 4b. Auto-kill stalled processes
            try:
                stalled_procs = [p for p in _process_list() if p.get("stalled")]
                for sp in stalled_procs:
                    log.warning("Watchdog: stalled process %s (PID %d, service=%s, runtime=%ds)",
                        sp["cmd"][:40], sp["pid"], sp["service"], sp["runtime_s"])
                    _process_kill(sp["pid"], force=False)
                    mlog.emit("warn", "watchdog", "watchdog.process_stall",
                        f"Killed stalled {sp['service']} PID {sp['pid']} (runtime {sp['runtime_s']}s)",
                        backend=sp["service"])
                    _watchdog_stats["reboots"] += 1
            except Exception as e:
                log.debug("Watchdog process check error: %s", e)


            # 6. Probe rate-limited backends for recovery
            for _wbk, _wbh in list(_backend_health.items()):
                if _wbh.get("status") in ("rate_limited", "recovering") and time.time() >= _wbh.get("cooldown_until", 0):
                    try:
                        _probe_fn = PROVIDER_REGISTRY.get(_wbk, {}).get("probe")
                        if _probe_fn and _probe_fn():
                            _backend_set_ok(_wbk)
                            log.info("Watchdog: backend %s recovered from rate limit", _wbk)
                            mlog.emit("info", "watchdog", "watchdog.backend_recovered",
                                f"Backend {_wbk} recovered from rate limit")
                            _emit_event("watchdog:backend_recovered", {"backend": _wbk})
                        else:
                            # Extend cooldown
                            _wbh["cooldown_until"] = time.time() + 60
                    except Exception:
                        _wbh["cooldown_until"] = time.time() + 60

            # 5. OpenClaw gateway health check
            oc_health = _openclaw_health_check()
            if not oc_health.get("ok"):
                log.warning("Watchdog: OpenClaw gateway unresponsive: %s", oc_health.get("error", "?"))
                mlog.emit("warn", "watchdog", "watchdog.openclaw_down",
                    f"OpenClaw gateway unresponsive: {oc_health.get('error', '?')[:100]}")
                _emit_event("watchdog:openclaw_down", {"error": oc_health.get("error", "?")[:200]})
                # Attempt restart
                restart = _openclaw_restart()
                if restart.get("ok"):
                    mlog.emit("info", "watchdog", "watchdog.openclaw_restarted",
                        f"OpenClaw gateway restarted via {restart.get('method', '?')}")
                    _emit_event("watchdog:openclaw_restarted", {"method": restart.get("method", "?")})
                else:
                    mlog.emit("error", "watchdog", "watchdog.openclaw_restart_failed",
                        f"OpenClaw restart failed: {restart.get('error', '?')[:100]}")


        except Exception as e:
            log.debug("Watchdog loop error: %s", e)

    log.info("Agent watchdog stopped")


_last_self_check = {"checks": [], "all_ok": None, "summary": "Not run yet", "ts": 0}



_ROLLBACK_FLAG = Path("/tmp/porter_rollback_attempted")

def _attempt_auto_rollback(critical_failed: list, fail_detail: str):
    """v0.30.36 — Auto-rollback: revert last commit if critical self-check fails post-deploy.

    Safety: uses /tmp/porter_rollback_attempted flag to prevent infinite restart loops.
    Only triggers on critical failures (version_endpoint, database).
    """
    import subprocess, time as _rbt
    # Guard: don't rollback if we already tried recently (within 5 min)
    if _ROLLBACK_FLAG.exists():
        try:
            flag_age = _rbt.time() - _ROLLBACK_FLAG.stat().st_mtime
            if flag_age < 300:  # 5 minutes
                mlog.emit("error", "system", "rollback.skipped",
                    f"Rollback already attempted {int(flag_age)}s ago — manual intervention needed. Failures: {fail_detail}")
                log.error("Auto-rollback SKIPPED (already attempted %ds ago): %s", int(flag_age), fail_detail)
                return
        except Exception as _e:
            mlog.emit("warn", "system", "exception.swallowed",
                      f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    # Guard: check we have git history to revert to
    try:
        result = subprocess.run(
            ["git", "log", "--oneline", "-2"],
            cwd=str(_DATA_DIR), capture_output=True, text=True, timeout=10)
        commits = result.stdout.strip().split("\n")
        if len(commits) < 2:
            mlog.emit("error", "system", "rollback.no_history",
                "Cannot auto-rollback: insufficient git history")
            log.error("Auto-rollback ABORTED: insufficient git history")
            return
        current_commit = commits[0]
        previous_commit = commits[1]
    except Exception as e:
        log.error("Auto-rollback ABORTED: git log failed: %s", e)
        return
    # Write rollback flag BEFORE attempting (prevents loops)
    try:
        _ROLLBACK_FLAG.write_text(f"rollback at {_rbt.time()}\ncritical: {critical_failed}\nfrom: {current_commit}\nto: {previous_commit}")
    except Exception as _e:
        mlog.emit("warn", "system", "exception.swallowed",
                  f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    mlog.emit("warning", "system", "rollback.starting",
        f"Auto-rollback triggered: {critical_failed} failed. Reverting {current_commit} → {previous_commit}")
    log.warning("AUTO-ROLLBACK: reverting %s → %s (critical failures: %s)",
        current_commit, previous_commit, critical_failed)
    # Execute rollback
    try:
        revert = subprocess.run(
            ["git", "revert", "HEAD", "--no-edit"],
            cwd=str(_DATA_DIR), capture_output=True, text=True, timeout=30)
        if revert.returncode != 0:
            mlog.emit("error", "system", "rollback.revert_failed",
                f"git revert failed: {revert.stderr[:200]}")
            log.error("Auto-rollback git revert FAILED: %s", revert.stderr[:200])
            return
        mlog.emit("info", "system", "rollback.reverted",
            f"Git revert successful. Restarting porter...")
        log.info("Auto-rollback: git revert successful, restarting porter")
        # Restart — this kills the current process
        subprocess.Popen(
            ["systemctl", "--user", "restart", "porter"],
            cwd=str(_DATA_DIR))
        # Give systemd a moment, then this process should be killed by SIGTERM
        _rbt.sleep(10)
    except Exception as e:
        mlog.emit("error", "system", "rollback.failed", f"Auto-rollback exception: {e}")
        log.error("Auto-rollback EXCEPTION: %s", e)


def _startup_self_check():
    """v0.30.32 — Post-startup self-check: verify Porter's own health."""
    import urllib.request, time as _sct
    _sct.sleep(5)  # Wait for server to fully start
    checks = []
    port = PORT
    # 1. Version endpoint responds
    try:
        req = urllib.request.Request(f"http://127.0.0.1:{port}/api/version")
        resp = urllib.request.urlopen(req, timeout=5)
        data = json.loads(resp.read())
        ver = data.get("v", "?")
        checks.append({"check": "version_endpoint", "ok": True, "detail": ver})
    except Exception as e:
        checks.append({"check": "version_endpoint", "ok": False, "detail": str(e)[:100]})
    # 2. Main page loads (non-empty HTML)
    try:
        req = urllib.request.Request(f"http://127.0.0.1:{port}/")
        resp = urllib.request.urlopen(req, timeout=5)
        html = resp.read()
        size = len(html)
        checks.append({"check": "main_page", "ok": size > 1000, "detail": f"{size} bytes"})
    except Exception as e:
        checks.append({"check": "main_page", "ok": False, "detail": str(e)[:100]})
    # 3. DB accessible (personas count)
    try:
        conn = _db_conn()
        count = conn.execute("SELECT COUNT(*) FROM personas").fetchone()[0]
        conn.close()
        checks.append({"check": "database", "ok": True, "detail": f"{count} personas"})
    except Exception as e:
        checks.append({"check": "database", "ok": False, "detail": str(e)[:100]})
    # 4. Background threads running
    alive_threads = [t.name for t in threading.enumerate() if t.is_alive() and t.name.startswith("porter-")]
    checks.append({"check": "background_threads", "ok": len(alive_threads) >= 5,
                    "detail": f"{len(alive_threads)} threads: {', '.join(alive_threads[:8])}"})
    # 5. Config loaded
    proj_count = len(_project_list(include_all=True))
    checks.append({"check": "config", "ok": True, "detail": f"{proj_count} projects"})
    # Report
    all_ok = all(c["ok"] for c in checks)
    summary = f"Self-check: {sum(1 for c in checks if c['ok'])}/{len(checks)} passed"
    if all_ok:
        mlog.emit("info", "system", "startup.self_check", summary)
        log.info("Startup self-check: %s", summary)
    else:
        failed = [c for c in checks if not c["ok"]]
        fail_detail = "; ".join(f"{c['check']}: {c['detail']}" for c in failed)
        mlog.emit("error", "system", "startup.self_check_failed",
            f"{summary} — FAILED: {fail_detail}")
        log.error("Startup self-check FAILED: %s — %s", summary, fail_detail)
        # v0.30.36 — Auto-rollback on critical failure
        critical_failed = [c["check"] for c in checks if not c["ok"] and c["check"] in ("version_endpoint", "database")]
        if critical_failed:
            _attempt_auto_rollback(critical_failed, fail_detail)
        # v0.30.40 — Self-dispatch: investigate non-critical health failures
        non_critical_failed = [c["check"] for c in checks if not c["ok"] and c["check"] not in ("version_endpoint", "database")]
        if non_critical_failed and not critical_failed:
            try:
                _self_dispatch_on_health_failure(non_critical_failed)
            except Exception as _e:
                mlog.emit("warn", "system", "exception.swallowed",
                          f"Caught and continued: {_e}", extra={"exc_type": type(_e).__name__})
    global _last_self_check
    _last_self_check = {"checks": checks, "all_ok": all_ok, "summary": summary, "ts": _sct.time()}
    _emit_event("system:self_check", {"checks": checks, "all_ok": all_ok, "summary": summary})


def _start_watchdog():
    """Start the agent watchdog in a background thread."""
    global _watchdog_running
    if _watchdog_running:
        return
    t = threading.Thread(target=_agent_watchdog_loop, daemon=True, name="agent-watchdog")
    t.start()


def _watchdog_status() -> dict:
    """Return current watchdog status."""
    return {
        "running": _watchdog_running,
        "interval": _WATCHDOG_INTERVAL,
        "stall_threshold": _STALL_THRESHOLD,
        "dispatch_stall": _DISPATCH_STALL,
        "stats": dict(_watchdog_stats),
    }


