                    if pid == "_files":
                        crumbs.append({"name": "My Files", "path": "_files/" + (parts[1] if len(parts) > 1 else "")})
                        for i in range(2, len(parts)):
                            crumbs.append({"name": parts[i], "path": "/".join(parts[:i+1])})
