            # v0.31.57 — Check if user is admin for log filtering
            _log_tok = self.get_session_token()
            _log_sess = get_session(_log_tok) if _log_tok else None
            _log_role = _log_sess.get("role", "operator") if _log_sess else "operator"
            _log_is_admin = _log_role in ("admin")
            lines = []

            # Try to read from journalctl first (systemd)
            try:
                import subprocess
                result = subprocess.run(
                    ["journalctl", "--user-unit=porter", "-n", str(n), "--no-pager", "-o", "short-iso"],
                    capture_output=True, text=True, timeout=5
                )
                if result.returncode == 0 and result.stdout.strip():
                    lines = result.stdout.strip().split("\n")
            except Exception as e:
                log.debug("journalctl read: %s", e)

            # Fallback: read from Python logging if no journalctl output
            if not lines:
                # Check if there's a log file
                log_path = _DATA_DIR / "porter.log"
                if log_path.exists():
                    try:
                        with open(log_path) as f:
                            all_lines = f.readlines()
                            lines = [l.rstrip() for l in all_lines[-n:]]
                    except Exception as e:
                        log.debug("Log file read: %s", e)

            if not lines:
                lines = ["No log entries found. Porter logs via systemd: journalctl --user-unit=porter"]

            # Filter system noise for non-admin users
            if not _log_is_admin:
                _noise = ("auto-remediat", "retry fix", "hygiene", "memory_extract", "cap_check", "heartbeat", "self_heal", "workflow_run", "agent_backend_eval", "staleness")
                lines = [l for l in lines if not any(_nw in l.lower() for _nw in _noise)]
            self.reply_json({"ok": True, "lines": lines})


